/* characters q01 (39 mục) — bồi mốc actor Lý thị @c274 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q01"]=window.__LIBQ["pham-nhan-tu-tien"]["q01"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q01"]["characters"]={"updatedAt":"2026-07-09","count":39,"chars":[{"id":"han-lap","name":"Hàn Lập","cn":"韩立","aliases":["Anh ngố"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"da-roi"},{"ten":"Hoàng Phong Cốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Luyện Khí kỳ — Trường Xuân công tầng 11","trangThai":"song","blurb":"Hàn Lập xuất thân Sơn Biên thôn, từ ký danh đệ tử Thất Huyền môn nhờ thể chất kỳ dị mà bước vào con đường tu tiên, từng sở hữu bình thần bí thôi sanh dược thảo và vượt qua cuộc đoạt xá của Mặc đại phu. Sau khi gia nhập Hoàng Phong Cốc, hắn từng đạt Trúc Cơ trung kỳ, nhiều lần dựa vào pháp khí, trận pháp và mưu kế vượt hiểm. Tính tới mốc mới nhất trong hồ sơ, sau biến cố cứu nữ tử che mặt, tu vi của Hàn Lập đại giảm xuống Luyện Khí kỳ tầng ba, bốn và đang cẩn trọng quay lại động quật sửa cổ Truyền tống trận.","vaiTro":"Nhân vật chính — tu sĩ Hoàng Phong Cốc trọng sinh tu vi","tinhCach":"Cẩn trọng, giỏi ẩn nhẫn và giữ khoảng cách; mưu trí, quen bố trí hậu thủ; dứt khoát khi đối địch; biết mạo hiểm cứu người trong tình thế nguy cấp","tabs":{"diem":[{"text":"Tự dùng Trúc cơ đan luyện chế để bế quan trong phòng địa hỏa và bước vào Trúc Cơ kỳ.","chuong":"@c0215"},{"text":"Thanh Nguyên kiếm quyết đột phá tầng thứ năm, đưa tu vi lên Trúc Cơ trung kỳ.","chuong":"@c0271"},{"text":"Trong chiến sự Hắc Sát giáo, bình tĩnh chỉ ra điểm linh khí dao động yếu của Tứ tượng trận để đồng môn xác nhận phá trận.","chuong":"@c0318"},{"text":"Dùng Điên Đảo Ngũ Hành Trận đối phó Việt Hoàng, giữ bình tĩnh trong Cấm đoạn đại trận trước đao mang của đối phương.","chuong":"@c0329"},{"text":"Diệt nguyên thần chiếm thân Khúc Hồn, nhận ra tiểu kiếm xanh là pháp bảo và đoạt được chiến lợi phẩm quan trọng.","chuong":"@c0343"},{"text":"Mạo hiểm cứu nữ tử che mặt khỏi vòng truy đuổi, nhưng sau đó bị hút chân nguyên khiến tu vi đại giảm.","chuong":"@c0361"}],"kinhLich":[{"bridge":true,"khoang":"c0001–c0003","text":"Tam thúc tiến cử Hàn Lập 10 tuổi dự kỳ khảo thí Thất Huyền môn; đi xe ngựa năm ngày cùng hơn ba chục hài đồng tới Thái Hà sơn."},{"chuong":4,"importance":"normal","tieuDe":"Ký danh đệ tử Thất Huyền môn","text":"Trải qua trắc thí Luyện Cốt Nhai ba chặng; kiệt sức không lên được đỉnh đúng giờ, được sư huynh Trương Quân ôm lên — vào phút cuối thành ký danh đệ tử. Mặc đại phu chọn làm đồng tử chế thuốc tại Thần Thủ Cốc."},{"chuong":6,"importance":"major","tieuDe":"Thành thân truyền đệ tử Mặc đại phu","text":"Mặc đại phu chính thức nhận Hàn Lập làm thân truyền đệ tử sau khi phát hiện thể chất kỳ dị tại khảo hạch (Ch.8); truyền Vô danh khẩu quyết với điều kiện tra khảo sau nửa năm. Được cấp thạch thất riêng và dược vật trân quý — đặc quyền vô tiền khoáng hậu trong Thất Huyền môn. Đây là điểm khởi đầu của mọi ràng buộc-lợi dụng về sau."},{"bridge":true,"khoang":"c0007–c0009","text":"Khổ tu Vô danh khẩu quyết nửa năm; phát hiện thể nội sinh lương khí lạnh khác hẳn đồng môn; đột phá tầng 2 nhờ dược vật, bị nội thương nhẹ."},{"chuong":10,"importance":"major","tieuDe":"Nhặt bình thần bí","text":"Nhặt được cái bình kim loại màu xanh biếc nặng bất thường trên đường mòn trong núi. Thử đập bằng thiết chùy tới mười hai phần công lực — bình vẫn không một vết xước. Giấu vào túi da đeo cổ, không khai cho ai. Bình này trở thành bảo vật trục toàn bộ hành trình tu luyện của Hàn Lập."},{"chuong":15,"importance":"normal","tieuDe":"Đình trệ tầng 3, đề phòng sư phụ","text":"Luyện tới tầng 3 Vô danh khẩu quyết thì đình trệ hơn một năm. Phát giác ánh mắt tham lam của Mặc đại phu qua những lần kiểm tra — lòng đề phòng bắt đầu tăng dần."},{"bridge":true,"khoang":"c0016–c0019","text":"Ra ngoài quan sát trường đấu giang hồ giữa các đệ tử; dùng thủ thuật moi tin từ Kim Đông Bảo; quan sát Lệ sư huynh thi triển Phong Lôi đao pháp."},{"chuong":20,"importance":"normal","tieuDe":"Cứu Lệ Phi Vũ, kết mối giao dịch","text":"Cứu tỉnh Lệ Phi Vũ bằng ngân châm bên suối; vạch trần bí mật Lệ sư huynh dùng Trừu Tủy Hoàn nguyên viên nhiều năm — đổi lấy sự tin tưởng và ân nghĩa. Hai người bắt đầu giao dịch dược-đổi-võ bí mật, Hàn Lập có được kênh học võ công bên ngoài sự kiểm soát của Mặc đại phu."},{"chuong":22,"importance":"minor","text":"Bị tâm ma xâm lấn đêm khuya; dùng bình an phù cha mẹ tặng trừ tâm ma, công lực đạt đỉnh phong tầng ba."},{"chuong":26,"importance":"major","tieuDe":"Nắm phương pháp bình thôi sanh","text":"Qua hai tháng thử nghiệm, xác nhận hoàn toàn cơ chế bình thần bí: hút quang điểm ban đêm trời quang, khoảng 7 ngày tái sinh một giọt lục dịch; nhỏ một giọt nguyên chất lên gốc cây tăng ~100 năm dược tính. Nuôi tam ô thảo thành ngàn năm thành công. Tiếp đó tự phối chế Hoàng Long Đan, Thanh Linh Tán, Kim Tủy Hoàn, Dưỡng Tinh Đan — hơn mười bình thánh dược. Bình thần bí từ đây là vũ khí bí mật toàn bộ chặng Luyện Khí."},{"chuong":28,"importance":"normal","tieuDe":"Đột phá tầng tư, giấu thực lực","text":"Ăn Hoàng Long Đan và Kim Tủy Hoàn, đột phá tầng tư Trường Xuân công trong một đêm; ngũ cảm tăng vọt. Giấu đột phá thật khi Mặc đại phu về kiểm tra."},{"chuong":31,"importance":"major","tieuDe":"Bị ép nuốt Thi Trùng Hoàn","text":"Mặc đại phu vạch trần việc Hàn Lập cố ý giấu tiến độ rồi bức hàng: ép nuốt Thi Trùng Hoàn — trùng noãn tiềm phục một năm, không giải dược thì phá vỡ ăn sạch nội tạng chết trong ba ngày ba đêm thống khổ. Hàn Lập khuất phục nhưng ngay lập tức quyết tâm tìm đường tự thoát, không phó thác mạng vào lòng thương của lão."},{"bridge":true,"khoang":"c0032–c0033","text":"Thử giải Thi Trùng Hoàn bằng Thanh Linh Tán — thất bại. Hơn nửa năm sau: đột phá tầng năm Trường Xuân công nhờ đan dược; bắt đầu giao dịch kiếm phổ với Lệ Phi Vũ."},{"chuong":37,"importance":"normal","tieuDe":"Chọn Trát Nhãn kiếm pháp","text":"Đọc trọn 74 quyển bí tịch do Lệ Phi Vũ trộm từ Thất Tuyệt đường; chọn Trát Nhãn kiếm pháp vì 'tam bất luyện' khớp hoàn cảnh — không cần chân khí, cần nghị lực và thiên phú. Ghi tạc toàn bộ vào trí nhớ thay vì sao chép để tránh bị Mặc đại phu phát hiện."},{"bridge":true,"khoang":"c0038–c0040","text":"Bí mật rèn kiếm và khổ luyện Trát Nhãn kiếm pháp; tiếp tục theo dõi động thái Mặc đại phu qua Kim Đông Bảo."},{"chuong":41,"importance":"normal","tieuDe":"Bỏ trốn khỏi sơn cốc","text":"Tố giác gian tế Dã Lang bang cho Lệ Phi Vũ lập công; đặt thợ rèn làm vỏ kiếm cải tiến và chuông sắt bí mật. Đêm đó bỏ trốn khỏi sơn cốc, để lại thư hẹn bốn tháng sau gặp lại."},{"bridge":true,"khoang":"c0042","text":"Trên đường ẩn tu: tìm khe núi hẻo lánh, bắt đầu khổ luyện bộ pháp và nội công không bị kiểm soát."},{"chuong":43,"importance":"normal","tieuDe":"Ẩn tu bốn tháng — đạt tầng sáu","text":"Ẩn tu khe núi hơn bốn tháng: luyện Nhuyễn cốt công, Liễm tức công, Ngụy nặc thuật và La Yên bộ trong rừng gai. Trường Xuân công đạt tầng sáu — tầng cao nhất Mặc đại phu từng cấp; phục hồi thân thể dị thường vượt xa người thường."},{"bridge":true,"khoang":"c0044","text":"Trở lại đúng hẹn; ép Mặc đại phu giao giải dược Thi Trùng Hoàn trước khi cho kiểm tra — giả lộ đột phá tầng tư, che giấu thực lực tầng sáu."},{"chuong":45,"importance":"normal","tieuDe":"Mặc đại phu trở mặt — đối đầu lần đầu","text":"Mặc đại phu bắt mạch rồi trở mặt ra lệnh khống chế. Nhờ thực lực tầng sáu vượt dự tính, Hàn Lập thoát ra; lần đầu rút kiếm lộ nanh vuốt, tuyên bố quyết sống mái."},{"bridge":true,"khoang":"c0046–c0049","text":"Ác đấu với Mặc đại phu: dùng bột khói + La Yên bộ ẩn mình tấn công một kiếm thất thủ; giao chiến Ma Ngân Thủ; dùng trá ngữ và chủy thủ giấu trong mũi kiếm — lão né thoát nhờ bản năng, chỉ trầy gáy."},{"chuong":50,"importance":"normal","tieuDe":"Bôi Triền Hương Ti — bị Thiết Nô bắt","text":"Vờ giảng hòa, tiết lộ đã bôi Triền Hương Ti — độc dược từ từ nhập cốt — lên tiêm trùy trước khi đâm trúng. Tuyên bố tánh mạng Mặc đại phu nằm trong tay mình. Nhưng lão có chỗ dựa: Thiết Nô ra tay bắt giữ, Hàn Lập bị trọng thương và mất hộ tâm kính."},{"bridge":true,"khoang":"c0051–c0055","text":"Bị Thiết Nô khống chế bất động; chứng kiến Mặc đại phu phát động Thất Quỷ Phệ Hồn đại pháp hồi xuân; bị dán Định Thần Phù mất quyền điều khiển cơ thể; bị đặt vào trận đồ đoạt xá giữa nhà đá."},{"chuong":57,"importance":"major","tieuDe":"Thắng đoạt xá — Mặc đại phu chết","text":"Trong cuộc đoạt xá, nguyên thần Hàn Lập hiện ra dưới dạng quang cầu xanh biếc lớn bất thường — nuốt gọn quang cầu vàng của Mặc đại phu, đánh đuổi nguyên thần Dư Tử Đồng chỉ còn 1/3 chạy trốn vào góc nhà đá. Tỉnh lại: Mặc đại phu đã chết, Định Thần Phù biến thành tro. Dùng mưu moi hết thông tin rồi dùng ống đồng độc dịch + kiếm kết liễu hoàn toàn nguyên thần Dư Tử Đồng. Mối hiểm lớn nhất đời Luyện Khí được giải trừ."},{"bridge":true,"khoang":"c0058–c0061","text":"Sau khi diệt trừ hậu hoạn, Hàn Lập dọn dẹp nhà đá bí mật và lục soát di vật, di thể Mặc đại phu."},{"chuong":62,"importance":"normal","tieuDe":"Di thư — ràng buộc Noãn Dương Bảo Ngọc","text":"Lục soát thi thể Mặc đại phu, phát hiện di thư: lão đã hạ kỳ độc Thi Trùng Hoàn từ trước (chỉ Noãn Dương Bảo Ngọc giải được), đặt giao dịch ràng buộc — Hàn Lập phải tới an bài thân nhân đổi lấy bảo ngọc. Chấp nhận."},{"chuong":63,"importance":"normal","tieuDe":"Khống chế Thiết Nô — phát hiện Khúc Hồn","text":"Dùng Dẫn Hồn Chung khống chế cự hán thiết nô làm thuộc hạ; nhìn kỹ mặt mới rúng động nhận ra chính là di thể bạn thân Trương Thiết — hồn phách đã mất, bị cải tạo thành thi nhân. Đặt tên Khúc Hồn."},{"bridge":true,"khoang":"c0064","text":"Sắp xếp hậu sự tại Thần Thủ Cốc; giả bút tích thư Mặc đại phu để che giấu cái chết trong thời gian đầu."},{"chuong":65,"importance":"normal","tieuDe":"Tiếp quản Thần Thủ Cốc — lộ Trường Xuân công cao tầng","text":"Hơn nửa năm sau, giả bút tích thư Mặc đại phu che giấu cái chết; tiếp quản Thần Thủ Cốc, nổi danh khắp Thất Huyền môn là 'Hàn thần y'. Phát hiện 'Trường sinh kinh' của Mặc đại phu thực ra là bí tịch Trường Xuân công ghi thêm hai tầng tiếp theo."},{"chuong":67,"importance":"major","tieuDe":"Luyện thành pháp thuật — bán tu tiên giả","text":"Giải mã cổ ngữ ba tháng, luyện năm pháp thuật từ bí tịch Trường Xuân công; chỉ luyện thành Hỏa Đạn Thuật và Thiên Nhãn Thuật. Xác nhận có pháp lực thật — là người duy nhất Thất Huyền môn đạt địa vị 'bán tu tiên giả'. Ba pháp thuật còn lại chờ điều kiện từ giới tu tiên mới luyện được; đây là bước đầu tiên thoát khỏi phạm trù võ học phàm nhân."},{"bridge":true,"khoang":"c0068–c0073","text":"Cứu Lý trưởng lão khỏi hỗn hợp kịch độc Dã Lang bang bằng Thanh Linh Tán + ngân châm; xác nhận với Lệ Phi Vũ biết bí mật Trừu Tủy Hoàn."},{"chuong":74,"importance":"normal","tieuDe":"Luyện thành Ngự Phong Quyết — bay được","text":"Luyện thành Ngự Phong Quyết sau nhiều thất bại — pháp thuật khinh thân dùng pháp lực, bay được một mình. Hàn Lập 18 tuổi."},{"chuong":75,"importance":"normal","tieuDe":"Đột phá tầng 8, hoàn thiện thân pháp","text":"Trường Xuân công đột phá tầng 8 nhờ ngày ngày ăn linh dược; dung hợp La Yên bộ + Ngự Phong Quyết tạo thân pháp xuất quỷ nhập thần; cải tiến Hỏa Đạn Thuật giữ hỏa cầu trên tay làm vũ khí cận chiến."},{"bridge":true,"khoang":"c0075b","text":"Đoàn đàm phán Thất Huyền môn bị Dã Lang bang phục kích tại Lạc Sa pha bằng nỏ liên châu quân dụng; phần lớn bị giết — Hàn Lập khởi động kế hoạch phản công."},{"chuong":76,"importance":"normal","tieuDe":"Lên kế hoạch tiêu diệt Dã Lang bang","text":"Triệu Khúc Hồn và dùng linh thức do thám; lần đầu phối hợp chiến thuật toàn diện — vừa ẩn thân vừa điều binh nhắm thẳng sào huyệt Dã Lang bang."},{"bridge":true,"khoang":"c0077–c0083","text":"Triệu Khúc Hồn tiêu diệt nhóm Dã Lang bang vào bắt 'thần y'; cùng Lệ Phi Vũ cải trang thâm nhập quanh Lạc Nhật Phong quan sát trận địa."},{"bridge":true,"khoang":"c0084–c0087","text":"Lần đầu công khai phô thực lực: thi triển La Yên bộ + Ngự Phong Quyết hạ sát hơn mười đệ tử Đoạn Thủy môn trong nháy mắt. Theo Lệ Phi Vũ lên Lạc Nhật Phong ký tử khế; thi triển thân pháp xuất hiện sau lưng Vương Tuyệt Sở khiến cả môn phái kinh ngạc chấp thuận."},{"chuong":90,"importance":"normal","tieuDe":"Nhận ra pháp thuật Chu Nho — nảy ý đoạt bảo","text":"Nhận ra khẩu quyết Chu Nho điều khiển luồng sáng giống hệt Khu Vật Thuật của mình — xác nhận pháp thuật này thuộc giới tu tiên. Nảy ý muốn giết người đoạt bảo."},{"chuong":91,"importance":"normal","tieuDe":"Đoạt kiếm phù — lần đầu dùng pháp thuật chiến đấu","text":"Dùng Khống Vật Thuật đoạt kiếm phù từ tay Chu Nho ngay giữa huyết đấu — lần đầu áp dụng pháp thuật tu tiên thật sự vào thực chiến; Chu Nho sửng sốt bỏ thế thượng phong."},{"bridge":true,"khoang":"c0092","text":"Tiếp tục đấu pháp và lực trận kéo dài; tiêu hao Chu Nho bằng chiến thuật kết hợp độn thân và pháp lực."},{"chuong":93,"importance":"normal","tieuDe":"Hạ người tu tiên đầu tiên — thu Thăng Tiên Lệnh","text":"Dùng mưu nhử Chu Nho bỏ Kim Quang Tráo rồi kết liễu bằng Hỏa Đạn Thuật; thu ba vật phẩm: kiếm phù lục, Thăng Tiên Lệnh bài, gia phả Tần thị. Đây là lần đầu Hàn Lập hạ được người tu tiên thật sự."},{"chuong":94,"importance":"normal","tieuDe":"Xóa sổ Dã Lang bang tại Lạc Nhật Phong","text":"Dùng ẩn thân và độn thuật xóa sổ hơn 50 người Dã Lang bang còn lại trong tử đấu trường tại Lạc Nhật Phong — Dã Lang bang bị diệt."},{"bridge":true,"khoang":"c0095–c0096","text":"Khổ luyện Khống Vật Thuật với kiếm phù ba ngày; tổng kết ba hạn chế của kiếm phù — tiêu hao lớn, hiệu quả trong 20 trượng, tuổi thọ hữu hạn. Dùng Thiên Nhãn Thuật uy hiếp tâm lý Vương Tuyệt Sở."},{"bridge":true,"khoang":"c0097–c0098","text":"Để lại thuốc kéo dài tuổi thọ cho Lệ Phi Vũ và đan dược cho Vương Tuyệt Sở; ghi thư từ biệt. Cùng Khúc Hồn ngồi xe ngựa rời Thất Huyền môn hướng đông."},{"chuong":99,"importance":"major","tieuDe":"Vĩnh viễn rời Quyển 1","text":"Dùng linh thức quan sát từ xa cảnh đám cưới em gái trong thôn — cha mẹ đầu bạc lưng còng, tam thúc, Hàn Thiết. Quyết định vĩnh viễn không trở lại, tiếp tục con đường tu tiên độc lập. Khép lại toàn bộ mối liên hệ với thế giới phàm nhân, đặt dấu chấm hết cho Quyển 1."},{"text":"Tới Gia Nguyên Thành — cố hương Mặc đại phu. Bị đám đầu mục bến đò phục kích; dùng thân pháp giết Hắc Hùng, ép Tôn nhị cẩu nuốt độc khống chế làm thủ hạ tai mắt.","bridge":true,"khoang":103},{"bridge":true,"khoang":"c0104–c0106","text":"Đọc di thư Mặc đại phu: xác nhận âm hàn chi độc ngưng kết trong đan điền còn hai tháng trước khi bộc phát; qua Tôn nhị cẩu nắm bố cục ba đại bang và âm mưu Ngô Kiếm Minh. Tại tửu lâu dùng Thiên Nhãn Thuật nhận ra tu tiên giả pháp lực thâm hậu; nghe lén biết Thăng Tiên hội và tên gọi Trúc Cơ đan — lần đầu hiểu sơ cảnh giới tiếp theo."},{"bridge":true,"khoang":"c0107–c0112","text":"Lén nhập Mặc phủ, vượt bẫy ám tiễn; ra mặt với Nghiêm thị bằng nhẫn tín vật; kháng lại mê hồn thuật Tam nương; gặp đủ bốn phu nhân và chứng kiến các bà giải mã ám thư."},{"text":"Phô Hỏa Đạn Thuật (hỏa cầu biến bàn thành tro) trước mặt các phu nhân để lập uy; phá mê dược thiên nhân túy trong nến trắng nhờ phương pháp đề phòng từ thời Thất Huyền môn.","bridge":true,"khoang":116},{"text":"Đàm phán với Nghiêm thị: kể toàn bộ chân tướng cái chết Mặc đại phu và âm mưu Dư Tử Đồng; yêu cầu Noãn Dương Bảo Ngọc — bị từ chối vì Mặc phủ đang nguy cơ diệt môn.","bridge":true,"khoang":117},{"bridge":true,"khoang":"c0118–c0121","text":"Đề nghị nhị tuyển nhất với Nghiêm thị; dùng Tiêu Hồn Tán diệt Trầm Trọng Sơn và cả nhóm Tứ bình bang cũ; cài Tôn nhị cẩu làm bang chủ bù nhìn."},{"text":"Từ chối lấy bất kỳ tiểu thư Mặc phủ; đặt điều kiện chỉ giết Âu Dương Phi Thiên đổi lấy Noãn Dương Bảo Ngọc; buộc phu nhân nuốt thuốc làm con tin.","bridge":true,"khoang":123},{"text":"Dùng Noãn Dương Bảo Ngọc áp đan điền hơn 15 ngày, trị lành hoàn toàn hàn độc. Ám sát Âu Dương Phi Thiên bằng kiếm phù khi hắn một mình ngắm trăng. Tại Thái Nam sơn, gặp Vạn Tiểu Sơn — xác nhận là tu tiên giả, nhận ra đây là địa điểm Thái Nam hội.","bridge":true,"khoang":126},{"bridge":true,"khoang":"c0127–c0128","text":"Moi từ Vạn Tiểu Sơn kiến thức tu tiên giới: hệ thống cảnh giới ba giai đoạn, thọ mệnh theo cấp, bốn loại linh căn, bảy môn phái Việt quốc. Lần đầu bước vào Thái Nam tiểu hội — sự kiện giao dịch năm năm một lần; đề phòng cao độ trước mọi người trong hội."},{"bridge":true,"khoang":"c0129–c0132","text":"Bị Thanh Nhan chân nhân nghi ngờ tâm thuật bất chánh; từ chối nhóm Tùng Văn đạo sĩ; đổi Hoàng Long Đan lấy Phi hành phù, Không bạch phù chỉ và quyển chú thư; gặp nhóm tán tu gồm Ngô Cửu Chỉ và Hoàng Hiếu Thiên."},{"text":"Hỏi Khổ Tang về cách chế linh phù; nhận ra huynh muội Yến gia (đệ nhất gia tộc có Kết Đan kỳ) đến dự; muốn mua Trường Xuân công tầng cao.","bridge":true,"khoang":136},{"text":"Đổi đan dược lấy quyển Trường Xuân công tầng 1-13 và Kim Trúc bút (dị bảo chế phù) — di vật tộc một thiếu nữ đổi để anh trai tham gia lôi đài.","bridge":true,"khoang":137},{"bridge":true,"khoang":"c0138–c0140","text":"Thử chế phù thất bại nhiều lần; Trường Xuân công đột phá tầng 9 trước khi hội kết thúc; chứng kiến hán tử da đen rao Tàn Phiến — pháp bảo ẩn hình qua mặt cả Thiên Nhãn Thuật; dùng Phi hành phù đổi lấy Tàn Phiến."},{"text":"Đọc 'Thanh Khê bút lục', vỡ lẽ Thăng Tiên Lệnh do Hoàng Phong Cốc phát — lệnh bài đen thu từ Chu Nho chính là tư cách nhận Trúc Cơ đan + nhập môn.","bridge":true,"khoang":141},{"text":"Bị Tùng Văn đạo sĩ lén rắc phấn định vị, bị hai kẻ mai phục tại ao bùn — băng trùy xuyên vai và chân trái; tự phong mạch cầm máu, dùng súc cốt công thoát ra.","bridge":true,"khoang":142},{"bridge":true,"khoang":"c0143–c0146","text":"Phản sát hai kẻ tập sát (thuật biến cát + pháp lực xuyên tim), thu hơn 50 linh thạch và pháp khí; sau đó tới Hoàng Phong Cốc trình Thăng Tiên Lệnh xin nhập môn."},{"chuong":147,"importance":"normal","tieuDe":"Chính thức nhập môn Hoàng Phong Cốc","text":"Nộp Thăng Tiên Lệnh tại Hoàng Phong Cốc; bị xác định tứ thuộc tính ngụy linh căn, xác suất Trúc Cơ ~1%. Nhường Trúc Cơ đan cho cháu Diệp Tính đổi lấy quyền tùy ý chọn công tác trồng linh dược. Chưởng môn chấp thuận; Hàn Lập chính thức là Chấp sự đệ tử Hoàng Phong Cốc — đổi hoàn toàn tông môn, bước vào giới tu tiên thật."},{"bridge":true,"khoang":"c0148–c0151","text":"Nhận vật phẩm đệ tử mới (Hoàng ti sam, Thanh Diệp pháp khí, Liệt Dương kiếm, túi trữ vật); chọn nhiệm vụ Bách Dược Viên tại Kim Phù lĩnh dù người trước đều thất bại; bí mật chôn bình thần bí ở góc dược viên, phủ Tàn Phiến che dấu hiệu thu linh khí."},{"text":"Hơn hai năm tiềm tu tại Bách Dược Viên: Trường Xuân công liên tiếp đột phá hai tầng lên tầng 11 — trung đẳng trong đệ tử cấp thấp. Hoàng Long Đan và Kim Tủy Hoàn hết hẳn công hiệu; bắt đầu tìm đan dược mới.","bridge":true,"khoang":152},{"bridge":true,"khoang":"c0153–c0156","text":"Lần đầu vào Nhạc Lộc điện qua Truyền tống trận; gặp Hứa lão gian thương; tìm được đan phương Trúc Cơ đan nhưng cần tiên thiên chân hỏa (chỉ Trúc Cơ kỳ mới có); biết địa phế chi hỏa thay thế; mua Ngân Ti đỉnh (đan lô) giá 32 linh thạch."},{"text":"Ngô Phong tiết lộ chủ dược Trúc Cơ đan chỉ còn trong cấm địa phía sau Hoàng Phong Cốc — bị cổ cấm phong bế, chỉ Luyện Khí kỳ vào được, tỉ lệ sống sót dưới một phần tư. Sự kiện gọi là Huyết Cấm Thí Luyện, nửa năm nữa sẽ diễn ra. Hàn Lập mấy ngày liên tục cân nhắc: không tham gia thì Trúc Cơ vô vọng; tham gia thì 3/4 cơ hội chết. Đây là nút thắt quyết định toàn bộ hướng đi tiếp theo.","bridge":true,"khoang":160},{"text":"Quyết định tham gia Huyết Cấm Thí Luyện. Ngô Phong truyền Liễm khí thuật — thu giấu pháp lực trông như người phàm — để tránh bị cao thủ tiêu diệt trước trong cấm địa.","bridge":true,"khoang":161},{"bridge":true,"khoang":"c0162–c0165","text":"Ra phường thị Hoàng Phong Cốc mua vật phẩm; tại Vạn Bảo Lâu dùng 2 gốc linh thảo ngàn năm đổi toàn bộ hộp gấm: Kim phù tử mẫu đao, Huyền thiết phi thiên thuẫn, Thiên lôi tử, Kim Quang Chuyên phù bảo, Hoàng tinh chi."},{"text":"Rời Vạn Bảo Lâu, tình cờ phát hiện Lục sư huynh cưỡng bức Trần sư muội bằng Hợp Hoan Hoàn; trong túi Trần sư muội lộ hộp gỗ đỏ chứa 2 viên Trúc Cơ đan thật — mục tiêu hắn đang cần.","bridge":true,"khoang":165},{"bridge":true,"khoang":"c0166–c0168","text":"Ác đấu Lục sư huynh (Luyện Khí tầng 12, phong linh căn): xây ba lớp phòng thủ Tinh cương hoàn + Huyền thiết thuẫn + Kim Cương phù; kích hoạt Kim Quang Chuyên phù bảo hóa cự kiếm chặn Thanh giao khổng lồ."},{"text":"Tiêu hao pháp lực kéo dài: Hàn Lập bí mật nhai linh thảo duy trì ưu thế, chủ động bỏ lớp bảo hộ dồn lực điều cự kiếm chém đỉnh đầu Lục sư huynh đồng thời thi triển La Yên bộ tới cực hạn né đao phong. Lục sư huynh bị chém làm đôi. Thu Thanh Giao Kỳ và bình xanh chứa 2 viên Trúc Cơ đan thật từ túi trữ vật địch. Kim Quang Chuyên phù bảo hóa tro sau trận — hết tuổi thọ.","bridge":true,"khoang":169},{"bridge":true,"khoang":"c0170–c0171","text":"Khống chế Trần sư muội bằng Định Thần Phù rồi đưa về an toàn. Phi tang thi thể Lục sư huynh bằng Hỏa Đạn Thuật; bế quan 3 ngày khu trừ dị vật trong đan điền."},{"text":"Biết cấm địa sẽ bị phong bế 60 năm sau lần mở năm nay — nếu chờ thì đã quá tuổi Trúc Cơ tốt nhất. Dù đã có 2 viên Trúc Cơ đan nhưng với ngụy linh căn vẫn cần chủ dược trong cấm địa. Quyết tham gia ngay lần này. Bịa chuyện 'Long Lân quả' giải thích tu vi tăng đột biến cho Vương sư thúc.","bridge":true,"khoang":172},{"bridge":true,"khoang":"c0173–c0175","text":"Tập hợp tại Nghị sự đại điện; gặp lại Trần sư muội — lãnh diễm, không nhận ra hắn. Gặp lần đầu Lý Sư Tổ (Kết Đan kỳ bí ẩn của Hoàng Phong Cốc) — ngũ tạng như bị nhìn xuyên; từ chối ý định bái sư vì bí mật quá nhiều. Cưỡi Ngân Giáp Giác Mãng tới điểm hẹn tại Kiến Châu; từ chối Hướng Tính đề nghị liên minh."},{"bridge":true,"khoang":"c0176–c0178","text":"Trên đường tới điểm tập kết, quan sát các đoàn dự Huyết Cấm — đặc biệt đoàn Yểm Nguyệt tông toàn đệ tử trẻ song tu không một lão giả, nghi có âm mưu riêng."},{"text":"Bảy tổ sư Kết Đan kỳ cùng pháp bảo bản mệnh công phá Phong Nhận đại trận mấy canh giờ mới mở thông đạo. Vào thông đạo — ngay khi ra đầu kia bị na di trận pháp bên trong truyền tống đến góc ngẫu nhiên trong cấm địa, toàn đoàn tan tác.","bridge":true,"khoang":179},{"text":"Tỉnh dậy tại vùng đất xám bùn lầy cây cối quái dị, định vị được gần Ô Long đàm phía Đông Bắc. Thi triển Ẩn hình thuật, cảnh giác đi bộ tìm Hàn yên thảo. Chứng kiến hai đệ tử Linh Thú Sơn lập mưu dụ-giết đệ tử Thiên Khuyết bảo — bước đầu hiểu rõ quy tắc sinh tử trong cấm địa.","bridge":true,"khoang":180},{"importance":"normal","chuong":"@c0192","tieuDe":"Né phi xà và giữ sức","text":"Hàn Lập tiến vào khu vực trung tâm, bị hai con phi xà từ sau lưng tập kích nhưng kịp né tránh nhờ thần thức phát hiện trước. Khi bị truy đuổi, hắn chỉ dựa vào cước lực và linh ngoa để chạy, không dùng La yên bộ hay Ngự phong quyết vì thể lực chưa hồi phục sau các trận ác đấu.","anchor":"Lúc này hắn thuần túy dựa vào cước lực đôi chân để chạy","mucCt":"vua","nguon":["bồi-cuối-quyển"]}],"tuViMoc":[{"chuong":1,"canhGioi":"Phàm nhân","text":"Khởi điểm — thiếu niên Sơn Biên thôn, chưa tu luyện, trong người không một điểm chân khí.","tieu":[{"chuong":6,"canhGioi":"Phàm nhân — sơ học Vô danh khẩu quyết","text":"Bắt đầu tu Vô danh khẩu quyết do Mặc đại phu truyền; sinh ra tia lương khí lúc có lúc không."}]},{"chuong":8,"canhGioi":"Luyện Khí Kỳ (Vô danh khẩu quyết)","text":"Chính thức nhập môn tu tiên: vận hành được chu thiên đầu tiên qua kỳ kinh bát mạch. Giai đoạn nền móng trước khi đổi sang Trường Xuân công.","tieu":[{"chuong":8,"canhGioi":"Vô danh khẩu quyết — tầng 1","text":"Luồng năng lượng nội thể từ bằng sợi tóc tăng lên bằng sợi chỉ; vận hành được một chu thiên qua kỳ kinh bát mạch."},{"chuong":9,"canhGioi":"Vô danh khẩu quyết — tầng 2","text":"Luyện thành tầng 2 nhờ dược vật trợ lực; bị nội thương nhẹ khi trùng quan do kinh mạch phá liệt."}]},{"chuong":14,"canhGioi":"Luyện Khí Kỳ (Trường Xuân công)","text":"Đổi tu Trường Xuân công — công pháp theo Hàn Lập suốt chặng Luyện Khí. Tu vi leo từ tầng 3 lên đỉnh phong tầng 11 (cận Trúc Cơ), phần lớn nhờ Hoàng Long Đan và Kim Tủy Hoàn.","tieu":[{"chuong":14,"canhGioi":"Trường Xuân công — tầng 3 (đỉnh phong)","text":"Sau 4 năm khổ tu, đột phá tầng 3; cảm quan cực kỳ mẫn duệ. Sau đó đình trệ hơn một năm."},{"chuong":23,"canhGioi":"Trường Xuân công — tầng 3 đỉnh phong (sau biến cố tâm ma)","text":"Sau khi dùng bình an phù trừ tâm ma, công lực đạt đỉnh phong tầng ba; cách tầng bốn không còn xa."},{"chuong":28,"canhGioi":"Trường Xuân công — tầng 4","text":"Nhờ Hoàng Long Đan và Kim Tủy Hoàn, đột phá tầng tư trong một đêm; ngũ cảm tăng vọt mang tính chất, điều khiển được cỗ chân khí kỳ dị."},{"chuong":34,"canhGioi":"Trường Xuân công — tầng 5","text":"Khoảng c032-c033, nhờ Hoàng Long Đan và Kim Tủy Hoàn đột phá thẳng từ tầng tư lên tầng năm; năng lực 'gặp qua không thể quên' khởi phát."},{"chuong":43,"canhGioi":"Trường Xuân công — tầng 6","text":"Nhờ hơn mười bình linh dược, đột phá tầng sáu — tầng cao nhất Mặc đại phu từng cấp. Có năng lực phục hồi thân thể dị thường; vẫn giấu thực lực, chỉ phô tầng tư."},{"chuong":59,"canhGioi":"Trường Xuân công — tầng 6","text":"Dư Tử Đồng xác nhận Hàn Lập đã tu tới tầng 6 — chỉ kém Dư Tử Đồng một tầng. Chính tốc độ/tư chất vượt dự tính của Mặc đại phu khiến đoạt xá thất bại."},{"chuong":75,"canhGioi":"Trường Xuân công — tầng 8","text":"Nhờ ngày ngày ăn linh dược, đột phá lên tầng 8. Pháp lực vượt nhục thân Dư Tử Đồng lúc còn sống, nhưng kỹ xảo thực chiến còn kém."},{"chuong":138,"canhGioi":"Trường Xuân công — tầng 9","text":"Sau hơn mười ngày khổ tu kết hợp đan dược tại Thái Nam hội, đột phá tầng chín; pháp lực tăng gấp đôi tầng tám. Thành thạo Lưu sa thuật và Băng đông thuật."},{"chuong":152,"canhGioi":"Trường Xuân công — tầng 11 (cận Trúc Cơ)","text":"Hơn hai năm tiềm tu tại Bách Dược Viên, liên tiếp đột phá hai tầng lên tầng mười một — trung đẳng trong đệ tử cấp thấp Hoàng Phong Cốc. Hoàng Long đan và Kim Tủy hoàn hết hẳn công hiệu; bước tiếp theo cần đan dược mới (Trúc Cơ Đan)."}]},{"chuong":67,"canhGioi":"Bán tu tiên giả — khởi phát pháp thuật","buocNgoat":true,"text":"Bước ngoặt: đạt đỉnh phong tầng sáu Trường Xuân công và LUYỆN THÀNH pháp thuật từ bí tịch — Hỏa Đạn Thuật và Thiên Nhãn Thuật — xác nhận có pháp lực, là người duy nhất Thất Huyền môn được coi là 'bán tu tiên giả'. (Ba pháp thuật còn lại chưa nhập môn.)"}],"nhanMach":[{"ten":"Tam thúc (Lão Hàn béo)","tag":"ho-hang","quanHe":"Chú ruột, đệ tử ngoại môn Thất Huyền môn, người tiến cử Hàn Lập"},{"ten":"Hàn phụ","tag":"cha-me","quanHe":"Cha ruột, nông dân"},{"ten":"Hàn mẫu","tag":"cha-me","quanHe":"Mẹ ruột"},{"ten":"Tiểu muội muội","tag":"ho-hang","quanHe":"Em gái út, người Hàn Lập yêu thương nhất"},{"ten":"Mặc đại phu","tag":"su-mon","quanHe":"Sư phụ thân truyền tại Thất Huyền môn"},{"ten":"Trương Thiết","tag":"ban-be","quanHe":"Bạn đồng môn thân nhất, cùng làm đệ tử Mặc đại phu; hiện mất tích"},{"ten":"Lệ Phi Vũ","tag":"dong-mon","quanHe":"Đệ tử cùng môn (Lệ sư huynh); Hàn Lập cứu mạng và kết ơn nghĩa; hứa giúp đỡ khi cần"},{"ten":"Kim Đông Bảo (tiểu toán bàn)","tag":"dong-mon","quanHe":"Đệ tử cùng môn, nguồn tin tức; Hàn Lập hứa chữa bệnh miễn phí"},{"ten":"Trương Thiết / Khúc Hồn","tag":"ban-be","quanHe":"Bạn thân đồng môn; di thể bị cải tạo thành thi nhân Khúc Hồn, nay phục tùng Hàn Lập"},{"ten":"Mã phó môn chủ","tag":"dong-mon","quanHe":"Phó môn chủ Thất Huyền môn, muốn lôi kéo Hàn Lập vào hệ phái"},{"ten":"Mã Vinh","tag":"dong-mon","quanHe":"Đệ tử Lý trưởng lão, người dẫn Hàn Lập tới cứu sư phụ"},{"ten":"Tôn nhị cẩu","tag":"thu-ha","quanHe":"Thủ hạ bị khống chế bằng Hủ tâm hoàn; tai mắt tại Gia Nguyên Thành"},{"ten":"Nghiêm thị","tag":"su-mon","quanHe":"Tứ phu nhân Mặc đại phu — 'Tứ sư mẫu' theo thư mạo danh; đang thương lượng giao Noãn dương bảo ngọc"}],"tuiDo":{"phapBao":[{"ten":"Bình thần bí","loai":"pháp bảo (bất hoại, hút linh khí, thôi sanh dược thảo)","trangThai":"đang giữ — đeo trong túi da ở cổ","moTa":"Bình màu xanh nhạt, hoa văn lá xanh biếc sống động. Bất hoại trước vũ lực phàm nhân. Hút ánh sáng (quang điểm) ban đêm trời quang có trăng sao; khoảng 7 ngày/giọt tái sinh Thần Bí Dịch (lục dịch). Nhỏ trực tiếp một giọt nguyên chất lên một gốc dược thảo tăng khoảng 100 năm tuổi/dược tính. Lục dịch chỉ giữ được trong bình; rời bình một khắc là tan biến. Cũng là kịch độc: pha loãng cho thỏ uống thì thỏ nổ banh thân.","nguon":["c0010","c0012","c0013","c0014","c0023","c0024","c0025","c0026"]},{"ten":"Huyền thiết phi thiên thuẫn (Huyền thiết thuẫn)","loai":"pháp khí — khiên phi hành","trangThai":"đang giữ","moTa":"Khiên phi hành pháp khí mua tại Vạn Bảo Lâu c163. Phòng thủ linh hoạt: vừa chặn đỡ vừa tấn công, di chuyển được trong không trung. Dùng thực chiến c167 làm lớp giữa ba lớp phòng thủ trước Phong tường thuật của Lục sư huynh.","nguon":["c0163","c0165","c0167"]},{"ten":"Thanh giao kỳ","loai":"pháp khí — kỳ phách","trangThai":"đang giữ — thu từ Lục sư huynh @c170","moTa":"Pháp khí phong thuộc tính của Lục sư huynh. Kích hoạt tuyệt chiêu Hóa giao biến thành Thanh giao (hình phách phong hệ) khổng lồ. Hàn Lập thu sau khi Lục sư huynh chết.","nguon":["c0166","c0167","c0168","c0169","c0170"]},{"ten":"Ngọc Đái đoản kiếm","loai":"nhuyễn kiếm (trọng kim)","trangThai":"đang giữ","moTa":"Nhuyễn kiếm Hàn Lập đặt thợ rèn làm bằng trọng kim — thanh kiếm đắt nhất hắn có. Rộng chừng một ngón tay, dài tầm thước rưỡi, lưỡi kiếm mềm dẻo. Lần đầu dùng tại c60 để chém nguyên thần Dư Tử Đồng.","nguon":["c0060"]},{"ten":"Ống đồng đựng độc dịch","loai":"vũ khí ẩn (độc)","trangThai":"đang giữ","moTa":"Ống đồng nhỏ chứa chất lỏng đen quánh đặc mùi hủ xú; bóp ngón cái thì phun ra. Tổn thương nguyên thần/quang cầu khi bắn trúng. Dùng lần đầu tại c60 để làm suy yếu nguyên thần Dư Tử Đồng trước khi chém.","nguon":["c0060"]}],"danDuoc":[{"ten":"Trúc Cơ đan (2 viên thật)","loai":"đan dược tu tiên — đột phá Trúc Cơ kỳ","trangThai":"đang giữ — thu từ túi Lục sư huynh @c170","moTa":"Hai viên Trúc Cơ đan thật, đựng trong bình xanh. Hàn Lập thu được từ túi trữ vật của Lục sư huynh sau trận chiến. Đây là mục tiêu hắn đã mưu tính từ đầu chuyến ra phường thị.","nguon":["c0166","c0170"]},{"ten":"Trừu Tủy Hoàn","loai":"đan dược (từng dùng chia nhỏ)","trangThai":"đã dùng","moTa":"Từng chia một viên thành mười phần làm dược dẫn — cách dùng an toàn không gây hại.","nguon":["c0020"]},{"ten":"Thi Trùng Hoàn","loai":"đan dược (độc trùng noãn trong cơ thể)","trangThai":"đã được giải trừ — uống giải dược từ Mặc đại phu","moTa":"Trùng noãn điều chế bằng bí pháp của Mặc đại phu. Tiềm phục trong cơ thể một năm; có giải dược đặc chế thì tan rã, không thì phá vỏ ăn sạch nội tạng, chết trong ba ngày ba đêm thống khổ. Hàn Lập bị ép nuốt làm con tin. Thanh Linh Tán không giải được. Mặc đại phu giao giải dược khi Hàn Lập trở lại đúng hẹn bốn tháng sau.","nguon":["c0031","c0032","c0044"]}],"congPhap":[{"ten":"Trường Xuân công","loai":"công pháp tu thân","trangThai":"đang tu (tầng 11)","moTa":"Tên thật của vô danh khẩu quyết Mặc đại phu truyền. Yêu cầu người tu còn trẻ và có linh căn. Sinh ra lương khí lạnh (chân khí kỳ dị) trong nội thể. Tầng năm cho năng lực ghi nhớ võ học gặp qua không thể quên; tầng sáu cho năng lực phục hồi thân thể dị thường vượt xa người thường. Mỗi tầng tăng mạnh tinh thần và ngũ cảm; sinh ra năng lượng gọi là 'ngụy chân khí' vận hành trong kinh mạch, chỉ làm xúc giác bén nhạy, không uy lực như chân khí thật. Tầng 8 đạt được nhờ ngày ngày ăn linh dược — pháp lực vượt qua nhục thân Dư Tử Đồng lúc còn sống. Tầng 9 đột phá tại Thái Nam hội c138 sau hơn mười ngày kết hợp đan dược; pháp lực tăng gấp đôi so với tầng 8. Tầng 11 đột phá tại Hoàng Phong Cốc c152 sau hơn hai năm tiềm tu dùng Hoàng Long đan và Kim Tủy hoàn liên tục; đây là giới hạn của hai loại đan này.","nguon":["c0006","c0007","c0008","c0009","c0014","c0015","c0028","c0030","c0034","c0043","c0045","c0075","c0138","c0152"]},{"ten":"Nhuyễn cốt công","loai":"công pháp tu thân","trangThai":"đã luyện thành","moTa":"Một trong chín bí kỹ Hàn Lập chọn từ kiếm phổ để luyện trong khe núi ẩn tu. Khiến thân thể mềm dẻo như không có xương, có thể áp sát ép thân xuống mặt đất để ẩn mình hoàn toàn ngay trước mắt đối thủ.","nguon":["c0042","c0046"]},{"ten":"Liễm tức công","loai":"công pháp tu thân","trangThai":"đã luyện tới hỏa hầu nhất định","moTa":"Công pháp ẩn giấu hơi thở và khí tức. Hàn Lập luyện tới hỏa hầu nhất định sau ~hai tháng trong khe núi; kết hợp với Nhuyễn cốt công và Ngụy nặc thuật để ẩn mình hoàn toàn.","nguon":["c0042","c0046"]},{"ten":"Ngụy nặc thuật","loai":"thuật","trangThai":"đã luyện tới hỏa hầu nhất định","moTa":"Thuật ngụy trang ẩn mình. Hàn Lập luyện tới hỏa hầu nhất định; dùng ngụy trang thành cọc gỗ vàng kiểm nghiệm thành quả, bắt được chim lông xám bay vào khe núi mà không bị phát hiện.","nguon":["c0042","c0046"]},{"ten":"La Yên bộ","loai":"than-phap","trangThai":"đã luyện thành — dung hợp với Ngự Phong Quyết","moTa":"Thân pháp di chuyển như làn khói xanh, quỷ mị lặng không tiếng động, biến hóa góc độ khó tưởng tượng. Hàn Lập luyện trong rừng gai nguy hiểm, giắt thiết linh (chuông sắt) ở cổ, hông, tay, chân rèn di chuyển không phát tiếng. Tốn thể lực lớn khi thi triển liên tục. Từ c75: dung hợp với Ngự Phong Quyết (thi triển Ngự Phong trước rồi vận La Yên bộ) — thân pháp xuất quỷ nhập thần, 'kỳ ảnh bất kiến kỳ nhân'. Tại c169: thi triển tới cực hạn né đao phong Phong thuộc tính của Lục sư huynh trong trận ác đấu.","nguon":["c0043","c0047","c0048","c0075","c0169"]},{"ten":"Trát Nhãn kiếm pháp","loai":"bí kỹ kiếm pháp","trangThai":"đang nghiên cứu (ghi thuộc lòng)","moTa":"Kiếm kỹ ám sát lợi dụng ánh sáng và sai lầm thị giác. Không cần nội lực tinh thuần; đòi hỏi ngũ quan hơn người và thiên phú. Hàn Lập ghi tạc toàn bộ vào trí nhớ thay vì chép để giấu Mặc đại phu.","nguon":["c0033","c0034","c0035","c0036","c0037","c0039","c0040"]},{"ten":"Hoàng Long Đan","loai":"đan dược (thánh dược)","trangThai":"đã dùng một viên","moTa":"Thánh dược thoát thai hoán cốt, gia tăng công lực lớn. Hàn Lập tự phối chế bằng lục dịch thôi sanh dược tài; dùng một viên cùng Kim Tủy Hoàn giúp đột phá tầng tư.","nguon":["c0027","c0028"]},{"ten":"Kim Tủy Hoàn","loai":"đan dược (thánh dược)","trangThai":"đã dùng một viên","moTa":"Thánh dược thoát thai hoán cốt, gia tăng công lực lớn. Hàn Lập tự phối chế; dùng cùng Hoàng Long Đan để đột phá tầng tư.","nguon":["c0027","c0028"]},{"ten":"Thanh Linh Tán","loai":"đan dược (thánh dược)","trangThai":"đang lưu giữ (đã dùng chữa cho Lý trưởng lão)","moTa":"Thánh dược giải độc hiếm có, giải được trăm ngàn loại kịch độc. Hàn Lập tự phối chế bằng lục dịch thôi sanh dược tài. Dùng tại c71: hòa vào nước ấm cho Lý trưởng lão uống để giải hỗn hợp độc Dã Lang bang; không giải được độc còn tiềm phục sâu trong người Lý trưởng lão.","nguon":["c0027","c0071"]},{"ten":"Dưỡng Tinh Đan","loai":"đan dược (thánh dược)","trangThai":"đang lưu giữ (đã dùng một số)","moTa":"Linh dược trị nội ngoại thương thần kỳ; ăn một viên lập tức cầm máu liền sẹo, ngày thứ hai tiêu trừ cả vết sẹo, không để lại dấu vết. Mạnh hơn nhiều thuốc trị thương thông thường. Hàn Lập dùng trong quá trình luyện La Yên bộ trong rừng gai. Tự phối chế bằng lục dịch thôi sanh dược tài.","nguon":["c0027","c0043"]},{"ten":"Hỏa Đạn Thuật","loai":"pháp thuật công kích","trangThai":"đã cải tiến","moTa":"Pháp thuật công kích đầu tiên Hàn Lập luyện thành từ bí tịch Trường Xuân công. Phóng ra hỏa cầu đỏ rực, uy lực đủ nung chảy tinh cương và bốc hơi nước. Từ c75: Hàn Lập cải tiến — thay vì bắn hỏa cầu đi (quá chậm, cao thủ khinh công dễ né), chỉ thi triển nửa thuật, giữ hỏa cầu trên lòng bàn tay làm vũ khí cận chiến đoản binh lợi hại.","nguon":["c0067","c0068","c0075"]},{"ten":"Thiên Nhãn Thuật","loai":"pháp thuật phụ trợ","trangThai":"đã luyện thành","moTa":"Pháp thuật quan sát pháp lực, luyện rất dễ (thử là được). Vận lên mắt để xem đối phương có pháp lực hay không, pháp lực thâm hậu hay không, và có dùng pháp thuật phụ trợ trên người không. Pháp lực hiện ra dưới dạng bạch quang nhàn nhạt, dày đặc nhất ở đan điền. Ngoài ra còn gây uy hiếp tâm lý với người thường — họ cảm thấy bị nhìn thấu nội tâm. Tại c126 xác nhận Vạn Tiểu Sơn là tu tiên giả.","nguon":["c0067","c0068","c0096","c0126"]}],"linhThu":[{"ten":"Vân sí điểu (chim lông vàng)","trangThai":"đang giữ — đậu trên vai","moTa":"Chim nhỏ màu vàng ban đầu là tai mắt của Mặc đại phu theo dõi Hàn Lập. Hàn Lập giữ lại sau khi Mặc đại phu chết. Từ c98 đậu trên vai Hàn Lập khi hắn rời Thất Huyền môn và tới Gia Nguyên Thành.","nguon":["c0042","c0098","c0100"]}],"nguyenLieu":[],"linhThao":[{"ten":"Túi mầm thất tinh thảo","trangThai":"đang giữ","moTa":"Túi xám buộc dây đỏ chứa mầm thất tinh thảo — mười năm nữa sẽ thành nguyên liệu tốt nhất chế tác bùa chú. Đổi từ thiếu nữ quầy hàng tại c137.","nguon":["c0137"]}],"khac":[{"ten":"Kiếm phù / Kim Quang Chuyên phù bảo (cự kiếm xám)","loai":"phù bảo tu tiên","trangThai":"hóa tro hoàn toàn @c170 — hỏng không thể dùng","moTa":"Ban đầu là đạo phù lục vẽ tiểu kiếm xám (đoạt từ Chu Nho c91); từ c165 xác định thêm tức là Kim Quang Chuyên phù bảo mua tại Vạn Bảo Lâu. Kích hoạt hóa cự kiếm xám 2–3 trượng, sát thương cực lớn. Dùng thực chiến c167–c169: chặn Thanh giao, chém đôi Lục sư huynh. Hóa tro hoàn toàn sau trận c170 — hết tuổi thọ.","nguon":["c0091","c0092","c0095","c0096","c0143","c0165","c0167","c0168","c0169","c0170"]},{"ten":"Kim Cương phù","loai":"phù lục hộ thể","trangThai":"đang giữ","moTa":"Vỗ lên người tạo lớp kim tráo (giáp kim quang) chống được pháp khí địch; làm thân pháp chậm lại. Lấy từ Kim Quang thượng nhân; khẩu quyết học từ Khẩu Tang hòa thượng. Dùng thực chiến c143.","nguon":["c0143"]},{"ten":"Hoàng ti sam","loai":"pháp y","trangThai":"đang mặc","moTa":"Áo tơ vàng — pháp y cấp phát cho đệ tử mới Hoàng Phong Cốc, nhận từ Lâm sư đệ c148.","nguon":["c0148"]},{"ten":"Thanh Diệp pháp khí (pháp khí phi hành hình lá xanh)","loai":"pháp khí phi hành","trangThai":"đang dùng","moTa":"Pháp khí phi hành đặc trưng Hoàng Phong Cốc, hình chiếc lá xanh. Dễ điều khiển nhưng tốc độ chậm hơn tuấn mã thường một chút vì đệ tử trong cốc đông. Hàn Lập dùng phi hành lần đầu c149.","nguon":["c0148","c0149"]},{"ten":"Liệt Dương kiếm","loai":"pháp khí — kiếm","trangThai":"đang giữ","moTa":"Kiếm pháp khí cấp phát cho đệ tử mới Hoàng Phong Cốc, nhận từ Lâm sư đệ c148.","nguon":["c0148"]},{"ten":"Lãnh Nguyệt đao","loai":"pháp khí — đao","trangThai":"đang giữ","moTa":"Đao pháp khí cấp phát cho đệ tử mới Hoàng Phong Cốc, nhận từ Lâm sư đệ c148.","nguon":["c0148"]},{"ten":"Thập Bội Trữ Vật (túi trữ vật)","loai":"túi trữ vật cấp thấp","trangThai":"đang dùng","moTa":"Túi trữ vật miệng nhỏ màu đen cấp phát cho đệ tử mới; cấp thấp, không nhận chủ — ai cướp được túi thì chiếm hữu toàn bộ vật bên trong. Ba kiêng kỵ: không chứa quá giới hạn; không thu sinh linh sống; không để lộ trước người tu tiên khác. Nhận từ Lâm sư đệ c148.","nguon":["c0148"]},{"ten":"Tàn Phiến (pháp bảo)","loai":"pháp bảo ẩn hình","trangThai":"đang dùng — phủ che bình thần bí trong Bách Dược Viên","moTa":"Mảnh tàn của pháp bảo, hình như tấm vải trong suốt đầy nếp nhăn, viền xung quanh rách nát, mặt trên thỉnh thoảng lóe ánh sáng trắng. Bao quanh vật thể sẽ ẩn hình hoàn toàn, một tia linh khí cũng không tiết ra ngoài và không để linh khí ngoài thâm nhập vào — Thiên Nhãn Thuật cũng không phá được. Do tu sĩ Kết Đan kỳ hoặc Nguyên Anh kỳ luyện chế. Hàn Lập đổi bằng một tờ Phi hành phù; xác nhận công hiệu hút linh khí tại c141. Từ c151: phủ lên trên bình thần bí đã chôn ở góc Bách Dược Viên để che giấu dấu hiệu thu nạp linh khí bất thường của bình — nhờ đó linh khí khu vực chỉ đậm hơn chút ít, không gây nghi ngờ.","nguon":["c0139","c0140","c0141","c0151"]},{"ten":"Kim Trúc bút","loai":"dị bảo chế phù","trangThai":"đang giữ","moTa":"Bút lông màu vàng rực dùng họa phù. Ngòi bút bằng lông yêu thú cấp hai Kim Tình Viên, thân bút bằng hỗn hợp kim tinh và ô thiết, do tu sĩ Trúc Cơ kỳ tế luyện ba ngày ba đêm. Di vật của tộc thiếu nữ bán cho Hàn Lập; giúp rót linh lực vào bút rất thuận lợi khi chế phù.","nguon":["c0137","c0138"]},{"ten":"Không bạch phù chỉ","loai":"phù lục sơ cấp bậc thấp","trangThai":"đang giữ","moTa":"Phù trắng bậc thấp dùng làm nền vẽ linh phù. Hàn Lập đổi được cùng Phi hành phù tại c132.","nguon":["c0132"]},{"ten":"Mộc bài mộc xanh (lệnh bài Bách Dược Viên)","loai":"lệnh bài cấm chế","trangThai":"đang giữ","moTa":"Khối mộc bài màu xanh biếc dùng điều khiển cấm chế ra vào Bách Dược Viên. Mã sư bá giao khi bàn giao quyền quản lý dược viên cho Hàn Lập.","nguon":["c0151"]},{"ten":"Hoàng Đồng bình (pháp khí trữ vật)","loai":"pháp khí — trữ vật","trangThai":"đang giữ","moTa":"Pháp khí trữ vật Trúc Cơ kỳ luyện chế, cất giữ vật phẩm không để linh lực phát tán ra ngoài. Là một trong ba pháp khí Hàn Lập nhận được do Diệp Tính bồi thường (dù bị hối ước). Hạn chế: chỉ giữ được lục dịch trong bình thần bí tối đa khoảng một ngày rồi lục dịch biến mất — xác nhận lục dịch không đơn thuần là thiên địa linh khí ngưng tụ.","nguon":["c0151","c0152"]},{"ten":"Ngọc đồng Trúc Cơ đan (bản phục chế)","loai":"ngọc giản lưu trữ đan phương","trangThai":"đang giữ","moTa":"Ngọc đồng màu xanh mướt ghi đầy đủ phương pháp luyện chế Trúc Cơ đan — từ nguyên liệu đến cách ngưng luyện thành đan. Bản phục chế từ ngọc đồng gốc tại tàng thư Nhạc Lộc điện, giá 10 linh thạch. Nhược điểm then chốt: bắt buộc phải dùng tiên thiên chân hỏa (chỉ Trúc Cơ kỳ mới có) để luyện thành.","nguon":["c0155"]},{"ten":"Ngọc đồng Định nhan đan (bản phục chế)","loai":"ngọc giản lưu trữ đan phương","trangThai":"đang giữ","moTa":"Ngọc đồng màu đỏ rực ghi phương pháp luyện chế Định nhan đan — đan chỉ dùng để giữ dung nhan thanh xuân vĩnh trú, không có tác dụng tu luyện. Ưu điểm: không cần tiên thiên chân hỏa, dược liệu thường thấy — nhưng cần dược tính ngàn năm trở lên. Bản phục chế giá 10 linh thạch; Hàn Lập giữ lại vì có thể tự luyện và bán cho người tu tiên khác.","nguon":["c0155"]},{"ten":"Ngân Ti đỉnh (đan lô)","loai":"pháp khí — đan lô","trangThai":"đang giữ","moTa":"Đan lô màu bạc nhỏ nhắn, tinh phẩm trong các đan lô của Hứa lão, thượng phẩm pháp khí. Hàn Lập chọn vì nhỏ gọn, tiết kiệm không gian túi trữ vật. Giá 32 linh thạch cấp thấp. Dùng để luyện đan dược tại huyền dương hỏa địa.","nguon":["c0156"]},{"ten":"Thăng Tiên Lệnh (lệnh bài đen)","loai":"vật nghịch thiên","trangThai":"đã nộp cho Hoàng Phong Cốc @c144-145 — đổi lấy tư cách nhập môn","moTa":"Lệnh bài một mặt khắc hai chữ 'Thăng Tiên', thu từ tro tàn Chu Nho c93. Do Hoàng Phong Cốc phát ra cho tổ thượng Tần gia. Người cầm tới đúng môn phái phát lệnh được ban Trúc Cơ đan + tư cách nhập môn — 'nhận lệnh không nhận người'. Vỡ lẽ lai lịch qua Thanh Khê bút lục c141. Hàn Lập nộp lệnh gia nhập Hoàng Phong Cốc c144-145; nhường Trúc Cơ đan cho cháu Diệp Tính.","nguon":["c0093","c0141","c0144","c0145"]},{"ten":"Tần thị tộc phổ","loai":"sách gia phả","trangThai":"đang giữ","moTa":"Gia phả tộc Tần của Chu Nho (Tần Diệp Lĩnh), thu được từ tro tàn sau khi Chu Nho bị giết tại c93.","nguon":["c0093"]},{"ten":"Văn long giới (một trong cặp)","loai":"tín vật — nhẫn hình rồng","trangThai":"đã trao cho Nghiêm thị @c109 — nay trong tay bà","moTa":"Một chiếc trong cặp nhẫn khắc hoa văn rồng (long văn giới chỉ). Tín vật Mặc đại phu để lại. Hàn Lập ném vào phòng Nghiêm thị để xác nhận thân phận; khớp hoàn hảo với chiếc Nghiêm thị đang đeo, hoa văn rồng liền mạch không kẽ hở.","nguon":["c0109"]}]}},"uuTien":1,"nguon":["c0001","c0002","c0003","c0004","c0005","c0006","c0007","c0008","c0009","c0010","c0011","c0012","c0013","c0014","c0015","c0016","c0017","c0018","c0019","c0020","c0021","c0022","c0023","c0024","c0025","c0026","c0027","c0028","c0029","c0030","c0031","c0032","c0033","c0034","c0035","c0036","c0037","c0038","c0039","c0040","c0041","c0042","c0043","c0044","c0045","c0046","c0047","c0048","c0049","c0050","c0051","c0052","c0053","c0054","c0055","c0056","c0057","c0058","c0059","c0060","c0061","c0062","c0063","c0064","c0065","c0066","c0067","c0068","c0069","c0070","c0071","c0072","c0073","c0074","c0075","c0076","c0077","c0078","c0079","c0080","c0081","c0082","c0083","c0084","c0085","c0086","c0087","c0088","c0089","c0090","c0091","c0092","c0093","c0094","c0095","c0096","c0097","c0098","c0099","c0100","c0101","c0102","c0103","c0104","c0105","c0106","c0107","c0108","c0109","c0110","c0111","c0112","c0113","c0114","c0115","c0116","c0117","c0118","c0119","c0120","c0121","c0122","c0123","c0124","c0125","c0126","c0127","c0128","c0129","c0130","c0131","c0132","c0133","c0134","c0135","c0136","c0137","c0138","c0139","c0140","c0141","c0142","c0143","c0144","c0145","c0146","c0147","c0148","c0149","c0150","c0151","c0152","c0153","c0154","c0155","c0156","c0157","c0158","c0159","c0160","c0161","c0162","c0163","c0164","c0165","c0166","c0167","c0168","c0169","c0170","c0171","c0172","c0173","c0174","c0175","c0176","c0177","c0178","c0179","c0180"]},{"id":"mac-dai-phu","name":"Mặc đại phu","cn":"墨大夫","aliases":["Mặc lão","Mặc phu","Mặc Cư Nhân"],"tenThat":"Mặc Cư Nhân","gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn — Cung Phụng đường","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân vô linh căn — cao thủ võ lâm (Ma Ngân Thủ); tự tu Trường Xuân công tới tầng 4 (vì không có linh căn)","trangThai":"tu-vong","blurb":"Mặc đại phu, tên thật Mặc Cư Nhân, là thầy thuốc bí ẩn của Thất Huyền môn, từng nhận Hàn Lập và Trương Thiết làm đệ tử ký danh rồi thu Hàn Lập làm thân truyền vì thể chất đặc biệt. Thực chất hắn là cao thủ võ lâm Lam Châu hiệu “quỷ thủ”, sở trường Ma Ngân Thủ, nhưng chỉ là phàm nhân vô linh căn, bị Dư Tử Đồng ký sinh và lợi dụng các quỷ thuật để chuẩn bị đoạt xá. Cuối cùng hắn phát động nghi thức đoạt xá Hàn Lập nhưng thất bại, nguyên thần bị thôn phệ ngược mà chết, còn để lại di thư cùng hậu thủ kỳ độc thi trung hoàn.","vaiTro":"Sư phụ danh nghĩa của Hàn Lập — phàm nhân mưu đoạt xá","tinhCach":"Thâm trầm, giỏi che giấu thân phận và mưu tính; tàn nhẫn, xem đệ tử như công cụ; giảo hoạt, biết cài bẫy và phòng bị bằng độc; tham sinh, khao khát trẻ lại và cướp thân","tabs":{"diem":[{"text":"Nhận Hàn Lập và Trương Thiết làm đệ tử ký danh, truyền Vô danh khẩu quyết với điều kiện tra khảo.","chuong":"@c0006"},{"text":"Phát hiện thể chất kỳ dị của Hàn Lập và thu hắn làm thân truyền đệ tử.","chuong":"@c0008"},{"text":"Lộ chân tướng là cao thủ võ lâm thực lực cao sâu, ra tay điểm huyệt chế trụ Hàn Lập thần tốc và tự xưng tên thật Mặc Cư Nhân.","chuong":"@c0029"},{"text":"Từng là cao thủ Lam Châu hiệu “quỷ thủ”, sở hữu tuyệt kỹ Ma Ngân Thủ.","chuong":"@c0030"},{"text":"Hoàn thành Thất Quỷ Phệ Hồn đại pháp, tạm hồi phục dung mạo nam tử khoảng ba mươi tuổi.","chuong":"@c0053"},{"text":"Đoạt xá thất bại, chết vô thanh vô tức do nguyên thần bị Hàn Lập thôn phệ ngược.","chuong":"@c0057"}],"kinhLich":[{"chuong":5,"importance":"major","text":"Bước ra từ rừng rậm, thiếu nhân thủ, chỉ ngay vào hai ký danh đệ tử Hàn Lập và Trương Thiết bắt về Thần thủ cốc."},{"chuong":6,"importance":"major","text":"Chính thức nhận Hàn Lập và Trương Thiết làm đệ tử ký danh; truyền Vô danh khẩu quyết với điều kiện tra khảo."},{"chuong":8,"importance":"major","text":"Kiểm tra và phát hiện thể chất kỳ dị của Hàn Lập; thu làm thân truyền đệ tử. Đột ngột đổi ý nhận cả Trương Thiết với tâm pháp khác."},{"chuong":9,"importance":"normal","text":"Cấp thạch thất luyện công riêng và dược vật trân quý cho Hàn Lập; truyền Tượng giáp công cho Trương Thiết."},{"chuong":14,"importance":"normal","text":"Hứa thưởng bạc trắng tăng gấp đôi mỗi tầng khẩu quyết Hàn Lập đột phá; phong tỏa Thần Thủ Cốc để hắn chuyên tâm tu luyện."},{"chuong":15,"importance":"normal","text":"Hạ sơn tìm dược tài — rời Thất Huyền môn, để Hàn Lập ở lại Thần Thủ Cốc một mình. Sức khỏe suy sụp, dược vật trợ lực đã cạn kiệt."},{"chuong":28,"importance":"major","text":"Trở về Thần Thủ Cốc sau một năm vắng mặt, dẫn theo một người thần bí mặc lục bào che kín mặt. Sắc mặt hôi bại không sinh khí như đại hạn sắp đến. Kiểm tra tiến độ tu luyện của Hàn Lập."},{"chuong":29,"importance":"major","text":"Lộ chân tướng là cao thủ thực lực cao sâu: ra tay điểm huyệt chế trụ Hàn Lập thần tốc. Tự xưng tên thật Mặc Cư Nhân; tuyên bố quan hệ hai bên chỉ là lợi dụng lẫn nhau."},{"chuong":30,"importance":"major","text":"Phơi bày toàn bộ thân thế: 30 tuổi thật, từng là cao thủ võ lâm Lam Châu hiệu 'quỷ thủ'; bị thân tín ám toán, nhờ kỳ thư tìm cách phá giải nhưng bị tà khí xâm cốt lão hóa cực nhanh; chỉ còn sống thêm khoảng một năm. Cần Hàn Lập luyện Trường Xuân công tới tầng tư để kích thích bí huyệt phá giải."},{"chuong":41,"importance":"normal","text":"Đọc thư Hàn Lập để lại, bóp nát thư, thả Vân sí điểu đi theo dõi Hàn Lập. Nhắc tới 'kế hoạch' lớn gắn với mốc bốn tháng; tuyên bố 'thần cản sát thần, phật cản sát phật', cười rộ phong cuồng."},{"chuong":42,"importance":"normal","text":"Nghe Dư Tử Đồng cảnh báo qua truyền âm trong đầu; đang luyện công pháp do Dư Tử Đồng cấp (đã thử trên động vật, có con vật chết). Đang rải trận pháp bằng bột xương dã thú trong thạch thất; hoàn toàn không biết Hàn Lập đã phát hiện thủ đoạn giám thị của mình."},{"chuong":44,"importance":"normal","text":"Giao giải dược Thi Trùng Hoàn (viên đan màu đen) cho Hàn Lập như mồi nhử để dụ hắn đồng ý cho kiểm tra công lực. Lão hóa rõ rệt hơn, trông như ông lão bảy mươi."},{"chuong":45,"importance":"major","text":"Bắt mạch xác nhận công lực rồi trở mặt: hô 'Thắt' khống chế thân thể Hàn Lập, định điểm ma huyệt trước ngực. Thất bại vì cơ thể Hàn Lập cứng như thiết bản; bị Hàn Lập thoát khỏi tay nắm nhờ cổ tay mềm dẻo như cá chạch. Bị Hàn Lập rút kiếm lần đầu lộ nanh vuốt."},{"chuong":46,"importance":"normal","text":"Bị Hàn Lập ám sát một kiếm suýt thủng bụng; phải dùng Thiết bản kiều mới thoát, lần đầu trong nửa đời giang hồ bị áp sát tử thần đến mặt xanh lét run rẩy. Thừa nhận đã coi nhẹ Hàn Lập, chuẩn bị nghiêm túc dùng tuyệt kỹ thật."},{"chuong":47,"importance":"normal","text":"Thi triển Ma Ngân Thủ — tuyệt kỹ thành danh của mình. Hai tay bành trướng chuyển màu trắng bạc cứng chắc như bạc thật. Chủ ý chỉ dùng nửa thành công lực để bắt sống Hàn Lập, không giết."},{"chuong":49,"importance":"normal","text":"Bị bạch quang mù tạm thời; dựa Ma Ngân Thủ và công phu nghe tiếng gió định vị bắt được mũi kiếm của Hàn Lập. Bị tiêm trùy giấu trong mũi kiếm rỗng đâm vào gáy, chỉ trầy da nhờ bản năng né thoát thần tốc. Tự phong huyết mạch cầm máu."},{"chuong":50,"importance":"major","tieuDe":"Bị hạ độc Triền Hương Ti","text":"Nhận ra bị trúng Triền Hương Ti — độc dược từ tờ phương thuốc chính lão chép rồi kẹp trong dược thư bỏ quên, nay bị Hàn Lập đọc lén và bôi lên binh khí. Biến sắc kinh hãi vì thứ này nằm ngoài dự liệu; cố chống đỡ nhưng vết thương ở gáy đang phát độc."},{"chuong":51,"importance":"normal","tieuDe":"Điều Thiết Nô bắt Hàn Lập","text":"Không ngại Triền Hương Ti của Hàn Lập — có chỗ dựa. Lệnh Thiết Nô bắt giữ Hàn Lập nhưng ra lệnh 'điểm nhẹ thôi' vì Hàn Lập còn 'có đại dụng'. Lấy hộ tâm kính của Hàn Lập (giải thích vì sao điểm huyệt trước thất bại). Giở hộp gỗ ngân nhận — dụng cụ thi thuật sắp tới."},{"chuong":52,"importance":"major","tieuDe":"Phát động Thất Quỷ Phệ Hồn đại pháp","text":"Tự cắm bảy dao nhọn cán hình đầu quỷ vào hai vai, hai chân, bụng và ngực. Nhập định, kết ấn hoa sen, niệm chú; mặt nổi quỷ vụ/hắc vụ đậm đen tạo xúc tu. Hét tên bí thuật 'Thất Quỷ Phệ Hồn đại pháp'."},{"chuong":53,"importance":"major","tieuDe":"Hồi phục tuổi trẻ","text":"Hoàn thành Thất Quỷ Phệ Hồn đại pháp — bảy đầu quỷ hút sạch quỷ vụ trên mặt, lão trở về dung mạo nam tử ~30 tuổi, mỹ nam tử mị lực. Vẫn chưa buông tha Hàn Lập — mục đích thật với hắn còn ẩn."},{"chuong":54,"importance":"major","tieuDe":"Khởi động đoạt xá bằng Định Thần Phù","text":"Tuyên bố thẳng ý định cướp thân Hàn Lập. Niệm chú dán Định Thần Phù lên sau gáy Hàn Lập — khống chế hoàn toàn thân thể hắn. Lộ quá khứ mỹ nam tử 'làm điên đảo giang hồ hiệp nữ'."},{"chuong":55,"importance":"normal","tieuDe":"Tự xây nhà đá hành thuật","text":"Dẫn Hàn Lập vào căn nhà đá kín mít tự xây; đặt Hàn Lập giữa trận đồ khảm ngọc thạch. Ra lệnh Thiết Nô canh ngoài 'giết không tha'. Đối thoại căng thẳng với nguyên thần Dư Tử Đồng — ép thề độc vì nghi y ôm hận lừa gạt."},{"chuong":56,"importance":"major","tieuDe":"Thực hiện nghi thức đoạt xá","text":"Cắm kim châm vào bí huyệt tăng tinh lực, kích hoạt trận đồ bằng hồng quang, niệm chú ngữ thôi miên Hàn Lập. Thực ra bị Dư Tử Đồng giăng bẫy: lão vô linh căn, tự tu tầng 4 bằng pháp lực mượn, không hơn được Hàn Lập tầng 6-7 → bị cắn ngược."},{"chuong":57,"importance":"major","tieuDe":"CHẾT — đoạt xá thất bại","text":"Chết 'vô thanh vô tức' do đoạt xá thất bại, nguyên thần bị Hàn Lập thôn phệ ngược. Ngoại hình lúc chết: hóa lão cực độ, tóc bạc, khô gầy tiều tụy, già thêm ~10 tuổi, mắt trợn tròn hoảng sợ."},{"chuong":62,"importance":"normal","tieuDe":"Di thư và kỳ độc thi trung hoàn","text":"Hàn Lập lục soát thi thể, phát hiện di thư cài sẵn của lão: đã hạ kỳ độc thi trung hoàn từ trước (thứ thật ra là kỳ độc phát tác 1-2 năm, chỉ noãn dương bảo ngọc mới giải được — không phải trùng noãn như tuyên bố trước đó), đặt giao dịch ràng buộc Hàn Lập tới nhà an bài thân nhân để đổi lấy noãn dương bảo ngọc."},{"text":"Ngày ngày ôm khư khư cuốn Trường Sinh Kinh, hé lộ động cơ thật: không phải thầy thuốc thường mà là kẻ tu luyện mưu cầu trường sinh bất tử, 'sống qua ngàn năm' như lão rùa đen — cái cảm tham vọng cốt lõi.","nguonNblm":true,"bridge":true,"khoang":"@c0007"},{"chuong":"@c0031","importance":"normal","text":"Lật bài không chế Hàn Lập: vạch trần hắn có ý trì hoãn luyện Trường Xuân Công tăng tư, ép nuốt Thi Trùng Hoàn (trùng noãn, một năm không có giải được thì trùng ăn sạch nội tạng), lại lấy tính mạng cha mẹ Hàn Lập uy hiếp — chính thức biến Hàn Lập thành con tin để lão khôi phục/luyện công.","nguonNblm":true},{"text":"Kinh hoàng phát hiện ông Ngự Độc Thúy tịch thu từ Hàn Lập có độc tính quỷ dị ăn thủng cả sàn nhà; sững sờ vì đứa nhỏ tự học chế độc mà lão chưa từng dạy, chửi Hàn Lập 'tâm ngoan thủ lạt' — bộc lộ thế hai bên cùng để chứng.","nguonNblm":true,"bridge":true,"khoang":"@c0032"},{"chuong":"@c0048","importance":"normal","text":"Trở mặt động thủ, đích thân giao đấu sinh tử với Hàn Lập: lộ bản lĩnh cao thủ (thân pháp như u linh, chiêu 'Chỉ xích thiên nhai' tiến sát như sức địa), thái độ đổi như tắc kè hoa (lúc khuyên hàng ôn hòa lúc lạnh khốc), quyết bắt sống Hàn Lập — nhưng bị Hàn Lập dùng trà ngự làm không thể công, sa vào bẫy chiêu kiếm cuối.","nguonNblm":true}],"tuViMoc":[{"chuong":29,"canhGioi":"Cao thủ võ lâm phàm trần — Ma Ngân Thủ","text":"Ra tay điểm huyệt Hàn Lập cực nhanh như u linh, thân pháp vượt xa phàm nhân thường. Sở hữu tuyệt kỹ thành danh Ma Ngân Thủ — hai tay luyện cứng trắng bạc như bạc thật, đao thương bất nhập, bắt được lưỡi kiếm trực tiếp."},{"chuong":59,"canhGioi":"Phàm nhân vô linh căn — Trường Xuân công tầng 4 (tự tu thất bại)","text":"Dư Tử Đồng tiết lộ: Mặc đại phu là phàm nhân KHÔNG có linh căn, không thể tu tiên thực thụ. Tự tu Trường Xuân công chỉ tới tầng 4 bằng pháp lực mượn/bí thuật. Đây là lý do hắn sa vào bẫy của Dư Tử Đồng — pháp lực không hơn Hàn Lập tầng 6-7 nên đoạt xá thất bại."}],"nhanMach":[{"ten":"Hàn Lập","tag":"su-mon","quanHe":"Thân truyền đệ tử trên danh nghĩa; thực chất lợi dụng để phá giải"},{"ten":"Trương Thiết","tag":"su-mon","quanHe":"Đệ tử (tâm pháp riêng)"},{"ten":"Vương môn chủ","tag":"an-nhan","quanHe":"Người mời nhập môn sau khi được Mặc đại phu cứu mạng"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Bí dược chậm lão hóa","loai":"đan dược (tự phối)","trangThai":"đang dùng","moTa":"Loại thuốc Mặc Cư Nhân tự phối chế theo công thức trong kỳ thư, giúp làm chậm tốc độ lão hóa để cầm cự tới nay.","nguon":["c0030"]}],"congPhap":[{"ten":"Trường Xuân công","loai":"công pháp","trangThai":"đã truyền dạy cho Hàn Lập","moTa":"Công pháp Mặc đại phu tìm được từ kỳ thư; truyền cho Hàn Lập với tên 'vô danh khẩu quyết'. Cần người tu có linh căn. Luyện tới tầng tư có thể dùng Trường Xuân khí kích thích bí huyệt.","nguon":["c0006","c0030"]},{"ten":"Trường sinh kinh","loai":"sách tu luyện","trangThai":"đang nghiên cứu","moTa":"Cuốn sách về tu thân dưỡng tính và kéo dài tuổi thọ; Mặc đại phu ôm khư khư.","nguon":["c0007"]},{"ten":"Kỳ thư thần bí","loai":"sách","trangThai":"đang giữ","moTa":"Quyển sách thâm ảo Mặc Cư Nhân vô tình được ở một nơi thần bí; chứa cách khôi phục công lực, cách phá giải tình cảnh của hắn, và công thức bí dược chậm lão hóa.","nguon":["c0030"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":2,"nguon":["c0005","c0006","c0007","c0008","c0009","c0010","c0011","c0013","c0014","c0015","c0020","c0021","c0022","c0023","c0027","c0028","c0029","c0030","c0031","c0032","c0035","c0039","c0040","c0041","c0042","c0044","c0045","c0046","c0047","c0048","c0049","c0050","c0062"]},{"id":"truong-thiet","name":"Trương Thiết","cn":"张铁","aliases":["Trương ca"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"da-roi"}],"canhGioiCaoNhat":"Phàm nhân (võ giả) — Tượng giáp công tầng 3; di thể cải tạo thành thi nhân 'Khúc Hồn'","trangThai":"mat-hon","blurb":"Trương Thiết, được Hàn Lập gọi thân là Trương ca, xuất thân nhà hàng ăn và cùng Hàn Lập được Mặc đại phu chọn làm ký danh đệ tử tại Thần thủ cốc. Nhờ Mặc đại phu đổi ý truyền cho Tượng giáp công, chỉ trong thời gian ngắn hắn luyện tới tầng 1 đỉnh phong rồi tầng 3, sau đó để lại thư cáo từ và biến mất với lý do đi lịch lãm giang hồ. Thực chất hắn đã bị hủy hồn phách và tử vong, di thể về sau bị luyện thành thi nhân 'Khúc Hồn', điều Hàn Lập nhớ lại qua chính thân thể ấy.","vaiTro":"Bạn thân, đồng môn ký danh của Hàn Lập tại Thất Huyền môn","tinhCach":"Chu đáo, tốt bụng (đưa bánh bao cho Hàn Lập); chăm chỉ, bền chí trong tu luyện; cởi mở, sẵn lòng chia sẻ với bạn","tabs":{"diem":[{"text":"Cùng Hàn Lập được Mặc đại phu chọn làm ký danh đệ tử tại Thần thủ cốc","chuong":"@c0005"},{"text":"Được truyền Tượng giáp công, chỉ sau hai tháng đã luyện tầng 1 tới đỉnh phong","chuong":"@c0009"},{"text":"Luyện thành Tượng giáp công tầng 3 rồi đột nhiên biến mất, chỉ để lại thư cáo từ","chuong":"@c0015"},{"text":"Được Hàn Lập nhớ lại qua thân thể thi nhân 'Khúc Hồn'","chuong":"@c0337"}],"kinhLich":[{"chuong":5,"importance":"normal","text":"Cùng Hàn Lập được Mặc đại phu chọn làm ký danh đệ tử tại Thần thủ cốc."},{"chuong":6,"importance":"normal","text":"Đưa bánh bao cho Hàn Lập; được Hàn Lập gọi là Trương ca."},{"chuong":8,"importance":"major","text":"Qua khảo hạch nhờ Mặc đại phu đột ngột đổi ý — đề nghị tâm pháp khác phù hợp với hắn."},{"chuong":9,"importance":"major","text":"Được truyền Tượng giáp công; chỉ sau hai tháng đã luyện tầng 1 tới đỉnh phong, đang ngồi dưới thác nước chuẩn bị đột phá tầng 2."},{"chuong":11,"importance":"normal","text":"Giúp Hàn Lập thử vặn mở bình thần bí nhưng cũng thất bại — bình hoàn toàn không nhúc nhích dù dùng hết sức."},{"chuong":13,"importance":"normal","text":"Kể cho Hàn Lập nghe sự tàn khốc của Tượng giáp công tầng 1: Mặc đại phu bôi thuốc hôi và dùng gậy gỗ đánh rèn gân cốt, đêm không ngủ yên."},{"chuong":15,"importance":"major","text":"Hai năm trước luyện thành Tượng giáp công tầng 3 rồi đột nhiên biến mất, chỉ để lại thư cáo từ nói muốn đi lịch lãm giang hồ — Thất Huyền môn chấn động."}],"tuViMoc":[{"chuong":9,"canhGioi":"Tượng giáp công — tầng 1 đỉnh phong","text":"Da thịt dày chắc hơn, lực khí bền bỉ hơn; đang ngồi dưới thác để chuẩn bị đột phá tầng 2.","importance":"major"},{"chuong":15,"canhGioi":"Tượng giáp công — tầng 3","text":"Luyện thành tầng 3 rồi rời môn bí ẩn — thông tin qua hồi cố, không có chi tiết quá trình đột phá.","importance":"major"}],"nhanMach":[{"ten":"Hàn Lập","tag":"ban-be","quanHe":"Bạn thân đồng môn"},{"ten":"Mặc đại phu","tag":"su-mon","quanHe":"Sư phụ truyền Tượng giáp công"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Tượng giáp công","loai":"công pháp luyện thể","trangThai":"đã luyện (tầng 3)","moTa":"Do Mặc đại phu truyền; môn võ công ngoại gia chín tầng cực hiếm. Luyện thành tầng 3 thì rời môn.","nguon":["c0009","c0013","c0015"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0005","c0006","c0007","c0008","c0009","c0010","c0011","c0013","c0015","c0063","c0064"]},{"id":"khuc-hon","name":"Khúc Hồn","cn":"曲魂","importance":"normal","aliases":["Khúc Hồn","Thiết nô","cự hán","yêu thi","Người lục bào","Thần bí nhân"],"blurb":"Khúc Hồn là thi nhân được Mặc đại phu và Dư Tử Đồng luyện từ di thể Trương Thiết, sau đó bị Hàn Lập dùng Dẫn hồn chung khống chế và đặt tên. Từ Thất Huyền môn tới Gia Nguyên Thành, hắn nhiều lần làm hộ vệ, trợ thủ chiến đấu cho Hàn Lập và Tôn Nhị Cẩu; về sau thân thể xuất hiện linh khí, từng bị tu sĩ Ngự Linh tông mất thân thể đoạt dụng rồi lại được Hàn Lập mang theo.","nguon":["63","64","c0028","c0029","c0034","c0044","c0051","c0052","c0053","c0054","c0055"],"tabs":{"kinhLich":[{"chuong":63,"importance":"major","tieuDe":"Nhận ra qua di thể — hồn phách đã mất","text":"Hàn Lập khống chế cự hán thiết nô bằng Dẫn hồn chung, rúng động nhận ra khuôn mặt cự hán chính là Trương Thiết — bạn thân năm xưa. Di thể đã bị Mặc đại phu cải tạo thành thi nhân, hồn phách hoàn toàn không còn."},{"chuong":64,"importance":"normal","tieuDe":"Được đặt tên Khúc Hồn","text":"Hàn Lập đặt tên 'Khúc Hồn' cho di thể. Sự thật: Mặc đại phu và Dư Tử Đồng đã bắt cóc, hủy hồn phách, dùng Tượng Giáp công kết hợp luyện thi thuật (do Dư Tử Đồng cung cấp) tạo thành thi nhân. Khúc Hồn nhận lệnh san phẳng nhà đá."},{"chuong":"@c0078","importance":"normal","text":"Lần đầu xuất trận làm trợ thủ chiến đấu cho Hàn Lập: được triệu ra từ căn phòng (thân hình cự hán đụng nát cửa gỗ), theo Hàn Lập và Lệ Phi Vũ rời Thần Thủ Cốc. Khi hơn mười người Dã Lang Bang do Tôn chấp pháp dẫn vào rừng, Hàn Lập lạnh lùng ra lệnh giết hết trừ Lam y chấp pháp; Khúc Hồn hóa thành cuồng phong xông vào rừng, chỉ trong nháy mắt giết sạch khiến Lệ Phi Vũ kinh hãi.","nguonNblm":true},{"text":"Cùng Hàn Lập và Lệ Phi Vũ chạy tới Lý trạch tiếp viện thì bị mười tên Đoạn Thủy môn chặn vây. Khi đám áo xanh tan vỡ bỏ chạy định phát tín hiệu cầu viện, Khúc Hồn hóa thành bóng đen quỷ mị thoắt ẩn thoắt hiện, dùng đoạn kiếm bén đâm xuyên yết hầu từ phía sau từng tên trốn xa nhất, không tha một ai — thân pháp ám sát vô hình đáng sợ.","nguonNblm":true,"bridge":true,"khoang":"@c0080"},{"text":"Khi Hàn Lập và Lệ Phi Vũ cải trang trà trộn lên Lạc Nhật Phong nghe Vương Tuyệt Sở nói chuyện, Khúc Hồn vì thân hình cao lớn dị thường quá lộ liễu nên không lên núi, tìm chỗ bí mật ẩn náu dưới chân núi chờ Hàn Lập.","nguonNblm":true,"bridge":true,"khoang":"@c0084"},{"chuong":"@c0095","importance":"normal","text":"Sau khi đại chiến Thất Huyền môn – Dã Lang bang kết thúc, năm ngày sau Hàn Lập lặng lẽ theo dòng người xuống Lạc Nhật Phong tìm được Khúc Hồn rồi cùng nhau trở về trong cốc (Khúc Hồn vẫn ẩn dưới chân núi từ trận đánh).","nguonNblm":true},{"text":"Theo Hàn Lập rời Thất Huyền môn, ngồi xe ngựa về hướng Đông (quê Hàn Lập). Thân hình cao lớn dị thường, mặc áo giáp che khuất mặt mày trông thần bí; trên vai vác một bao to chứa quần áo cùng nhiều vàng bạc vật phẩm. Khi Hàn Lập vào thôn cũ thì bị giữ lại trên xe (tránh gây chú ý).","nguonNblm":true,"bridge":true,"khoang":"@c0098"},{"text":"Theo Hàn Lập đặt chân tới Gia Nguyên Thành (Lam Châu) sau ba tháng đi thuyền — cố hương của Mặc đại phu. Mô tả: cự hán cao hơn người thường hai cái đầu, đầu đội nón che mặt, mặc lục bào, trang phục quỷ dị, luôn theo sát sau lưng Hàn Lập nửa bước không rời, ra dáng hạ nhân.","nguonNblm":true,"bridge":true,"khoang":"@c0100"},{"text":"Tại bến đò Gia Nguyên Thành, đóng vai bảo tiêu/hạ nhân mang bao đồ to nặng (chứa mấy ngàn lượng bạc) cho Hàn Lập; theo lệnh Hàn Lập đưa bao đồ cho khổ lực, không tranh đoạt. Khối tài phú này khiến hai đầu mục bến đò Tôn nhị cẩu và Hắc Hùng nổi lòng tham, lập mưu cướp.","nguonNblm":true,"bridge":true,"khoang":"@c0101"},{"text":"Khi băng cướp Hắc Hùng – Tôn nhị cẩu phục kích trong hẻm để mưu tài hại mệnh, Hàn Lập ra lệnh 'giết, không lưu tay'. Khúc Hồn xông vào: một quyền đánh nát đầu một đại hán văng vào tường, gạt bay binh khí, quét chân đá hai tên bay xa hơn một trượng; tiếp tục đánh nát đầu thêm mấy tên. Thực lực áp đảo, được mô tả còn chưa xuất toàn lực.","nguonNblm":true,"bridge":true,"khoang":"@c0102"},{"text":"Một mình hạ gục hơn hai mươi đại hán thủ hạ của Tôn nhị cẩu nằm la liệt, khiến Tôn nhị cẩu khiếp sợ quỳ xin hàng. Sau khi Hàn Lập thu phục Tôn nhị cẩu (ép uống Hủ tâm hoàn), Khúc Hồn cõng hành lý theo Hàn Lập rời đi.","nguonNblm":true,"bridge":true,"khoang":"@c0103"},{"chuong":"@c0120","importance":"normal","text":"Hàn Lập định kế đoạt Tứ Bình Bang, giao Khúc Hồn cho Tôn nhị cẩu sai khiến để diệt phe phản đối và bảo vệ hắn lên ngôi bang chủ. Hàn Lập lấy ra Dẫn Hồn Chung trao cho Tôn nhị cẩu — pháp khí điều khiển Khúc Hồn (phương pháp khác do Mặc đại phu dạy): ai cầm chuông đều sai khiến được Khúc Hồn, nhưng chừng nào chủ nhân cũ (Hàn Lập) đã nhỏ máu lên chuông còn sống thì người khác không thể chiếm quyền điều khiển — khóa an toàn chống phản loạn.","nguonNblm":true},{"text":"Khi Hàn Lập chuẩn bị rời Gia Nguyên Thành đi tìm Thái Nam cốc và ám sát ở Độc Phách sơn trang, hắn quyết định gửi Khúc Hồn lại lâu dài ở chỗ Tôn nhị cẩu — không phải vì hết cần bảo vệ mà vì bộ dáng Khúc Hồn quá thu hút chú ý, không tiện đi xa; Hàn Lập dặn cấm dùng Khúc Hồn gây thị phi kẻo chuốc hoạ sát thân, và thầm có chút không nỡ rời bỏ.","nguonNblm":true,"bridge":true,"khoang":"@c0125"},{"chuong":28,"importance":"normal","text":"Xuất hiện lần đầu (dưới tên 'người lục bào'): theo sau Mặc đại phu khi lão trở về Thần Thủ Cốc; đứng bất động phía sau ghế của Mặc đại phu, không nói gì."},{"chuong":34,"importance":"normal","text":"Hàn Lập quan sát từ xa thấy người này đứng bất động ngoài cửa phòng Mặc đại phu giữa trời nắng; Hàn Lập thử bắt chuyện nhưng hắn như khúc gỗ. Bóng lưng khiến Hàn Lập có cảm giác quen thuộc tựa hồ đã gặp ở đâu."},{"chuong":44,"importance":"minor","text":"Vẫn đứng vô thanh vô tức trong góc phòng Mặc đại phu như người chết khi Hàn Lập tới gặp lại; Hàn Lập phải cố ý để ý mới nhận ra sự tồn tại."},{"chuong":51,"importance":"normal","tieuDe":"Lộ tên — bắt Hàn Lập theo lệnh","text":"Được Mặc đại phu gọi tên 'Thiết Nô' lần đầu. Nhận lệnh bắt Hàn Lập; đánh văng thiết trùy của hắn rồi khống chế hoàn toàn — thân thể cứng như đá, thiết trùy bật ra không gây thương tích. Đánh gãy vai và đầu gối Hàn Lập nhưng cố ý 'điểm nhẹ' theo lệnh chủ."},{"chuong":52,"importance":"minor","text":"Tiếp tục khống chế Hàn Lập trong lúc Mặc đại phu thi triển Thất Quỷ Phệ Hồn đại pháp; không cho Hàn Lập thoát."},{"chuong":53,"importance":"minor","text":"Vẫn canh giữ Hàn Lập sau khi Mặc đại phu hồi phục tuổi trẻ thành mỹ nam tử."},{"chuong":54,"importance":"minor","text":"Canh giữ Hàn Lập khi Mặc đại phu dán Định Thần Phù."},{"chuong":55,"importance":"minor","text":"Mang Hàn Lập vào căn nhà đá kín. Bị Mặc đại phu cho ra ngoài canh cửa với lệnh 'giết không tha' bất kỳ ai cố đột nhập."},{"chuong":"@c0061","importance":"normal","tieuDe":"Trơ trơ gác cửa sau khi Mặc đại phu chết","text":"Sau khi Hàn Lập diệt xong nguyên thần Dư Tử Đồng và Mặc đại phu đã chết, cụ hán thiết nô vẫn đứng gác ngoài cửa đá, ngây ngốc chỉ chấp hành mệnh lệnh cũ — cửa mở hay trong thạch phòng có biến cũng không liếc mắt, không phản ứng. Hàn Lập nhận ra mình quên hỏi Dư Tử Đồng về lai lịch/nhược điểm của hắn, đành quay sang lục thi thể Mặc đại phu để tìm cách khác chế.","nguonNblm":true},{"chuong":"@c0062","importance":"normal","tieuDe":"Chân tướng: là thi thể không hồn (thi nhân) Mặc đại phu để lại","text":"Di thư Mặc đại phu (giấu trong túi hương hoa Bạch Quyên trên thi thể) tiết lộ chân tướng 'thần bí nhân': cụ hán thiết nô thực chất là một THI THỂ KHÔNG HỒN PHÁCH (thi nhân) — hồn đã chuyển thể đầu thai từ lâu, chỉ còn cử động theo lệnh. Di thư trao cho Hàn Lập phương pháp không chế thiết nô (cùng Vạn tự điều), biến hắn thành trợ thủ/công cụ của Hàn Lập theo giao dịch. Đây là mốc GIẢI BÍ của giai đoạn thần bí nhân.","nguonNblm":true}],"diem":[{"text":"Sau khi Mặc đại phu chết vẫn trơ trơ gác cửa, cho thấy chỉ hành động theo mệnh lệnh đã nhận.","chuong":"@c0061"},{"text":"Di thư Mặc đại phu tiết lộ hắn là thi thể không hồn, tức thi nhân được để lại.","chuong":"@c0062"},{"text":"Lần đầu được Hàn Lập triệu ra làm trợ thủ chiến đấu, thân hình cự hán đụng nát cửa khi xuất trận.","chuong":"@c0078"},{"text":"Một mình hạ gục hơn hai mươi thủ hạ của Tôn Nhị Cẩu trong hẻm Gia Nguyên Thành.","chuong":"@c0103"},{"text":"Được Hàn Lập giao cho Tôn Nhị Cẩu sai khiến nhằm diệt phe phản đối và bảo vệ hắn trong kế đoạt Tứ Bình Bang.","chuong":"@c0120"},{"text":"Thân thể lộ linh khí tương đương Luyện Khí kỳ tầng năm hoặc tầng sáu, rồi bị phát hiện có kẻ khác chiếm dụng.","chuong":"@c0337"}],"nhanMach":[{"ten":"Mặc đại phu","tag":"chu","quanHe":"Chủ nhân tuyệt đối sai khiến; Thiết Nô không bao giờ hành động ngược lệnh"}]},"detail":"Sau khi được đặt tên (c64), Khúc Hồn trở thành trợ thủ chiến đấu mạnh đầu tiên của Hàn Lập trong giai đoạn giang hồ phàm nhân: hộ vệ tuyệt đối phục tùng, im lặng không nói, thân hình cự hán cao hơn người thường hai cái đầu, thường đội nón/áo giáp che mặt và mặc lục bào để giấu thân phận. Sức chiến đấu áp đảo võ giả phàm tục (một quyền nát đầu người, hóa cuồng phong/bóng đen ám sát hàng loạt), nhiều lần được mô tả 'chưa xuất toàn lực'. Theo Hàn Lập suốt chặng rời Thất Huyền môn → về quê → tới Gia Nguyên Thành (Lam Châu, cố hương Mặc đại phu). Tới c120 được Hàn Lập tạm giao cho Tôn nhị cẩu điều khiển qua Dẫn Hồn Chung để đoạt Tứ Bình Bang, rồi c125 được gửi lại lâu dài ở chỗ Tôn nhị cẩu khi Hàn Lập rời thành — kết thúc giai đoạn đồng hành ≤c180.","vaiTro":"Yêu thi trợ chiến đầu tiên của Hàn Lập","tinhCach":"Không còn hồn phách, thần trí; tuyệt đối nghe lệnh người khống chế; thân thể cứng rắn, lực chiến áp đảo"},{"id":"tam-thuc","name":"Tam thúc (Lão Hàn béo)","cn":null,"aliases":["Lão Hàn béo","Hàn béo mập"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn — ngoại môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (ngoại đệ tử, không tu luyện)","trangThai":"song","blurb":"Chú ruột của Hàn Lập, đại chưởng quỹ Xuân Hương tửu lâu tại Thanh Ngưu trấn và là đệ tử ngoại môn Thất Huyền môn. Ông chính là người mở ra con đường tu tiên cho Hàn Lập khi về thăm nhà đề nghị tiến cử cháu dự khảo thí, rồi đích thân đưa cháu tới trấn và lo lót để cháu được chiếu cố.","vaiTro":"Chú ruột Hàn Lập, người tiến cử nhập Thất Huyền môn","tinhCach":"Biết lo xa, chủ động mở đường tu tiên cho cháu; khéo léo, thạo ứng xử qua việc đút lót nhờ chiếu cố","tabs":{"diem":[{"text":"Về thăm nhà, chủ động đề nghị tiến cử Hàn Lập dự khảo thí Thất Huyền môn và được cha Hàn Lập đồng ý","chuong":"@c0001"},{"text":"Dẫn Hàn Lập tới Xuân Hương tửu lâu ở Thanh Ngưu trấn, đút lót Vương hộ pháp để nhờ chiếu cố cháu","chuong":"@c0002"},{"text":"Đại chưởng quỹ Xuân Hương tửu lâu tại Thanh Ngưu trấn, đồng thời là đệ tử ngoại môn Thất Huyền môn","chuong":"@c0002"}],"kinhLich":[{"chuong":1,"importance":"major","text":"Về thăm nhà, đề nghị tiến cử Hàn Lập dự khảo thí Thất Huyền môn; cha Hàn Lập đồng ý."},{"chuong":2,"importance":"major","text":"Dẫn Hàn Lập tới Xuân Hương tửu lâu ở Thanh Ngưu trấn; đút lót Vương hộ pháp để nhờ chiếu cố cháu."}],"tuViMoc":[],"nhanMach":[{"ten":"Hàn Lập","tag":"ho-hang","quanHe":"Cháu ruột"},{"ten":"Hàn phụ","tag":"ho-hang","quanHe":"Anh ruột"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0001","c0002"]},{"id":"vuong-ho-phap","name":"Vương hộ pháp","cn":null,"aliases":["Vương lão đệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (võ công không yếu)","trangThai":"song","blurb":"Vương hộ pháp, biệt danh Vương lão đệ, là hộ pháp Thất Huyền môn được giao dẫn đợt đệ tử mới thứ mười bảy về tông môn. Hán tử cao gầy khoảng bốn mươi tuổi, võ công không yếu. Trên đường đón đệ tử hắn nhận túi nặng của Lão Hàn béo và đồng ý chiếu cố Hàn; về sau cùng Hàn Lập tạo thế giáp công trong hỗn chiến, được Hàn Lập cứu khỏi độc thủ của Băng Yêu, rồi cuối cùng bị giáo chủ giết.","vaiTro":"Hộ pháp Thất Huyền môn — người dẫn đợt đệ tử thứ mười bảy","tinhCach":"Ngạo mạn khi đi đường nhưng cung kính trước cấp trên; dễ nhận lễ vật và hứa chiếu cố người gửi; biết phối hợp giáp công trong chiến đấu; dễ hoảng sợ khi lâm nguy","tabs":{"diem":[{"text":"Tự thân tới Xuân Hương tửu lâu đón nhóm đệ tử thứ mười bảy, nhận túi nặng của Lão Hàn béo và đồng ý chiếu cố Hàn","chuong":"@c0002"},{"text":"Cùng Hàn Lập tạo thế giáp công Thanh Văn trong hỗn chiến, mừng khi thấy Hàn Lập xuất thủ mạnh","chuong":"@c0318"},{"text":"Kịp dùng ba đạo lục mang cắt ngang Tỏa Kim hoàn, giúp Hàn Lập hoàn tất pháp thuật","chuong":"@c0319"},{"text":"Bị Băng Yêu chọn làm mục tiêu đánh lén sau khi chứng kiến Tuyết Hồng chết thảm, được Hàn Lập cứu khỏi độc thủ","chuong":"@c0322"},{"text":"Bị giáo chủ giết","chuong":"@c0324"}],"kinhLich":[{"chuong":2,"importance":"major","text":"Tự thân tới Xuân Hương tửu lâu đón nhóm đệ tử thứ mười bảy; nhận túi nặng của Lão Hàn béo, đồng ý chiếu cố Hàn Lập."},{"chuong":3,"importance":"normal","text":"Dẫn nhóm tới Thái Hà sơn, bị Nhạc đường chủ trách đến trễ hai ngày."}],"tuViMoc":[],"nhanMach":[{"ten":"Nhạc đường chủ","tag":"su-mon","quanHe":"Cấp trên trong Thất Huyền môn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0002","c0003","c0005"]},{"id":"nhac-duong-chu","name":"Nhạc đường chủ","cn":"乐堂主","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn — Bách Đoán đường","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đường chủ Bách Đoán đường của Thất Huyền môn, mặt mũi hồng hào và uy nghiêm. Người tiếp đón đệ tử mới nhập môn, điều phối và công bố kết quả trắc thí tuyển đệ tử.","vaiTro":"Đường chủ Bách Đoán đường của Thất Huyền môn","tinhCach":"Uy nghiêm; nghiêm khắc với thuộc hạ; giữ trật tự quy củ","tabs":{"diem":[{"text":"Tiếp đón nhóm đệ tử mới thứ mười bảy, trách Vương hộ pháp đến trễ và lệnh đưa đám trẻ nghỉ đêm","chuong":"@c0003"},{"text":"Công bố kết quả trắc thí: sáu người vào Bách Đoán đường, Vũ Nham vào Thất Tuyệt đường","chuong":"@c0005"}],"kinhLich":[{"chuong":3,"importance":"normal","text":"Tiếp đón nhóm thứ mười bảy, trách Vương hộ pháp đến trễ, lệnh đưa đám trẻ nghỉ đêm."},{"chuong":5,"importance":"major","text":"Công bố kết quả trắc thí: sáu người vào Bách Đoán đường, Vũ Nham vào Thất Tuyệt đường, Trương Thiết và Hàn Lập thành ký danh đệ tử."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0003","c0004","c0005"]},{"id":"vu-nham","name":"Vũ Nham","cn":"武岩","aliases":["Vũ thiếu gia"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn — Thất Tuyệt đường","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân — hạch tâm đệ tử Thất Tuyệt đường","trangThai":"song","blurb":"Vũ Nham, còn gọi Vũ thiếu gia, là con nhà võ quán mới mười ba tuổi, có biểu tỷ là Huyền phu nhân — vợ Mã phó môn chủ. Nhờ thế lực gia đình, cậu được vượt tuổi quy định dự trắc thí, leo lên đỉnh sơn nhai sớm nhất và được nhận vào Thất Tuyệt đường học tuyệt kỹ với thân phận hạch tâm đệ tử. Về sau tái ngộ Hàn Lập tại Thần thủ cốc vẫn giữ thái độ ngạo mạn và bị đối phương ngầm trả đũa.","vaiTro":"Hạch tâm đệ tử Thất Tuyệt đường, có thế lực gia đình chống lưng","tinhCach":"Ngạo mạn, tự cao dựa vào thế lực; hiếu thắng, thích dẫn đầu; nhanh nhẹn, thể chất trội hơn bạn đồng lứa","tabs":{"diem":[{"text":"Người lớn tuổi nhất trên xe, đóng vai đại ca của đám trẻ","chuong":"@c0003"},{"text":"Dẫn đầu cuộc trắc thí Luyện Cốt Nhai, leo lên đỉnh sớm nhất","chuong":"@c0004"},{"text":"Được lam bào lão giả tiếp nhận vào Thất Tuyệt đường làm hạch tâm đệ tử","chuong":"@c0005"},{"text":"Tái ngộ Hàn Lập tại Thần thủ cốc với thái độ ngạo mạn, bị Hàn Lập cố ý tăng liều thuốc trả đũa","chuong":"@c0066"}],"kinhLich":[{"chuong":3,"importance":"normal","text":"Người lớn nhất xe (13 tuổi), làm đại ca đám trẻ."},{"chuong":4,"importance":"normal","text":"Dẫn đầu cuộc trắc thí Luyện Cốt Nhai, leo lên đỉnh sớm nhất."},{"chuong":5,"importance":"major","text":"Được lam bào lão giả tiếp nhận vào Thất Tuyệt đường làm hạch tâm đệ tử."},{"chuong":66,"importance":"normal","tieuDe":"Tái ngộ — Hàn Lập trả đũa","text":"Tái ngộ Hàn Lập tại Thần thủ cốc với thái độ ngạo mạn như trước. Bị Hàn Lập cố ý tăng liều thuốc trả đũa nhưng vẫn được chữa khỏi bệnh."}],"tuViMoc":[],"nhanMach":[{"ten":"Huyền phu nhân","tag":"ho-hang","quanHe":"Biểu tỷ (chị họ)"},{"ten":"Mã phó môn chủ","tag":"dong-minh","quanHe":"Biểu tỷ phu (chồng chị họ), phó môn chủ Thất Huyền môn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0003","c0004","c0005","c0066"]},{"id":"truong-quan","name":"Trương Quân","cn":"张君","aliases":["Lạnh sư huynh","Sư huynh cao gầy"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Sư huynh bảo hộ Hàn Lập trong trắc thí Luyện Cốt Nhai. Mặt lạnh lùng, thân thể cường kiện. Đã dang tay sẵn sàng đỡ Hàn Lập khi suýt rơi, sau đó ôm Hàn Lập leo lên đỉnh sơn nhai.","vaiTro":"Đệ tử Thất Huyền môn, sư huynh bảo hộ Hàn Lập","tinhCach":[{"text":"Lạnh lùng, ít nói, nhưng âm thầm chăm sóc đệ tử được giao","chuong":4},{"text":"Miệng ghen ghét nhưng biết giữ mồm khi Ngô Minh nhắc nhở","chuong":5}],"tabs":{"diem":[],"kinhLich":[{"chuong":4,"importance":"normal","text":"Đi sát sau bảo hộ Hàn Lập; dang tay sẵn sàng đỡ khi Hàn Lập suýt rơi khỏi vách đá."},{"chuong":5,"importance":"normal","text":"Ôm Hàn Lập leo lên đỉnh sơn nhai; tiết lộ Vũ Nham vào Thất Tuyệt đường nhờ quan hệ."}],"tuViMoc":[],"nhanMach":[{"ten":"Ngô Minh","tag":"dong-minh","quanHe":"Đồng môn sư huynh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0004","c0005"]},{"id":"ngo-minh","name":"Ngô Minh","cn":null,"aliases":["Ngô Minh Thụy","Mặt gầy sư huynh"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Sư huynh trong Thất Huyền môn, đồng hành với Trương Quân. Thận trọng, sợ liên lụy, hay nịnh bợ Mặc đại phu.","vaiTro":"Đệ tử Thất Huyền môn","tinhCach":[{"text":"Thận trọng, sợ bị phạt — can ngăn Trương Quân nói bậy về phó môn chủ","chuong":5}],"tabs":{"diem":[],"kinhLich":[{"chuong":5,"importance":"minor","text":"Cùng Trương Quân dẫn nhóm đệ tử quá quan lên núi; bợ đỡ Mặc đại phu."}],"tuViMoc":[],"nhanMach":[{"ten":"Trương Quân","tag":"dong-minh","quanHe":"Đồng môn sư huynh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0005"]},{"id":"han-phu","name":"Hàn phụ","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Cha của Hàn Lập, một nông dân nghèo sống ở Sơn Biên tiểu thôn. Vốn tính thận trọng, ông ban đầu do dự khi nghe đề nghị đưa con vào môn phái, nhưng cuối cùng đồng ý vì lợi ích tiền bạc cho gia đình. Trước khi con lên đường, ông dặn dò Hàn Lập những lời răn về cách xử thế.","vaiTro":"Cha ruột Hàn Lập — nông dân nghèo ở Sơn Biên tiểu thôn","tinhCach":"Thận trọng, do dự trước quyết định lớn; coi trọng lợi ích thực tế cho gia đình; dạy con giữ đạo làm người","tabs":{"diem":[{"text":"Dặn Hàn Lập sống thành thật, nhẫn nhịn và không tranh chấp trước khi con rời nhà","chuong":"@c0001"}],"kinhLich":[{"chuong":1,"importance":"major","text":"Dặn Hàn Lập thành thật, nhẫn nhịn, không tranh chấp trước khi con lên đường."}],"tuViMoc":[],"nhanMach":[{"ten":"Hàn Lập","tag":"cha-me","quanHe":"Con trai thứ tư"},{"ten":"Tam thúc","tag":"ho-hang","quanHe":"Em ruột"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0001"]},{"id":"vuong-mon-chu","name":"Vương Tuyệt Sở","cn":null,"aliases":["Vương môn chủ"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ — người tu luyện, cao thủ võ học đứng đầu Thất Huyền môn","trangThai":"song","blurb":"Vương Tuyệt Sở, người tu luyện đứng đầu Thất Huyền môn và là truyền nhân của Thất tuyệt thương nhân. Từng bị địch tập kích trọng thương rồi được Mặc đại phu cứu sống và mời nhập môn, lão dẫn dắt Thất Huyền môn qua cuộc chiến sinh tử với Dã Lang bang — bày trận cơ quan Đại Hãm tại Lạc Nhật Phong, đề xuất tử khế đấu và trọng dụng Hàn Lập để lật ngược thế cờ. Sau đại thắng, lão vừa mừng vừa lo trước thân thủ bí ẩn của Hàn Lập.","vaiTro":"Môn chủ Thất Huyền môn — truyền nhân Thất tuyệt thương nhân","tinhCach":"Quyết đoán, dám đập bàn định đoạt giữa nội bộ chia rẽ; mưu lược, dùng bẫy cơ quan và tử khế đấu; thận trọng dò xét địch trước khi ra tay; biết trọng dụng nhân tài lại đề phòng hiểm họa","tabs":{"diem":[{"text":"Bị địch tập kích trọng thương, được Mặc đại phu cứu sống rồi mời lão nhập môn cấp sơn cốc","chuong":"@c0006"},{"text":"Đập bàn quyết định hòa đàm với Dã Lang bang giữa nội bộ chia rẽ","chuong":"@c0075"},{"text":"Biến toàn bộ Lạc Nhật Phong thành đại bẫy cơ quan 'Đại Hãm', kích hoạt cản bước địch","chuong":"@c0084"},{"text":"Đề xuất tử khế đấu 50 đối 50 với Cổ Thiên Long, ký Sinh Tử Khế quyết một phe sống chết","chuong":"@c0085"},{"text":"Sáng suốt cho Hàn Lập tham gia tử đấu, mừng như điên khi Hàn Lập áp đảo địch","chuong":"@c0092"},{"text":"Nhận Lệ Phi Vũ làm đệ tử, phong đường chủ Ngoại Nhận Đường; nhận đan dược từ Hàn Lập","chuong":"@c0098"}],"kinhLich":[{"chuong":6,"importance":"normal","text":"Xuất môn bị địch nhân tập kích trọng thương, được Mặc đại phu cứu; cảm kích mời lão nhập môn và cấp sơn cốc."},{"chuong":43,"importance":"normal","text":"Trước đông đảo đệ tử chính thức thụ phong chức hộ pháp cho Lệ Phi Vũ sau khi Lệ Phi Vũ lập công bắt hai gian tế Dã Lang bang."},{"chuong":75,"importance":"normal","tieuDe":"Quyết định hòa đàm với Dã Lang bang","text":"Khi Dã Lang bang đột nhiên đề nghị hòa đàm, nội bộ Thất Huyền môn chia rẽ ý kiến; Vương môn chủ đập bàn quyết định: cứ đàm phán xem điều kiện — không quá đáng thì làm hòa, quá hà khắc thì tiếp tục chiến đấu."},{"chuong":77,"importance":"normal","tieuDe":"Ở Lạc Nhật phong nhận tin tức về trận phục kích","text":"Hai vị cung phụng thoát nạn tại Lạc Sa pha chạy về Lạc Nhật phong báo cáo đoàn đàm phán bị diệt. Vương môn chủ nhận tin ở tổng đàn."},{"chuong":80,"importance":"normal","tieuDe":"Lệnh bài được tên mập dùng khống chế nội bộ","text":"Kim sắc lệnh bài thiếp thân (tín vật đại diện Vương môn chủ) nằm trong tay tên mập họ hàng — bị dùng để tước quyền chỉ huy ngoại đường đệ tử của Mã Vinh."},{"chuong":82,"importance":"normal","tieuDe":"Tên thật lộ — Vương Tuyệt Sở","text":"Tên thật Vương Tuyệt Sở lần đầu được gọi trực tiếp trong nguyên tác. Vương môn chủ chỉ huy Thất Huyền môn cố thủ tại tổng đàn Lạc Nhật Phong trước đợt tấn công của Dã Lang bang và Chu Nho."},{"chuong":84,"importance":"normal","tieuDe":"Kích hoạt cơ quan Địa Động","text":"Trước sức tấn công áp đảo của Dã Lang bang, kích hoạt cơ quan bẫy Địa Động trong Lạc Nhật Phong để cản bước địch."},{"chuong":85,"importance":"major","tieuDe":"Đề xuất tử khế đấu","text":"Đề ra hai điều kiện tử khế đấu 50 đối 50 với Cổ Thiên Long — giao đấu quyết định một phe được sống, một phe phải rút lui hẳn. Cổ Thiên Long chấp thuận."},{"chuong":87,"importance":"normal","tieuDe":"Kinh ngạc trước thân pháp Hàn Lập","text":"Vốn định từ chối để Hàn Lập ở lại làm thầy thuốc; sau khi Hàn Lập phô thân pháp tốc độ kinh người — biến mất vô thanh vô tức hiện sau lưng mà không hề bị phát giác — Vương môn chủ cùng ba vị sư thúc đều kinh hãi, nghi ngờ lai lịch 'người này rốt cuộc là ai'. Cuối cùng gạch hai tên yếu, viết tên Hàn Lập và Lệ Phi Vũ vào sinh tử thư."},{"chuong":88,"importance":"normal","tieuDe":"Thận trọng dò xét Chu Nho","text":"Không để cả đám xông lên cùng lúc; chỉ phái một hộ pháp ra thăm dò Kim Quang Tráo của Chu Nho trước khi quyết định bước tiếp."},{"chuong":89,"importance":"normal","tieuDe":"Điều sư thúc đối phó kim tráo","text":"Sau khi thấy hộ pháp thất bại, cùng ba sư thúc thương lượng đối sách rồi cử hán tử râu ria — sư thúc cao thủ từng là mãnh tướng — ra phá kim cương bất hoại công của Chu Nho."},{"chuong":90,"importance":"minor","text":"Cùng đám người của mình hô 'Cẩn thận' cảnh báo khi luồng sáng từ hộp đen Chu Nho phóng tới, nhưng không kịp ngăn hán tử bị giết."},{"chuong":92,"importance":"minor","text":"Mừng như điên khi thấy Hàn Lập áp đảo Chu Nho; tự nhủ quyết định cho Hàn Lập tham gia tử đấu là cực sáng suốt; xem sự tồn vong của môn phái nay trông cậy vào Hàn Lập."},{"chuong":95,"importance":"normal","text":"Vừa mừng vừa lo sau đại chiến: mừng vì Cổ Thiên Long bị diệt, lo vì thân thủ bí ẩn của Hàn Lập có thể chèn ép Thất Huyền môn. Để mắt tới Lệ Phi Vũ như đòn bẩy để tiếp cận Hàn Lập."},{"chuong":97,"importance":"normal","text":"Họp kín bàn cách xử trí Hàn Lập; nội bộ chia phe giết-ngay và ôn-hòa. Lời cảnh báo của sư thúc áo xám về 'trưởng bối sau lưng Hàn Lập' khiến cả hội nghị chuyển sang phe ôn hòa. Được Hàn Lập gặp riêng sớm nửa ngày; sau giao dịch bí mật, tuyên bố trước hội trường rằng mọi phiền phức đã biến mất."},{"chuong":98,"importance":"major","tieuDe":"Nhận Lệ Phi Vũ làm đệ tử — nhận đan dược từ Hàn Lập","text":"Chính thức nhận Lệ Phi Vũ làm đệ tử và phong làm đường chủ Ngoại Nhận Đường. Nhận được bình ngọc chứa Dưỡng Tinh Đan và thuốc khác do Hàn Lập để lại trước khi rời đi."},{"chuong":"@c0083","importance":"normal","text":"Khi Cổ Thiên Long tra hỏi việc đầu hàng, Vương Tuyệt Sở tiết lộ cả Lạc Nhật Phong là đại bẫy cơ quan 'Đại Hãm Tịnh', dùng lời uy hiếp 'động quỷ vu tản' để không chế cục diện thay vì đầu hàng thật, rồi lạnh lùng quay vào điện ra lệnh 'Khởi động cơ quan thứ hai'.","nguonNblm":true},{"chuong":"@c0086","importance":"normal","text":"Chính thức trao đổi và giữ một bản Sinh Tử Khế với Cổ Thiên Long, vào thạch điện tuyên bố bốn trăm tinh duệ tu sĩ, dẫn theo ba vị sư thúc (cao thủ mạnh nhất, 'trẻ ngoài già trong') làm quân bài chủ lực ra trường tử đấu.","nguonNblm":true},{"chuong":"@c0091","importance":"normal","text":"Khi hai sư thúc còn lại lao ra bảo thù cho sư thúc đã chết, Vương Tuyệt Sở định gọi họ về nhưng nuốt lời, quyết để mặc các sư thúc liều mạng quyết sống chết với phi kiếm/yêu pháp của Chu Nho.","nguonNblm":true},{"chuong":"@c0094","importance":"normal","text":"Cùng người Thất Huyền môn lạnh lùng nhìn Cổ Thiên Long 'như xem người chết' khi Hàn Lập tàn diệt toàn bộ Dã Lang bang trong tử đấu trường, kết thúc trận Lạc Nhật Phong nghiêng hẳn về Thất Huyền môn.","nguonNblm":true},{"chuong":"@c0096","importance":"normal","text":"Lo ngại Hàn Lập (tin đồn thành yêu ma), cử Lệ Phi Vũ làm sứ giả tới dò xét và hứa chức Phó Đường chủ để mua chuộc; nhưng sáng hôm sau Hàn Lập lên thẳng vào phòng ngủ của Vương Tuyệt Sở trên Lạc Nhật Phong, dùng Thiên Nhãn thuật xâm nhiếp khiến Vương môn chủ hoảng sợ, ra oai phủ đầu.","nguonNblm":true}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc đại phu","tag":"an-nhan","quanHe":"Người cứu mạng, được mời vào môn làm Cung phụng"},{"ten":"Lệ Phi Vũ","tag":"su-mon","quanHe":"Đệ tử được phong hộ pháp rồi đường chủ Ngoại Nhận Đường"},{"ten":"Hàn Lập","tag":"su-mon","quanHe":"Thầy thuốc trong môn, đã ký tử khế đấu; lai lịch bí ẩn; đã rời môn sau giao dịch bí mật"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0006","c0043","c0075","c0077","c0080","c0082","c0084","c0085","c0086","c0087","c0088","c0089","c0090","c0092","c0095","c0097","c0098"]},{"id":"ma-pho-mon-chu","name":"Mã phó môn chủ","cn":null,"aliases":["Mã phó bang chủ"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ — luyện Huyền âm chỉ đến tinh thuần","trangThai":"song","blurb":"Phó môn chủ Thất Huyền môn, luyện Huyền âm chỉ đến mức tinh thuần. Từng ra tay đưa biểu muội Vũ Nham vào Thất Tuyệt đường và tích cực thu xếp cho Hàn Lập tiếp quản Thần thủ cốc, nhưng đằng sau vẻ thân thiện là các thủ đoạn ngầm nhằm chia rẽ Hàn Lập với những hệ phái khác trong môn.","vaiTro":"Phó môn chủ Thất Huyền môn","tinhCach":"Bề ngoài thân thiện, giỏi mưu kế ngầm (tiếu lý tàng đao); chủ động lôi kéo và cài đặt quan hệ có lợi cho mình; sẵn sàng dùng quỷ kế chia rẽ để đạt mục đích","tabs":{"diem":[{"text":"Ra tay tương trợ đưa Vũ Nham vào Thất Tuyệt đường dù tuổi vượt yêu cầu","chuong":"@c0005"},{"text":"Chấp thuận để Hàn Lập tiếp quản chức trị bệnh tại Thần thủ cốc và cấp bổng lộc cung phụng","chuong":"@c0065"},{"text":"Đồng ý quy định chuông cốc do Hàn Lập đặt ra tại cửa Thần thủ cốc","chuong":"@c0066"},{"text":"Dùng quỷ kế tâng bốc y thuật Hàn Lập để khích Triệu trưởng lão sinh nghi, nhằm chia rẽ","chuong":"@c0070"},{"text":"Có mặt hỗ trợ khi Hàn Lập dùng Thanh Linh Tán và châm cứu chữa trị Lý trưởng lão","chuong":"@c0071"},{"text":"Cùng Tiễn trưởng lão dùng nội lực bức huyết độc qua huyệt đạo, nguyên khí hao tổn không ít","chuong":"@c0072"}],"kinhLich":[{"chuong":5,"importance":"normal","text":"Ra tay tương trợ đưa Vũ Nham vào Thất Tuyệt đường dù tuổi vượt yêu cầu."},{"chuong":65,"importance":"normal","tieuDe":"Chấp thuận tiếp quản Thần thủ cốc","text":"Chấp thuận để Hàn Lập tiếp quản chức trị bệnh tại Thần thủ cốc; cấp bổng lộc cung phụng. Bắt đầu tiếp xúc trực tiếp với Hàn Lập."},{"chuong":66,"importance":"normal","tieuDe":"Đồng ý quy định chuông cốc","text":"Đồng ý để Hàn Lập đặt chuông lớn tại cửa Thần thủ cốc — ai muốn gặp phải gõ chuông trước. Cũng đề nghị xếp thị nữ phục vụ sinh hoạt cho Hàn Lập; Hàn Lập từ chối."},{"chuong":70,"importance":"normal","tieuDe":"Khích Triệu trưởng lão — lộ quỷ kế chia rẽ","text":"Dùng quỷ kế tâng bốc y thuật Hàn Lập để khích Triệu trưởng lão buột miệng nghi ngờ, nhằm làm Hàn Lập có ấn tượng xấu với Triệu trưởng lão và ngăn Hàn Lập ngả về hệ phái khác. Hàn Lập nhìn thấu nhưng không lộ. Lộ ra Mã phó môn chủ luyện Huyền âm chỉ đã tới mức tinh thuần."},{"chuong":71,"importance":"normal","tieuDe":"Hỗ trợ chữa trị Lý trưởng lão","text":"Có mặt và hỗ trợ khi Hàn Lập dùng Thanh Linh Tán và châm cứu chữa trị."},{"chuong":72,"importance":"normal","tieuDe":"Dùng nội lực bức độc — nguyên khí hao tổn","text":"Cùng Tiễn trưởng lão dùng nội lực bức huyết độc qua huyệt đạo ra ngoài; nguyên khí hao tổn không ít."}],"tuViMoc":[],"nhanMach":[{"ten":"Vũ Nham","tag":"ho-hang","quanHe":"Em họ bên vợ (Huyền phu nhân là biểu tỷ của Vũ Nham)"},{"ten":"Huyền phu nhân","tag":"the-thiep","quanHe":"Vợ"},{"ten":"Triệu trưởng lão","tag":"doi-dich","quanHe":"Đối thủ hệ phái nội môn Thất Huyền môn"},{"ten":"Hàn Lập","tag":"loi-dung","quanHe":"Đang ra sức lôi kéo vào hệ phái, chưa thành công"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Huyền âm chỉ","loai":"chỉ pháp","trangThai":"đã luyện tới tinh thuần","moTa":"Công pháp/chỉ pháp đặc trưng của Mã phó môn chủ. Đã luyện tới mức tinh thuần; tên công pháp được đề cập trong lúc đấu khẩu với Triệu trưởng lão.","nguon":["c0070"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0005","c0065","c0066","c0069","c0070","c0071","c0072"]},{"id":"lao-truong","name":"Lão Trương","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Người lớn tuổi duy nhất biết chữ trong Sơn Biên tiểu thôn. Từng làm thư đồng vài năm cho nhà giàu trong thành. Người đặt tên cho hầu hết trẻ con trong thôn, kể cả Hàn Lập.","vaiTro":"Người biết chữ duy nhất trong thôn Hàn Lập","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":1,"importance":"minor","text":"Đặt tên cho hầu hết trẻ con trong thôn; hay kể chuyện thế giới bên ngoài cho Hàn Lập nghe."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0001"]},{"id":"vu-nham-bieu-ty","name":"Huyền phu nhân","cn":null,"aliases":["Biểu tỷ Vũ Nham"],"gioiTinh":"nu","theLuc":[{"ten":"Thất Huyền môn","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Chị họ của Vũ Nham, vợ Mã phó môn chủ Thất Huyền môn. Sự kiện bà gả vào vị trí đó là lý do Vũ Nham được ưu tiên vào Thất Tuyệt đường.","vaiTro":"Vợ Mã phó môn chủ, chị họ Vũ Nham","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":5,"importance":"minor","text":"Được nhắc tới là lý do Vũ Nham vào được Thất Tuyệt đường vượt tuổi quy định."}],"tuViMoc":[],"nhanMach":[{"ten":"Vũ Nham","tag":"ho-hang","quanHe":"Em họ"},{"ten":"Mã phó môn chủ","tag":"the-thiep","quanHe":"Chồng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0005"]},{"id":"le-su-huynh","name":"Lệ Phi Vũ","cn":null,"aliases":["Lệ sư huynh","Lệ hổ"],"tenThat":"Lệ Phi Vũ","gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"},{"ten":"Ngoại Nhận Đường","trangThai":"duong-chu"}],"canhGioiCaoNhat":"Phàm nhân (võ giả) — đường chủ Ngoại Nhận Đường, Thất Huyền môn","trangThai":"song","blurb":"Lệ Phi Vũ, biệt danh “Lệ hổ”, là võ giả Thất Huyền môn từ ký danh đệ tử tự lực vươn lên nhờ Phong Lôi đao pháp và bí mật dùng Trừu Tủy Hoàn. Sau khi được Hàn Lập cứu mạng, y kết thành bằng hữu, nhiều lần lập công trong cuộc chiến với Dã Lang bang, thăng tới đường chủ Ngoại Nhận Đường và được Vương Tuyệt Sở nhận làm đệ tử. Dù biết thọ mệnh chỉ còn mấy năm, y vẫn từ chối phế võ và quyết bảo vệ Trương Tụ Nhi.","vaiTro":"Đường chủ Ngoại Nhận Đường; bằng hữu Hàn Lập","tinhCach":"khổ luyện tự lực, cầu tiến bất chấp tổn thọ; trọng ơn nghĩa với Hàn Lập; chung tình, liều mạng vì Trương Tụ Nhi; cơ cảnh nhưng đôi khi nóng vội","tabs":{"diem":[{"text":"Ký danh đệ tử tự lực vươn lên top hạng Thất Huyền môn, nổi danh “Lệ hổ” và sắp vào Thất Tuyệt đường","chuong":"@c0018"},{"text":"Được Hàn Lập cứu khỏi cơn phát tác gần chết do dùng Trừu Tủy Hoàn, từ đó mang ơn sâu với Hàn Lập","chuong":"@c0020"},{"text":"Nhờ cơ cảnh phá tan âm mưu trộm danh sách đệ tử của gian tế Dã Lang bang và được thăng hộ pháp Thất Huyền môn","chuong":"@c0043"},{"text":"Biết mình chỉ còn sống được mấy năm nhưng kiên quyết không phế võ, tuyên bố giữ Trương Tụ Nhi","chuong":"@c0073"},{"text":"Giết tử y chưởng kỳ sứ Dã Lang bang trong chiến tranh, được thăng phó đường chủ Ngoại Nhận Đường","chuong":"@c0074"},{"text":"Được Vương Tuyệt Sở nhận làm đệ tử và phong làm đường chủ Ngoại Nhận Đường","chuong":"@c0098"}],"kinhLich":[{"chuong":17,"importance":"normal","text":"Xuất hiện lần đầu trong trường đấu — được cả hai phe đồng loạt hô tên cổ vũ khi bước vào trận cuối. Cầm đao nhắm mắt, thần sắc lãnh khốc."},{"chuong":18,"importance":"normal","text":"Tiểu sử được kể lại: ký danh đệ tử tự lực vươn lên top hạng, danh hiệu \"Lệ hổ\", sắp vào Thất Tuyệt đường. Dùng Phong Lôi đao pháp hóa hơn mười đao ảnh, hét vang như sấm, áp đảo Triệu Tử Linh."},{"chuong":19,"importance":"minor","text":"Thắng Triệu Tử Linh — liên hoàn đao chấn bay nhuyễn kiếm, Triệu Tử Linh cam bái hạ phong. Đột nhiên biến sắc, viện cớ việc gấp, dùng khinh công cao minh vội rời trường."},{"chuong":20,"importance":"major","text":"Bệnh cấp tính phát tác bên suối, gần chết. Được Hàn Lập cứu bằng ngân châm. Bí mật bị vạch trần: dùng Trừu Tủy Hoàn cả viên nhiều năm, chỉ còn sống thêm 5-6 năm. Phải tự chọn: nhờ Mặc đại phu phối bí dược (sống thêm 20-30 năm, mất võ công) hay tiếp tục dùng hoàn."},{"chuong":21,"importance":"major","text":"Tỉnh lại sau khi được cứu, lập tức rút trường đao kề cổ Hàn Lập đòi lý do không diệt khẩu; lộ vẻ xấu hổ và thu đao sau khi Hàn Lập lập luận và phát độc thề. Tự xưng tên thật Lệ Phi Vũ, hứa trả ơn. Là đệ tử hộ pháp bình thường nhưng được lòng đường chủ/trưởng lão/môn chủ, nên cuộc sống không yên."},{"chuong":22,"importance":"normal","text":"Hẹn trưa hôm sau quay lại lấy thuốc rồi đi điều dưỡng. Mang ơn sâu với Hàn Lập vì hắn không truy hỏi nguyên nhân dùng Trừu Tủy Hoàn."},{"chuong":24,"importance":"normal","text":"Nhận gói dược phấn giảm đau (chỉ thống dược, năm phân) từ Hàn Lập tại cốc khẩu; mừng rỡ vì các loại thuốc giảm đau trước đây đều vô dụng. Lại thiếu Hàn Lập thêm một phần đại nhân tình."},{"bridge":true,"khoang":"c0033–c0034","text":"Giao dịch dược-đổi-võ định kỳ hơn nửa năm với Hàn Lập tại thủy đàm bí mật; dạy Cuồng Mãnh Kình và Triền Ti Thủ; hai người dần thành hảo hữu."},{"chuong":35,"importance":"major","tieuDe":"Trộm bí tịch Thất Tuyệt đường","text":"Lấy trộm toàn bộ bí tịch từ Thất Tuyệt đường tàng thư — hóa ra 74 quyển đều cùng tên 'Trát Nhãn kiếm phổ' — mang ra giao cho Hàn Lập tại thủy đàm."},{"chuong":37,"importance":"normal","tieuDe":"Mất hứng vì tam bất luyện","text":"Khi Hàn Lập giải thích Trát Nhãn kiếm pháp có điều kiện 'chân khí đã có thành tựu — không thể luyện', Lệ Phi Vũ (chân khí nội gia đã có hỏa hậu) lập tức mất hứng, dặn Hàn Lập sao lục bí tịch rồi cáo từ trước."},{"chuong":39,"importance":"normal","tieuDe":"Nhận công lao từ Hàn Lập","text":"Hàn Lập quyết định chuyển công lao bắt gian tế Dã Lang bang cho Lệ Phi Vũ lập công huy hoàng — vừa báo đáp ân tình kiếm phổ, vừa giúp Lệ Phi Vũ (người có dã tâm tiến vào cao tầng) thực hiện khát vọng."},{"chuong":41,"importance":"normal","text":"Nhận lại nguyên bản bí tịch từ Hàn Lập; được Hàn Lập báo tin về gian tế Dã Lang bang. Vừa mừng vừa sợ, gọi Hàn Lập 'hảo huynh đệ', cực kỳ cảm động."},{"chuong":43,"importance":"major","tieuDe":"Thăng hộ pháp Thất Huyền môn","text":"Nhờ cơ cảnh hơn người, đương trường phá tan âm mưu trộm danh sách đệ tử của hai gian tế Dã Lang bang nằm vùng; bắt được bọn chúng. Vương môn chủ trước đông đảo đệ tử thụ phong hộ pháp, Lệ Phi Vũ chính thức tiến nhập trung tầng Thất Huyền môn, danh tiếng vang dội."},{"chuong":69,"importance":"normal","tieuDe":"Tái xuất — vướng lưới tình thiếu nữ","text":"Tái xuất bất ngờ tại phòng khách nhà Lý trưởng lão (dù trước đây không có quan hệ gì với Lý trưởng lão). Đứng cạnh an ủi một thiếu nữ ~15-16 tuổi đang khóc — bộ dáng kẻ vướng vào lưới tình, trái ngược hoàn toàn với hình ảnh liều mạng vô thiên vô pháp trước đây."},{"chuong":70,"importance":"minor","tieuDe":"Vờ không quen Hàn Lập — lén làm mặt quỷ","text":"Cố tình làm bộ lãnh khốc, vờ không quen biết Hàn Lập trước đông người để không bại lộ mối quan hệ riêng. Khi mọi người quay đi, lén làm mặt quỷ trêu Hàn Lập rồi lập tức khôi phục vẻ lạnh lùng."},{"chuong":73,"importance":"major","tieuDe":"Từ chối phế võ — tuyên bố giữ Trương Tụ Nhi","text":"Hàn Lập thẳng thắn hỏi về Trừu Tủy Hoàn và thọ mệnh. Lệ Phi Vũ xác nhận chỉ còn sống được mấy năm, kiên quyết từ chối phế bỏ tu vi; tuyên bố 'trong khi còn sống, Trương Tụ Nhi là của ta một mình'."},{"chuong":74,"importance":"major","tieuDe":"Thăng phó đường chủ Ngoại Nhận Đường","text":"Giết tử y chưởng kỳ sứ Dã Lang bang trong chiến tranh, được thăng chức phó đường chủ Ngoại Nhận Đường. Trở thành một trong 'Song Hùng' của Thất Huyền môn."},{"chuong":75,"importance":"normal","tieuDe":"Phản đối hòa đàm với Dã Lang bang","text":"Khi Dã Lang bang đề nghị hòa đàm, Lệ Phi Vũ kiên quyết phản đối — nhưng ý kiến không được coi trọng."},{"chuong":76,"importance":"normal","tieuDe":"Sống sót trận phục kích Lạc Sa pha","text":"Đi cùng đoàn đàm phán bị Dã Lang bang phục kích. Sống sót vì không bị coi là mục tiêu trọng yếu; mình đầy máu chạy về núi báo tin."},{"chuong":77,"importance":"normal","tieuDe":"Phục kích Lam y chấp pháp — khai thác tin tức","text":"Phục kích một Lam y chấp pháp Dã Lang bang, xác nhận Ngô phó môn chủ và nhiều trưởng lão đã chết, nắm được kế hoạch địch. Báo cáo với Hàn Lập trên nóc nhà; lấy cớ trị thương lén tới chỗ Hàn Lập thay vì lên Lạc Nhật phong sợ bị đổ tội."},{"chuong":78,"importance":"normal","tieuDe":"Chứng kiến Khúc Hồn giết địch","text":"Lần đầu thấy Khúc Hồn xuất trận — sốt ruột thúc giục Hàn Lập, rồi sợ run người khi Khúc Hồn bước ra. Chứng kiến Khúc Hồn tàn sát nhóm Dã Lang bang trong nháy mắt; khuôn mặt đầy vẻ khó tin."},{"chuong":79,"importance":"normal","tieuDe":"Bức cung — diệt khẩu Lam y chấp pháp","text":"Bức cung Lam y chấp pháp khai toàn bộ tin tức về kế hoạch Dã Lang bang và liên minh. Sau khi lấy xong thông tin, tự tay diệt khẩu. Đồng ý đi hội họp người của mình theo kế hoạch Hàn Lập."},{"chuong":80,"importance":"normal","tieuDe":"Một mình phá trận mười địch","text":"Bị mười tên áo xanh Đoạn Thủy môn chặn vây khi chạy tới Lý trạch. Một mình lao ra đoạt cương đao địch rồi chém người, thân pháp như cầu vồng, giết liền mấy tên chưa kịp phản ứng."},{"chuong":83,"importance":"normal","tieuDe":"Cải trang vào Lạc Nhật Phong","text":"Cùng Hàn Lập cải trang thành người Đoạn Thủy Lưu để lén vào khu vực quanh Lạc Nhật Phong, nắm tình hình trận địa."},{"chuong":87,"importance":"major","tieuDe":"Ký tử khế vì Trương Tụ Nhi","text":"Khi thấy Trương Tụ Nhi bị điều vào nhóm tử đấu, quyết tâm xé trang phục ngụy trang, lộ y phục Thất Huyền môn, đến trước Vương Tuyệt Sở tự xưng phó đường chủ Ngoại Nhận Đường xin tham gia huyết đấu. Chính thức ký tên vào sinh tử thư. Cảm động khi Hàn Lập đi theo, gọi 'huynh đệ tốt, đa tạ'."},{"chuong":88,"importance":"minor","text":"Đứng trong hàng ngũ Thất Huyền môn tham gia huyết đấu; đang tâm sự thân mật cùng Trương Tụ Nhi ngay tại chiến trường."},{"chuong":90,"importance":"minor","text":"Có mặt trong trận huyết đấu; chứng kiến Chu Nho kích hoạt luồng sáng từ hộp đen giết hán tử cao thủ phe đối lập."},{"chuong":95,"importance":"normal","text":"Hưng phấn dị thường vì biết bạn thân Hàn Lập là 'thế ngoại cao nhân'; kể cho Hàn Lập nghe tin đồn 'hỏa ma' và ôm bụng cười hồi lâu không đứng dậy nổi. Vương Tuyệt Sở để mắt tới Lệ Phi Vũ với ánh mắt 'lão cáo già giảo hoạt' — muốn lợi dụng quan hệ với Hàn Lập."},{"chuong":97,"importance":"minor","text":"Là người trung gian báo tin Hàn Lập sẽ lên Lạc Nhật Phong cho các nhân vật cao cấp; cũng là người Hàn Lập nhờ truyền thư hẹn gặp riêng Vương Tuyệt Sở."},{"chuong":98,"importance":"major","tieuDe":"Được Vương Tuyệt Sở nhận làm đệ tử và thăng đường chủ Ngoại Nhận Đường","text":"Vương Tuyệt Sở chính thức nhận Lệ Phi Vũ làm đệ tử và phong làm đường chủ Ngoại Nhận Đường. Nhận được thuốc kéo dài tuổi thọ Hàn Lập để lại. Đứng trên đỉnh đồi nhìn theo bóng xe ngựa Hàn Lập rời đi trong cảm xúc."},{"text":"Trên đường cùng Hàn Lập đột phá vòng vây tìm cứu Trương Tư Nhi, lần đầu Lệ Phi Vũ chứng kiến Hàn Lập dùng La Yên bộ và Ngũ Phong quyết giết sạch địch nhân trong nháy mắt, trợn mắt há hốc mồm mới biết thực lực chân chính của bạn. Lệ Phi Vũ lầm tưởng đó là nhờ Trát Nhân kiếm pháp nên ghen tị, suýt muốn tự phế công lực để chuyển tu (lý trí kịp ngăn vì tuổi tác/tu chất). Sau đó một chưởng đánh ngất tên thân tín mập của Vương môn chủ (dùng lệnh bài giữ người), rồi cùng Hàn Lập trà trộn lên Lạc Nhật Phong.","nguonNblm":true,"bridge":true,"khoang":"@c0084"}],"tuViMoc":[{"chuong":18,"canhGioi":"Phàm nhân (võ giả) — Phong Lôi đao pháp đỉnh","text":"Thực lực hạng ba toàn môn Thất Huyền môn nhờ kết hợp Phong Lôi đao pháp và Trừu Tủy Hoàn tăng cường thân thể."},{"chuong":33,"canhGioi":"Phàm nhân (võ giả) — đã vào Thất Tuyệt đường","text":"Đã được vào Thất Tuyệt đường tu luyện; chân khí nội gia có hỏa hậu không ít; dùng dĩ chuyết phá xảo mới thắng Hàn Lập (không dùng chân khí thì trong trăm chiêu chưa chắc thắng)."},{"chuong":74,"canhGioi":"Phàm nhân (võ giả) — phó đường chủ Ngoại Nhận Đường","text":"Sau khi giết tử y chưởng kỳ sứ Dã Lang bang, được thăng phó đường chủ Ngoại Nhận Đường, trở thành 'Song Hùng' cùng một cao thủ khác.","importance":"major"},{"chuong":98,"canhGioi":"Phàm nhân (võ giả) — đường chủ Ngoại Nhận Đường; đệ tử Vương Tuyệt Sở","text":"Vương Tuyệt Sở nhận làm đệ tử và thăng đường chủ Ngoại Nhận Đường sau khi Hàn Lập rời môn.","importance":"major"}],"nhanMach":[{"ten":"Hàn Lập","tag":"an-nhan","quanHe":"Người cứu mạng; đang nhận chỉ thống dược mỗi năm; hứa giúp đỡ khi cần; giao dịch võ-dược hơn nửa năm thành hảo hữu; cùng ký tử khế huyết đấu"},{"ten":"Trương Tụ Nhi","tag":"the-thiep","quanHe":"Người trong lòng; ký tử khế để ở bên nàng trong trận huyết đấu"},{"ten":"Triệu Tử Linh","tag":"doi-dich-tam-thoi","quanHe":"Đối thủ trong trường đấu, bị Lệ Phi Vũ đánh bại"}],"tuiDo":{"phapBao":[{"ten":"Trường đao","loai":"binh khí phàm tục","trangThai":"đang giữ","moTa":"Đao hàn quang, dùng thi triển Phong Lôi đao pháp.","nguon":["c0017","c0018"]}],"danDuoc":[{"ten":"Trừu Tủy Hoàn","loai":"đan dược (đang dùng)","trangThai":"đang dùng — cả viên","moTa":"Dùng cả viên để tăng vọt võ công; chỉ còn sống thêm mấy năm. Gây thống khổ dữ dội sau mỗi lần dùng. Tại c73 Lệ Phi Vũ xác nhận với Hàn Lập: từ chối phế bỏ tu vi dù biết rõ thọ mệnh không còn.","nguon":["c0020","c0021","c0022","c0024","c0073"]}],"congPhap":[{"ten":"Phong Lôi đao pháp / Bôn Lôi đao pháp","loai":"đao pháp võ lâm","trangThai":"thành thục","moTa":"Đao pháp trung tầng Thất Huyền môn, liên hoàn đao thức, hét vang như sấm áp chế đối thủ, chém đá chặt vàng.","nguon":["c0017","c0018","c0019"]},{"ten":"Cuồng Mãnh Kình","loai":"công pháp cương mãnh","trangThai":"thành thục","moTa":"Công pháp thiên về cương dương mà Lệ Phi Vũ truyền cho Hàn Lập. Hàn Lập thấy quá cương mãnh không hợp.","nguon":["c0033"]},{"ten":"Triền Ti Thủ","loai":"công pháp","trangThai":"thành thục","moTa":"Môn võ công Lệ Phi Vũ truyền cho Hàn Lập; Hàn Lập luyện xuất thần nhập hóa chỉ trong hai tháng.","nguon":["c0035"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0017","c0018","c0019","c0020","c0021","c0022","c0024","c0033","c0034","c0035","c0036","c0037","c0038","c0039","c0041","c0043","c0069","c0070","c0071","c0072","c0073","c0074","c0075","c0076","c0077","c0078","c0079","c0080","c0083","c0087","c0088","c0090","c0095","c0097","c0098"]},{"id":"kim-dong-bao","name":"Kim Đông Bảo","cn":null,"aliases":["tiểu toán bàn","vạn sự thông"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (võ giả)","trangThai":"song","blurb":"Đệ tử trẻ của Thất Huyền môn, biệt danh \"tiểu toán bàn\" và \"vạn sự thông\" vì hay tính toán và biết hết chuyện trong môn. Là nguồn cung cấp thông tin cho Hàn Lập khi hắn quan sát trường đấu. Hứa được Hàn Lập chữa bệnh miễn phí.","vaiTro":"Đệ tử cùng môn, nguồn tin tức","tinhCach":[{"text":"Hay tính toán vụ lợi, xu viêm phụ thế — đổi ngay từ \"sư đệ\" sang \"sư huynh\" khi tưởng Hàn Lập có thế lực","chuong":17},{"text":"Miệng không ngừng, hào hứng kể chuyện, dễ tin người khi được chứng minh thân phận","chuong":19}],"tabs":{"diem":[{"text":"Biết hết mọi người, mọi sự trong môn — tự xưng \"vạn sự thông\"","chuong":16},{"text":"Tục danh Kim Đông Bảo — lộ rõ khi Hàn Lập hỏi thẳng","chuong":19}],"kinhLich":[{"chuong":16,"importance":"normal","text":"Đứng ngoài cổ vũ, kể cho Hàn Lập nghe toàn bộ nguyên do trường đấu (bi kịch Vương Dạng, mâu thuẫn phe phái)."},{"chuong":17,"importance":"minor","text":"Đổi thái độ lập tức khi tưởng Hàn Lập là đệ tử cung phụng quyền thế; bắt đầu nghi ngờ khi thấy hắn không có dấu hiệu nội công."},{"chuong":19,"importance":"minor","text":"Xác nhận thân phận Hàn Lập qua lệnh bài nội môn; kể bối cảnh chiến tranh Thất Huyền Môn — Dã Lang Bang và môn quy mới. Tục danh Kim Đông Bảo được hé lộ; Hàn Lập hứa chữa bệnh/thương miễn phí."}],"tuViMoc":[],"nhanMach":[{"ten":"Hàn Lập","tag":"dong-mon","quanHe":"Quen biết tại trường đấu; được hứa chữa bệnh miễn phí"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0016","c0017","c0019"]},{"id":"trieu-tu-linh","name":"Triệu Tử Linh","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (võ giả)","trangThai":"song","blurb":"Đệ tử của ngũ trưởng lão Thất Huyền môn. Kẻ mạnh nhất phe Trương Trường Quý trong trường đấu — dùng nhuyễn kiếm, kiếm pháp âm độc gian xảo, phòng thủ kín. Thua Lệ sư huynh: bị liên hoàn đao chấn bay nhuyễn kiếm, hổ khẩu tay phải bị thương, cam bái hạ phong.","vaiTro":"Đệ tử ngũ trưởng lão, đấu thủ phe Trương Trường Quý","tinhCach":[{"text":"Tuy thua nhưng vẫn mỉm cười thi lễ — phong độ không mất mặt","chuong":19}],"tabs":{"diem":[{"text":"Đệ tử ngũ trưởng lão — thế lực sau lưng mạnh hơn bình thường","chuong":18},{"text":"Dùng nhuyễn kiếm mỏng mềm, kiếm pháp phiêu hốt bất định, âm độc gian xảo, phòng thủ như giọt nước không lọt","chuong":18}],"kinhLich":[{"chuong":18,"importance":"normal","text":"Được Trương Trường Quý cử ra đấu với Lệ sư huynh — người mạnh nhất phía mình. Phòng thủ kín nhưng khí thế đã mất trước liên hoàn đao áp đảo."},{"chuong":19,"importance":"normal","text":"Bị liên hoàn đao của Lệ sư huynh chấn bay nhuyễn kiếm, hổ khẩu tay phải bị thương; cam bái hạ phong, mỉm cười thi lễ."}],"tuViMoc":[],"nhanMach":[{"ten":"Ngũ trưởng lão","tag":"su-mon","quanHe":"Sư phụ"},{"ten":"Lệ sư huynh","tag":"doi-dich-tam-thoi","quanHe":"Đối thủ trường đấu, người đánh bại mình"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Nhuyễn kiếm pháp","loai":"kiếm pháp võ lâm","trangThai":"thành thục","moTa":"Dùng nhuyễn kiếm mỏng mềm, kiếm pháp phiêu hốt bất định, âm độc gian xảo.","nguon":["c0018","c0019"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0018","c0019"]},{"id":"vuong-dai-ban","name":"Vương đại bàn","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (võ giả)","trangThai":"song","blurb":"Đệ tử Thất Huyền môn, hảo hữu của Hàn Lập. Thân hình béo mập nhưng hạ bàn vững, quyền cước có lực, quan hệ rộng ở tầng trung-hạ. Đứng ra báo thù cho đường đệ Vương Dạng bị cướp hôn ước, cầm đầu phe trung-hạ tầng trong trường đấu với phe phú gia đệ tử của Trương Trường Quý.","vaiTro":"Đệ tử Thất Huyền môn, cầm đầu phe trung-hạ tầng trong tranh chấp","tinhCach":[{"text":"Trọng nghĩa khí, đứng ra báo thù cho đường đệ; sau khi thắng thì đắc ý lắc mông khoe khoang","chuong":16}],"tabs":{"diem":[{"text":"Quan hệ rộng ở tầng trung-hạ — thu hút nhiều đệ tử tự nguyện giúp","chuong":16}],"kinhLich":[{"chuong":16,"importance":"normal","text":"Thắng trận mở màn bằng quyền trúng gáy đối thủ, khiến hắn ngất xỉu. Sau đó đắc ý khoe khoang."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Dạng","tag":"ho-hang","quanHe":"Đường đệ, đã tự tử"},{"ten":"Trương Trường Quý","tag":"doi-dich","quanHe":"Đối thủ trong tranh chấp"},{"ten":"Hàn Lập","tag":"ban-be","quanHe":"Hảo hữu trong môn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0016","c0017","c0020"]},{"id":"truong-truong-quy","name":"Trương Trường Quý","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (võ giả)","trangThai":"song","blurb":"Con lão bản tiền trang, nội môn đệ tử Thất Huyền môn. Ỷ tiền ép cô gái đã hứa hôn với Vương Dạng cải hôn theo mình, gây ra cái chết của Vương Dạng và châm ngòi trận đấu phe phái với Vương đại bàn. Tự biết võ nghệ kém nên đòi chia nhiều trận tính tổng và dùng tiền chiêu mộ trợ thủ phú gia đệ tử.","vaiTro":"Đệ tử phú gia Thất Huyền môn, cầm đầu phe đối địch trong tranh chấp","tinhCach":"tâm cao khí ngạo; ỷ vào tiền bạc; toan tính, biết võ kém nên tìm cách lấy số đông và tài lực bù đắp","tabs":{"diem":[{"text":"Ép cô gái đã hứa hôn với Vương Dạng cải hôn theo mình","chuong":"@c0016"},{"text":"Hành vi ép hôn dẫn tới cái chết của Vương Dạng","chuong":"@c0016"},{"text":"Tổ chức đấu phe với Vương đại bàn, đòi chia nhiều trận tính tổng","chuong":"@c0016"},{"text":"Dùng tiền chiêu mộ trợ thủ là phú gia đệ tử để bù đắp võ nghệ kém","chuong":"@c0016"}],"kinhLich":[{"chuong":16,"importance":"normal","text":"Ép cô gái cải hôn, dẫn tới cái chết Vương Dạng. Tổ chức đấu phe với Vương đại bàn — đòi chia nhiều trận tính tổng, dùng tiền mộ trợ thủ."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương đại bàn","tag":"doi-dich","quanHe":"Đối thủ trong tranh chấp"},{"ten":"Triệu Tử Linh","tag":"dong-minh","quanHe":"Đấu thủ đại diện phe mình"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0016","c0017","c0018","c0019","c0020"]},{"id":"vuong-duong","name":"Vương Dạng","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn — ngoại môn","trangThai":"da-roi"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"tu-vong","blurb":"Đường đệ Vương đại bàn, ngoại môn đệ tử Thất Huyền môn. Có hôn ước từ nhỏ với một cô gái; cô gái bị Trương Trường Quý ỷ tiền ép cải hôn. Vương Dạng đau khổ nhảy sông tự tử — cái chết của hắn là ngòi nổ cho trận đấu phe phái giữa Vương đại bàn và Trương Trường Quý.","vaiTro":"Nhân vật nền — nguyên nhân của trận đấu phe phái","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":16,"importance":"normal","text":"Bị Trương Trường Quý ỷ tiền cướp hôn ước (cô gái cải hôn); đau khổ nhảy sông tự tử. Cái chết thúc đẩy Vương đại bàn tìm Trương Trường Quý quyết đấu."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương đại bàn","tag":"ho-hang","quanHe":"Đường huynh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0016"]},{"id":"co-thien-long","name":"Cổ Thiên Long","cn":null,"aliases":["Kim lang"],"gioiTinh":"nam","theLuc":[{"ten":"Dã Lang bang","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ — võ giả phàm tục cấp cao","trangThai":"tu-vong","blurb":"Cổ Thiên Long, biệt hiệu 'Kim lang', là bang chủ Dã Lang bang và đại địch của Thất Huyền môn. Ngoài mặt gầy yếu tuấn tú tuổi khoảng ba mươi nhưng ra tay tàn độc đúng như lời đồn ma đầu tắm máu, y tổ chức cuộc tấn công tổng lực vào Lạc Nhật Phong với Hồng y thiết vệ, 300 cây nỏ liên châu quân dụng và thuê cao thủ tu tiên Chu Nho. Sau khi nhận huyết đấu và chứng kiến ba sư thúc Thất Huyền môn vượt xa dự liệu, y bắt đầu hối tiếc rồi cuối cùng tử trận dưới tay Hàn Lập tại tử đấu trường.","vaiTro":"Bang chủ Dã Lang bang — đại địch của Thất Huyền môn","tinhCach":"Tàn nhẫn hiếu sát, động là giết người; tự tin đến chủ quan; toan tính, dùng tiền và cao thủ ngoại vi để đạt mục đích; dễ hối tiếc và hoảng loạn khi cục diện vượt dự liệu","tabs":{"diem":[{"text":"Trực tiếp chỉ huy tấn công Lạc Nhật Phong với Hồng y thiết vệ và 300 cây nỏ liên châu quân dụng","chuong":"@c0081"},{"text":"Thuê Chu Nho (Kim Quang thượng nhân) với thù lao 3000 lượng vàng trả trước, 2000 lượng khi giết ba sư thúc, dưới chỉ đạo của Trương tiên sư","chuong":"@c0082"},{"text":"Chấp thuận tử khế đấu 50 đối 50 với Vương Tuyệt Sở vì tự tin vào phi kiếm thuật của Chu Nho","chuong":"@c0085"},{"text":"Nâng thù lao Chu Nho từ 5.000 lên 8.000 lượng vàng để ra trận tiêu diệt Thất Huyền môn","chuong":"@c0088"},{"text":"Bắt đầu hối tiếc khi thấy Chu Nho bị sư thúc Thất Huyền môn áp chế, cục diện vượt dự liệu","chuong":"@c0089"},{"text":"Tử trận cùng hơn 50 người Dã Lang bang tại tử đấu trường, bị Hàn Lập dùng ẩn thân và độn thuật giết","chuong":"@c0094"}],"kinhLich":[{"chuong":38,"importance":"normal","tieuDe":"Được nhắc qua lời gian tế và Lệ Phi Vũ","text":"Hai gian tế đêm khuya nhắc 'bang chủ' khi bàn kế hoạch hành động với Thất Huyền môn. Hàn Lập nhận ra 'Kim lang' Cổ Thiên Long là bang chủ Dã Lang bang duy nhất trong phương viên mấy trăm dặm. Lệ Phi Vũ từng kể thực tế về ngoại hình và tính cách hắn."},{"chuong":81,"importance":"normal","tieuDe":"Tổ chức tấn công Lạc Nhật Phong","text":"Trực tiếp chỉ huy cuộc tấn công Lạc Nhật Phong với Hồng y thiết vệ tinh nhuệ và 300 cây nỏ liên châu mua từ em họ phó tướng; lên doanh trại chỉ huy trận chiến."},{"chuong":82,"importance":"major","tieuDe":"Thuê Chu Nho — nhận chỉ đạo từ Trương tiên sư","text":"Thuê Chu Nho (Kim Quang thượng nhân) với thù lao 3000 lượng vàng trả trước và 2000 lượng sau khi giết ba sư thúc Thất Huyền môn. Toàn bộ kế hoạch tấn công có sự chỉ đạo của 'Trương tiên sư' — nhân vật bí ẩn chỉ nghe thấy giọng nói, Cổ Thiên Long tuyệt đối phục tùng."},{"chuong":85,"importance":"major","tieuDe":"Chấp thuận tử khế đấu","text":"Nhận đề nghị tử khế đấu 50 đối 50 của Vương Tuyệt Sở; tự tin vào phi kiếm thuật của Chu Nho nên đồng ý. Ký vào sinh tử thư."},{"chuong":88,"importance":"normal","tieuDe":"Nâng thù lao Chu Nho","text":"Tăng thù lao từ 5.000 lên 8.000 lượng vàng để Chu Nho ra trận tiêu diệt người Thất Huyền môn; vui mừng khi thấy Kim Quang Tráo uy lực."},{"chuong":89,"importance":"normal","tieuDe":"Bắt đầu hối tiếc nhận huyết đấu","text":"Chứng kiến Chu Nho bị hán tử râu ria (sư thúc Thất Huyền môn) áp chế, lần đầu hối tiếc vì tùy tiện nhận lời huyết đấu; nhận ra Thất Huyền môn có ba cao thủ quái vật chống lưng, đó là lý do đối phương dám nhận tử khế. Cân nhắc có nên cử người trợ giúp Chu Nho hay không."},{"chuong":90,"importance":"minor","text":"Sau khi thấy hán tử không phá nổi kim quang, bỏ ý định phái thêm người tấn công. Chứng kiến Chu Nho kích hoạt hộp đen giết hán tử."},{"chuong":94,"importance":"major","tieuDe":"Tử trận tại tử đấu trường","text":"Bị Hàn Lập dùng ẩn thân và độn thuật qua mặt rồi giết trong tử đấu trường Lạc Nhật Phong. Cùng hơn 50 người Dã Lang bang còn lại đều bị tiêu diệt. Dã Lang bang chính thức bị xóa sổ."},{"chuong":"@c0083","importance":"normal","text":"Tra hỏi Vương Tuyệt Sở có thật đầu hàng không; bị đáp mặt mờ liền nổi giận, ra đầu thiết về vây quanh giường Liên Châu Nỏ chĩa vào đội giết ngay — nhưng bị lời uy hiếp 'cả Lạc Nhật Phong là đại bẫy, sẽ động quỷ vu tản' làm dao động; hạ lệnh chém giết những kẻ nhất quyết định bỏ chạy để vãn hồi trật tự.","nguonNblm":true},{"chuong":"@c0084","importance":"normal","text":"Khi thạch điện sụp thành hang động sâu (cơ quan Địa Động của Vương Tuyệt Sở), thấy cả Kim Quang thượng nhân cũng kinh hoàng → nhận ra kẻ diệt Thất Huyền môn đêm nay thật bại, không cầm lòng phải chấp nhận đàm phán điều kiện, tự nhận hai bên 'ngang tay'.","nguonNblm":true},{"text":"Trao đổi/xác nhận Sinh Tử Khế; tuyển 13 tinh anh Dã Lang bang và ép thêm vài chục thần thủ tiểu bang phải ký tử khế để giảm tổn thất phe mình; trong cậy toàn bộ vào phi kiếm thuật Kim Quang thượng nhân, rụt rè do hỏi rồi phải cười xin lỗi nịnh nọt khi bị Chu Nho gạt.","nguonNblm":true,"bridge":true,"khoang":"@c0086"},{"text":"Trước nay soi trao, nay sợ toát mồ hôi lạnh, sắc mặt tái nhợt khi thấy sư thúc áo xám Thất Huyền môn xuất được kiếm quang/kiếm mang; lo lắng khi phi kiếm Chu Nho bị đánh rớt.","nguonNblm":true,"bridge":true,"khoang":"@c0091"}],"tuViMoc":[],"nhanMach":[{"ten":"Dã Lang bang","tag":"su-mon","quanHe":"Người lãnh đạo"},{"ten":"Thất Huyền môn","tag":"doi-dich","quanHe":"Thế lực đối địch chính"},{"ten":"Chu Nho","tag":"dong-minh","quanHe":"Cao thủ tu tiên thuê làm chỗ dựa; giá 5000 rồi 8000 lượng vàng"},{"ten":"Trương tiên sư","tag":"an-nhan","quanHe":"Nhân vật bí ẩn đứng sau chỉ đạo toàn bộ kế hoạch — lai lịch chưa rõ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0038","c0081","c0082","c0083","c0084","c0085","c0086","c0087","c0088","c0089","c0090","c0094"]},{"id":"quan-su-bep","name":"Đại quản sự phòng bếp","cn":null,"aliases":["Quản sự trù phòng"],"gioiTinh":"nam","theLuc":[{"ten":"Dã Lang bang","trangThai":"gan-bo"},{"ten":"Thất Huyền môn","trangThai":"gia-mao"}],"canhGioiCaoNhat":"Không rõ — võ giả phàm tục","trangThai":"song","blurb":"Đại quản sự phòng bếp trên núi Thất Huyền môn, bề ngoài là người buôn bán thật thà với bộ râu chữ bát, thực chất là gian tế do Dã Lang bang cài cắm nội bộ. Từng bán thỏ cho Hàn Lập và để lại ấn tượng tốt, nhưng cuối cùng bị Hàn Lập nhận ra qua giọng nói khi nghe lén cuộc bàn kế hoạch đêm khuya trên sơn đạo.","vaiTro":"Nội gián Dã Lang bang trong Thất Huyền môn","tinhCach":"Kín đáo, che giấu thân phận dưới vẻ ngoài thành thật; giỏi ngụy trang trong sinh hoạt thường ngày","tabs":{"diem":[{"text":"Râu chữ bát, vẻ ngoài người buôn bán thành thật — thân phận quản sự bếp giúp thường xuyên lên xuống núi truyền tin không bị chú ý","chuong":38}],"kinhLich":[{"chuong":38,"importance":"major","tieuDe":"Bị Hàn Lập nhận ra là gian tế","text":"Một trong hai gian tế đi đêm bàn kế hoạch hành động với Thất Huyền môn liên quan tới việc trộm một 'danh sách'. Hàn Lập nhận ra qua giọng nói — chính là quản sự trù phòng từng bán thỏ cho hắn."}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Thiên Long","tag":"su-mon","quanHe":"Chủ của bang phái thực sự"},{"ten":"Hàn Lập","tag":"doi-dich-tam-thoi","quanHe":"Người tình cờ phát hiện thân phận thật"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0038"]},{"id":"truong-lao-trat-nhan","name":"Trưởng lão sáng lập Trát Nhãn kiếm pháp","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"da-roi"}],"canhGioiCaoNhat":"Võ giả phàm tục (từng công lực cao thâm)","trangThai":"tu-vong","blurb":"Vị trưởng lão Thất Huyền môn thời xa xưa. Thời tráng niên vốn công lực cao thâm, nhưng trong một lần giao tranh trên giang hồ bị đối thủ vô ý phế bỏ nội công. Giấu kín bí mật, bế quan hơn mười năm tự sáng tạo ra Trát Nhãn kiếm pháp — môn kiếm kỹ không cần nội lực. Dùng kiếm pháp mới luyện thành cứu Thất Huyền môn khỏi bị diệt vong, lập đại công, rồi qua đời ở tuổi hoa giáp (sáu mươi). Để lại di chúc đưa kiếm phổ vào Thất Tuyệt đường.","vaiTro":"Người sáng lập Trát Nhãn kiếm pháp","tinhCach":[{"text":"Tài cao, thiên phú, kiên trì bế quan hơn mười năm để sáng tạo võ học mới sau khi mất nội lực","chuong":40}],"tabs":{"diem":[{"text":"Bị phế bỏ nội công, sợ mất địa vị trong môn nên giấu kín; dùng cơ trí hơn người để che đậy suốt thời gian bế quan","chuong":40},{"text":"Qua đời ở tuổi hoa giáp (sáu mươi) sau khi cứu thoát Thất Huyền môn khỏi bị các bang phái vây công","chuong":40}],"kinhLich":[{"chuong":33,"importance":"normal","tieuDe":"Được nhắc lần đầu","text":"Lệ Phi Vũ đề cập vị trưởng lão sáng tạo Trát Nhãn kiếm pháp: từng nhiều lần cứu Thất Huyền môn khỏi nguy cơ, trước khi lâm chung lập di chúc bắt buộc đưa kiếm pháp vào Thất Tuyệt đường."},{"chuong":40,"importance":"normal","tieuDe":"Lai lịch đầy đủ được tiết lộ","text":"Thời tráng niên công lực cao thâm, bị đối thủ phế bỏ võ công vô ý; giấu bí mật, lặng lẽ cưỡng đoạt nhiều bí tịch các môn phái, bế quan hơn mười năm tự sáng tạo Trát Nhãn kiếm pháp. Khi luyện thành, Thất Huyền môn đang bị vây công sắp diệt; hắn mở đường máu thoát vây, lập đại công. Sau đó gặp đại hạn, qua đời ở tuổi hoa giáp."}],"tuViMoc":[{"chuong":40,"canhGioi":"Võ giả bị phế nội công — chuyển sang kiếm kỹ không cần chân khí","text":"Từng công lực cao thâm nhưng bị phế bỏ hoàn toàn; về sau dùng Trát Nhãn kiếm pháp thay thế, đủ sức mở đường máu cho toàn môn phái."}],"nhanMach":[{"ten":"Thất Huyền môn","tag":"su-mon","quanHe":"Môn phái, người hắn cứu thoát"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Trát Nhãn kiếm pháp","loai":"bí kỹ kiếm pháp","trangThai":"sáng lập — đã để lại di chúc đưa vào Thất Tuyệt đường","moTa":"Môn kiếm kỹ ám sát không cần nội lực do hắn tự sáng tạo sau hơn mười năm bế quan, tổng hợp nhiều bí tịch.","nguon":["c0033","c0034","c0040"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["c0033","c0034","c0040"]},{"id":"du-tu-dong","name":"Dư Tử Đồng","cn":null,"aliases":["Đệ tam nhân","Nguyên thần ký sinh"],"gioiTinh":"nam","theLuc":["Gia tộc tu tiên (không nêu tên)"],"canhGioiCaoNhat":"Tu tiên — Trường Xuân công tầng 7 (chưa Trúc Cơ; nay chỉ còn nguyên thần, mất pháp thân)","trangThai":"tu-vong","blurb":"Tu sĩ xuất thân gia tộc tu tiên, tu Trường Xuân công tới tầng 7 nhưng tư chất có hạn nên không đạt Trúc Cơ. Sau khi chết, nguyên thần ẩn mình ký sinh làm quỷ hồn suốt nhiều năm và là kẻ chủ mưu thật giăng bẫy hòng đoạt xá Hàn Lập. Cuối cùng bị Hàn Lập phản sát, nguyên thần chỉ còn 1/3 rồi bị độc dịch diệt tận dứt điểm.","vaiTro":"Phản diện ngầm — kẻ chủ mưu vụ đoạt xá; nguyên thần ký sinh trong thân Mặc đại phu","tinhCach":"thâm hiểm, giỏi giăng bẫy để ngư ông đắc lợi; xảo ngôn — chiêu tìm đồng cảm, biện minh khi bị vạch trần; ẩn nhẫn, ký sinh chờ thời nhiều năm; toan tính lạnh lùng, coi người khác làm quân cờ đoạt xá","tabs":{"diem":[{"text":"Cảnh báo Mặc đại phu qua truyền âm rằng Hàn Lập tinh minh, không dễ thất bại","chuong":"@c042"},{"text":"Lộ diện 'đệ tam nhân' — tiếng nói cất lên trong căn nhà đá khiến cả Mặc đại phu lẫn Hàn Lập đều nghe","chuong":"@c055"},{"text":"Đoạt xá thất bại, nguyên thần bị Hàn Lập đánh đuổi, chỉ còn 1/3 và trốn vào góc nhà đá","chuong":"@c0057"},{"text":"Tự khai lai lịch: gia tộc tu tiên, tu Trường Xuân công tầng 7, không đạt Trúc Cơ","chuong":"@c058"},{"text":"Bị vạch trần là kẻ chủ mưu giăng bẫy; tự thú rồi đề nghị hợp tác","chuong":"@c0059"},{"text":"Nguyên thần (lục sắc quang cầu) bị Hàn Lập dùng độc dịch diệt tận dứt điểm","chuong":"@c061"}],"kinhLich":[{"chuong":42,"importance":"normal","text":"Cảnh báo Mặc đại phu qua truyền âm: Hàn Lập tinh minh, không dễ thất bại. Bị Mặc đại phu khiển trách nghi ngờ công pháp 'có chỗ không ổn'; vội giải thích rồi không dám tiếp lời. Bộ mặt thật lúc này còn ẩn."},{"chuong":55,"importance":"normal","tieuDe":"Lộ diện 'đệ tam nhân'","text":"Tiếng nói 'đệ tam nhân' lần đầu lộ diện — cất tiếng trong căn nhà đá khiến cả Mặc đại phu lẫn Hàn Lập đều nghe thấy. Ép Mặc đại phu thề độc về việc hợp tác — vì nghi lão ôm hận muốn trở mặt sau khi đoạt xá xong."},{"chuong":56,"importance":"normal","tieuDe":"Giải thích Thất Quỷ Phệ Hồn đại pháp","text":"Tham gia vào nghi thức đoạt xá bên phía Mặc đại phu; hiện diện như quỷ hồn ẩn trong không gian. Giải thích nguyên lý Thất Quỷ Phệ Hồn đại pháp và cơ chế đoạt xá cho Hàn Lập nghe (lúc Hàn Lập đang bất tỉnh — về sau Hàn Lập nhớ lại)."},{"chuong":57,"importance":"major","tieuDe":"Lộ danh tính — đoạt xá thất bại","text":"Đoạt xá thất bại; nguyên thần bị nguyên thần Hàn Lập đánh đuổi, chỉ còn 1/3, trốn vào góc nhà đá. Hàn Lập gọi đúng tên 'Dư Tử Đồng' — thừa nhận thân phận và bắt đầu khai báo. Chính thức lộ diện là nhân vật thứ ba ẩn phía sau vụ đoạt xá."},{"chuong":58,"importance":"normal","tieuDe":"Tự khai lai lịch — chiêu tìm đồng cảm","text":"Kể trọn bộ lai lịch: gia tộc tu tiên, tu Trường Xuân công tầng 7, không đạt Trúc Cơ, lang thang thế tục, mua Huyết linh thảo, bị truy sát, dùng Bảo mệnh phù chạy thoát, gặp Mặc đại phu bị hại, lâm tử dùng huyết tiến âm hồn chú cứu nguyên thần. Đẩy hết tội cho Mặc đại phu, tự nhận là nạn nhân bất đắc dĩ."},{"chuong":59,"importance":"major","tieuDe":"Tự thú chủ mưu — đề nghị hợp tác","text":"Bị Hàn Lập vạch trần toàn bộ: thực ra là kẻ chủ mưu, cố ý giăng bẫy. Thừa nhận là chủ mưu nhưng biện minh 'không có lựa chọn khác'. Tiết lộ tam đại thiết tắc của đoạt xá. Ở thế yếu, xuống nước đề nghị hợp tác: hứa dẫn Hàn Lập gặp trưởng lão gia tộc thu làm đồ đệ tu tiên chân chính."},{"chuong":60,"importance":"major","tieuDe":"BỊ DIỆT — Hàn Lập phản sát","text":"Bị Hàn Lập dùng mưu vờ đồng ý hợp tác để câu giờ; lúc mất cảnh giác bị phun độc dịch trúng nguyên thần — quang cầu ảm đạm, thụ thương nặng, kêu thảm. Tiếp theo bị Ngọc Đái đoản kiếm chém xuống. Nguyên thần bị tiêu diệt tận gốc."},{"chuong":"@c0061","importance":"major","text":"Nguyên thần Dư Tử Đồng (lục sắc quang cầu) bị Hàn Lập diệt tận dứt điểm: dính thất độc thúy (thêm Thổ cổ hóa hại nguyên thần tư tiên) nên mất pháp lực, bị dồn vào góc và chém bằng nhuyễn kiếm; cuối cùng Hàn Lập mở cửa đá cho ánh sáng tràn vào, phần nguyên thần còn sót hóa khói xanh tan biến — xóa sạch dấu vết Dư Tử Đồng trên thế gian, chết hẳn.","nguonNblm":true}],"tuViMoc":[{"chuong":58,"canhGioi":"Tu tiên — Trường Xuân công tầng 7 (không đạt Trúc Cơ)","text":"Tự khai: tu Trường Xuân công tới tầng 7 nhưng tư chất có hạn, hỏa hầu không đủ để đột phá Trúc Cơ. Rời gia tộc xuống thế tục tìm dược liệu/nâng tâm cảnh, cuối cùng sa vào vinh hoa phai nhạt tâm tu.","importance":"major"},{"chuong":59,"canhGioi":"Nguyên thần tàn — 1/3 còn lại, nguyên khí đại thương","text":"Sau cuộc đoạt xá thất bại với Hàn Lập: chỉ còn 1/3 nguyên thần, nguyên khí đại thương, pháp lực hao mòn dần. Dư Tử Đồng xác nhận cao hơn Hàn Lập 1 tầng (tầng 7 vs tầng 6-7 của Hàn Lập), nhưng ở trạng thái đại thương không thể địch lại."}],"nhanMach":[{"ten":"Mặc đại phu (Mặc Cư Nhân)","tag":"cuu-thu","quanHe":"Kẻ hạ độc giết hắn năm xưa; hắn ký sinh vào thân Mặc đại phu suốt nhiều năm, thống hận nhưng bất lực trước Phệ Hồn đại pháp"},{"ten":"Hàn Lập","tag":"ke-thu","quanHe":"Mục tiêu đoạt xá; bị Hàn Lập phản sát tại c60"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Huyết linh thảo (đã mất)","loai":"dược liệu","trangThai":"bị cướp","moTa":"Dược liệu hiếm mua được ở dược điếm; bị Mặc đại phu cướp sau khi giết hắn.","nguon":["c0058"]},{"ten":"Dược hoàn (đã mất)","loai":"đan dược không rõ loại","trangThai":"bị cướp","moTa":"Đan dược trên thi thể Dư Tử Đồng; Mặc đại phu cướp uống vào, khôi phục công lực.","nguon":["c0058"]}],"congPhap":[{"ten":"Trường Xuân công (tầng 7)","loai":"công pháp tu tiên","trangThai":"đã tu","moTa":"Tu tới tầng 7, không đột phá Trúc Cơ được vì tư chất hạn.","nguon":["c0058"]},{"ten":"Huyết tiến âm hồn chú","loai":"bí thuật lâm tử","trangThai":"đã dùng @c58","moTa":"Bí thuật dùng khi lâm tử: hóa máu huyết thành huyết chú phún lên đầu đối phương; nguyên thần xuất khiếu thoát ra trước khi thân xác chết.","nguon":["c0058"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Bảo mệnh phù (đã dùng)","loai":"phù lục gia tộc","trangThai":"đã tiêu hao","moTa":"Bí pháp gia tộc tu tiên: kích hoạt gây hiệu ứng 'đồng quy vu tận' với đối thủ — dùng để dọa lui tu sĩ truy sát.","nguon":["c0058"]}]}},"uuTien":3,"nguon":["c0042","c0055","c0056","c0057","c0058","c0059","c0060"]},{"id":"ly-truong-lao","name":"Lý trưởng lão","cn":"李长老","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ — trưởng lão Thất Huyền môn","trangThai":"song","blurb":"Lý trưởng lão là một trong những trưởng bối của Thất Huyền môn, sư phụ của Mã Vinh và là người được cả môn yêu quý nhờ tính tình nhân hậu, không màng tranh đoạt. Trong một lần xuống núi hành sự, ông trúng ám toán kịch độc của Dã Lang bang và hôn mê bất tỉnh, bệnh tình cực nặng, sau đó được Hàn Lập cùng các trưởng bối cứu chữa và hồi phục hoàn toàn. Về sau ông trực tiếp ký tử khế đấu, tham gia huyết chiến giữa Thất Huyền môn và Dã Lang bang.","vaiTro":"Trưởng lão Thất Huyền môn, sư phụ của Mã Vinh","tinhCach":"Nhân hậu, không tranh quyền đoạt thế; đối đãi tử tế với đồng môn từ cấp cao đến cấp thấp; quan hệ rộng, được cả môn yêu quý; quả cảm, dám ký tử khế đấu tham gia huyết chiến","tabs":{"diem":[{"text":"Vóc người mi mục thanh tú ('mi mục thiên') khi còn khỏe","chuong":70},{"text":"Bị trúng kịch độc ám toán khi đấu với cao thủ Dã Lang bang: lúc trúng không để ý còn đánh bại đối phương, nhưng chưa về tới núi thì độc phát, lâm vào hôn mê","chuong":68}],"kinhLich":[{"chuong":68,"importance":"major","tieuDe":"Trúng kịch độc Dã Lang bang","text":"Xuống núi hành sự, đấu với cao thủ Dã Lang bang, trúng ám toán kịch độc; đánh bại đối phương xong nhưng chưa về núi thì độc phát hôn mê. Các đại phu trên núi đều bó tay không nhận ra loại độc."},{"chuong":70,"importance":"normal","tieuDe":"Bệnh tình được Hàn Lập chứng kiến","text":"Hàn Lập lần đầu trực tiếp thấy bệnh tình: hôn mê bất tỉnh; toàn thân nổi độc ban lớn nhỏ đủ màu sắc; mỗi lần thở ra mặt bị hắc khí nhàn nhạt phủ — triệu chứng trúng độc cực nặng."},{"chuong":71,"importance":"normal","tieuDe":"Được Hàn Lập dùng Thanh Linh Tán giải độc","text":"Nhờ kết hợp Thanh Linh Tán (hòa nước ấm) và châm cứu. Toàn thân hắc khí và độc ban giảm mạnh. Thanh Linh Tán không giải được độc còn tiềm phục sâu trong người."},{"chuong":72,"importance":"major","tieuDe":"Hoàn toàn giải độc — sẽ tỉnh lại ngày hôm sau","text":"Mã phó môn chủ và Tiễn trưởng lão dùng nội lực bức huyết độc qua huyệt đạo; Hàn Lập dùng kim châm để lấy độc ra. Mã Vinh lấy chậu nước. Toàn bộ độc tố tiêu trừ — hắc khí và độc ban biến mất hoàn toàn."},{"chuong":73,"importance":"normal","tieuDe":"Hồi phục hoàn toàn","text":"Hắc khí và độc ban đã hết; Lý trưởng lão được phán là sẽ hồi phục dần. Hàn Lập kê đơn thuốc bổ rồi rời đi không chờ cảm tạ."},{"chuong":80,"importance":"bridge","tieuDe":"Đã lên Lạc Nhật phong cùng gia nhân","text":"Được tên mập (thân tín Vương môn chủ) tới triệu lên Lạc Nhật phong nghị sự; Lý trưởng lão dẫn theo Trương Tụ Nhi và vài đệ tử lên núi trước khi đại biến xảy ra."},{"chuong":86,"importance":"major","tieuDe":"Xác nhận là sư phụ Mã Vinh — ký tử khế đấu","text":"Một trong những trưởng bối trực tiếp ký tử khế đấu tham gia huyết chiến Thất Huyền môn với Dã Lang bang. Danh tính là sư phụ của Mã Vinh được xác nhận rõ trong nguyên tác tại chương này."}],"tuViMoc":[],"nhanMach":[{"ten":"Mã Vinh","tag":"su-mon","quanHe":"Đệ tử đắc ý thứ năm"},{"ten":"Lý thị","tag":"the-thiep","quanHe":"Vợ"},{"ten":"Trương Tụ Nhi","tag":"ho-hang","quanHe":"Cháu ngoại"},{"ten":"Triệu trưởng lão","tag":"ban-be","quanHe":"Bạn chí giao"},{"ten":"Hàn Lập","tag":"an-nhan","quanHe":"Thầy thuốc được mời tới cứu chữa"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0068","c0069","c0070","c0071","c0072","c0073","c0080","c0086"]},{"id":"trieu-truong-lao","name":"Triệu trưởng lão","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ — luyện Hỗn viên thủ","trangThai":"song","blurb":"Trưởng lão Thất Huyền môn, bạn chí giao của Lý trưởng lão. Tính bộc trực, lỗ mãng, dễ bị khích nổi nóng. Luyện Hỗn viên thủ — khiến hai bàn tay to lớn, mười ngón căng phồng. Vừa từ Tụ Bảo đường trở về, không cùng hệ phái với Mã phó môn chủ; lạnh nhạt và hoài nghi y thuật Hàn Lập.","vaiTro":"Trưởng lão Thất Huyền môn","tinhCach":[{"text":"Bộc trực, lỗ mãng, dễ bị khích nổi nóng — buột miệng nói thẳng điều không nên nói khi bị Mã phó môn chủ dẫn dụ","chuong":70},{"text":"Hoài nghi y thuật của người trẻ — không tin 'tiểu oa đầu mười mấy tuổi' có thể trị được","chuong":70}],"tabs":{"diem":[{"text":"Bàn tay to lớn, mười ngón căng phồng — đặc trưng của Hỗn viên thủ","chuong":69},{"text":"Vừa từ Tụ Bảo đường trở về núi (hai ngày trước c69)","chuong":69}],"kinhLich":[{"chuong":69,"importance":"normal","tieuDe":"Lần đầu gặp Hàn Lập","text":"Được Mã Vinh giới thiệu với Hàn Lập. Thái độ không lạnh không nóng, trong mắt đầy hoài nghi về y thuật 'Hàn thần y' còn trẻ tuổi."},{"chuong":70,"importance":"normal","tieuDe":"Bị Mã phó môn chủ khích — mâu thuẫn hệ phái lộ rõ","text":"Bị Mã phó môn chủ dẫn dụ buột miệng nghi ngờ y thuật Hàn Lập ('Mới mười mấy tuổi tiểu oa đầu… ta không tin'). Lộ mâu thuẫn hệ phái: Triệu và Mã thuộc hai hệ phái đối địch trong Thất Huyền môn. Luyện Hỗn viên thủ được nhắc đến."},{"chuong":71,"importance":"normal","tieuDe":"Hỗ trợ chữa trị Lý trưởng lão","text":"Có mặt và hỗ trợ khi Hàn Lập tiến hành chữa trị Lý trưởng lão."},{"chuong":72,"importance":"normal","tieuDe":"Dùng nội lực bức độc","text":"Cùng Mã phó môn chủ và Tiễn trưởng lão dùng nội lực bức huyết độc qua huyệt đạo ra ngoài — nguyên khí hao tổn không ít."}],"tuViMoc":[],"nhanMach":[{"ten":"Lý trưởng lão","tag":"ban-be","quanHe":"Bạn chí giao"},{"ten":"Mã phó môn chủ","tag":"doi-dich","quanHe":"Đối thủ hệ phái nội môn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Hỗn viên thủ","loai":"thủ pháp","trangThai":"đang luyện","moTa":"Võ công đặc thù khiến hai bàn tay to lớn, mười ngón căng phồng. Mã phó môn chủ mỉa mai 'chắc đã luyện tới mức xuất thần nhập hóa'.","nguon":["c0070"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0069","c0070","c0071","c0072"]},{"id":"tien-truong-lao","name":"Tiễn trưởng lão","cn":null,"aliases":["Tiền trưởng lão"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ — luyện nội công tuyệt tình đoạn dục","trangThai":"song","blurb":"Trưởng lão Thất Huyền môn, mặt trắng bệch ('bạch diện'). Luyện một môn nội công đặc thù phải 'tuyệt tình đoạn dục', dẫn đến tính cách lãnh đạm với tất cả mọi người. Hàn Lập đã từng gặp qua trước c69.","vaiTro":"Trưởng lão Thất Huyền môn","tinhCach":[{"text":"Lãnh đạm với tất cả mọi người do yêu cầu của công pháp tu luyện — tuyệt tình đoạn dục","chuong":69}],"tabs":{"diem":[{"text":"Mặt trắng bệch ('bạch diện'), vẻ lạnh lùng nhất trong các trưởng lão","chuong":69}],"kinhLich":[{"chuong":69,"importance":"minor","tieuDe":"Xuất hiện tại nhà Lý trưởng lão","text":"Có mặt trong phòng khách nhà Lý trưởng lão. Chỉ lạnh lùng gật đầu khi Mã Vinh giới thiệu với Hàn Lập, thái độ lãnh đạm đúng theo tính cách."},{"chuong":71,"importance":"normal","tieuDe":"Hỗ trợ chữa trị Lý trưởng lão","text":"Có mặt và hỗ trợ khi Hàn Lập tiến hành chữa trị."},{"chuong":72,"importance":"normal","tieuDe":"Dùng nội lực bức độc — nguyên khí đại thương","text":"Cùng Mã phó môn chủ dùng nội lực bức huyết độc qua huyệt đạo ra ngoài; nguyên khí hao tổn không ít."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Nội công tuyệt tình đoạn dục (chưa rõ tên)","loai":"nội công đặc thù","trangThai":"đang luyện","moTa":"Môn nội công đòi hỏi người luyện phải đoạn tuyệt tình cảm và dục vọng; dẫn đến tính cách lãnh đạm với mọi người. Tên cụ thể chưa được tiết lộ.","nguon":["c0069"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0069","c0071","c0072"]},{"id":"truong-tu-nhi","name":"Trương Tụ Nhi","cn":null,"aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Thất Huyền môn","trangThai":"ho-hang"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Thiếu nữ khoảng 15-16 tuổi, ban đầu được giới thiệu là cháu ngoại (khác họ) của Lý trưởng lão và là đối tượng tình cảm của Lệ Phi Vũ. Xuất hiện lần đầu bên Lệ Phi Vũ trong lúc khóc vì lo cho ông ngoại, rồi theo Lý trưởng lão lên Lạc Nhật phong giữa lúc đại biến. Về sau lộ thân phận thực là hạch tâm đệ tử Thất tuyệt đường và bị điều vào huyết đấu cùng phía Thất Huyền môn.","vaiTro":"Cháu ngoại Lý trưởng lão, sau lộ là hạch tâm đệ tử Thất tuyệt đường","tinhCach":"Biểu lộ tình cảm chân thật, dễ khóc khi lo cho người thân; giấu kín thân phận thực; gương mặt tinh nghịch đáng yêu","tabs":{"diem":[{"text":"Cháu ngoại Lý trưởng lão, mang họ Trương (khác họ Lý)","chuong":70},{"text":"Khoảng 15-16 tuổi, trên đầu cài bích ngọc trâm, mặc y phục xanh biếc, tóc đen tuyền túm cao","chuong":69}],"kinhLich":[{"chuong":69,"importance":"normal","tieuDe":"Xuất hiện cạnh Lệ Phi Vũ","text":"Đang khóc (lo cho tình trạng ông ngoại), được Lệ Phi Vũ ở cạnh an ủi. Hàn Lập gặp lần đầu, đánh giá là 'tiểu mĩ nhân tiền thật giá thật'."},{"chuong":70,"importance":"minor","tieuDe":"Được giới thiệu là cháu ngoại Lý trưởng lão","text":"Mã Vinh giới thiệu là cháu ngoại (khác họ) của Lý trưởng lão — chi tiết làm Hàn Lập hơi ngạc nhiên."},{"chuong":77,"importance":"bridge","tieuDe":"Đã lên Lạc Nhật phong cùng ông ngoại","text":"Được nhắc tên khi Lệ Phi Vũ lo lắng cho an nguy; đã đi theo Lý trưởng lão lên Lạc Nhật phong trước khi đại biến xảy ra."},{"chuong":80,"importance":"bridge","tieuDe":"Đang ở Lạc Nhật phong trong đại biến","text":"Được tên mập nhắc tới; đang ở Lạc Nhật phong cùng ông ngoại Lý trưởng lão trong khi Thất Huyền môn bị liên quân tấn công."},{"chuong":86,"importance":"major","tieuDe":"Lộ thân phận hạch tâm đệ tử Thất tuyệt đường — ký tử khế","text":"Bị Vương môn chủ điều vào nhóm tử đấu — thân phận thực là hạch tâm đệ tử Thất tuyệt đường, không phải thiếu nữ nhu nhược như Hàn Lập tưởng. Đứng trong nhóm nữ cắn môi mặt tái nhợt, mặc quần áo trắng; sắp ký tử khế."},{"chuong":87,"importance":"normal","text":"Vừa mừng rỡ vừa sợ hãi khi thấy Lệ Phi Vũ đến; chính thức tham gia huyết đấu cùng phía Thất Huyền môn. Đang tâm sự thân mật với Lệ Phi Vũ ngay tại chiến trường."}],"tuViMoc":[],"nhanMach":[{"ten":"Lý trưởng lão","tag":"ho-hang","quanHe":"Ông ngoại"},{"ten":"Lệ Phi Vũ","tag":"tinh-cam","quanHe":"Người để ý, ký tử khế để ở bên nàng trong huyết đấu"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0069","c0070","c0077","c0080","c0086","c0087"]},{"id":"ly-thi","name":"Lý thị","cn":null,"aliases":["Sư nương"],"gioiTinh":"nu","theLuc":[{"ten":"Thất Huyền môn","trangThai":"ho-hang"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Thiếu phụ trung niên, vợ của Lý trưởng lão, được Mã Vinh gọi là 'sư nương'. Bà dẫn Hàn Lập vào phòng bệnh và tự tay bón thuốc cứu chữa cho chồng đến khi giải độc hoàn toàn. Về sau bà được nhắc là đã chết trong biến cố Mặc phủ bị phá hủy sau khi bị cao thủ Ngũ sắc môn tập kích.","vaiTro":"Vợ Lý trưởng lão — được môn hạ gọi là sư nương","tinhCach":"Tận tâm chăm sóc chồng bệnh; phối hợp làm theo hướng dẫn cứu chữa","tabs":{"diem":[{"text":"Được Mã Vinh giới thiệu và dẫn Hàn Lập tới sát giường bệnh của Lý trưởng lão","chuong":"@c0070"},{"text":"Tự tay bón Thanh Linh Tán hòa nước ấm cho Lý trưởng lão uống theo hướng dẫn của Hàn Lập","chuong":"@c0071"},{"text":"Có mặt chứng kiến Lý trưởng lão được bức độc và giải độc hoàn toàn","chuong":"@c072"},{"text":"Được Mặc Thải Hoàn nhắc là đã chết sau khi Mặc phủ bị phá hủy","chuong":"@c0250"},{"text":"Được Nghiêm thị kể là chết trong lúc Mặc phủ phá vòng vây sau khi bị cao thủ Ngũ sắc môn tập kích","chuong":"@c0251"}],"kinhLich":[{"chuong":70,"importance":"minor","tieuDe":"Được giới thiệu, dẫn Hàn Lập vào phòng bệnh","text":"Mã Vinh giới thiệu Lý thị (sư nương) cho Hàn Lập. Lý thị dẫn Hàn Lập đi sát tới giường bệnh của Lý trưởng lão."},{"chuong":71,"importance":"normal","tieuDe":"Bón thuốc cho Lý trưởng lão","text":"Tận tay bón Thanh Linh Tán đã hòa nước ấm cho Lý trưởng lão uống theo hướng dẫn của Hàn Lập."},{"chuong":72,"importance":"normal","tieuDe":"Chứng kiến giải độc hoàn toàn","text":"Có mặt khi Mã phó môn chủ và Tiễn trưởng lão bức độc và Hàn Lập dùng kim châm. Lý trưởng lão hoàn toàn giải độc."},{"importance":"normal","chuong":"@c0246","tieuDe":"Chứng kiến hiểu lầm về Đổng Huyên Nhi","text":"Lý thị chứng kiến Hồng Phất làm rõ chuyện thủ cung sa của Đổng Huyên Nhi vẫn còn, nên nhận ra trước đó mình đã hiểu lầm nàng. Sau khi nghe giải thích về Hóa xuân quyết và các lời đồn, bà mang vẻ xấu hổ rồi thuật lại sự việc cho Lý Hóa Nguyên.","anchor":"Vì vậy, thiếu phụ nghe hết thảy những cái này, mang theo thần sắc phi thường xấu hổ","mucCt":"vua","nguon":["bồi-cuối-quyển"]},{"importance":"normal","chuong":"@c0274","tieuDe":"An ủi Hàn Lập và giải thích việc chọn hắn","text":"Lý thị an ủi Hàn Lập khi hắn bị gọi vào hỏi chuyện, đồng thời tò mò về quan hệ giữa hắn và Nam Cung Uyển. Về sau nàng bổ sung rằng Tống Mông không được chọn vì từ nhỏ ở Lục Ba động, thiếu lịch lãm thế tục trong khi đối tượng cần bảo vệ là phàm nhân.","anchor":"Mặt khác Tống Mông từ nhỏ ở tại Lục Ba động, không có sự lịch lãm trong thế tục","mucCt":"vua","nguon":["bồi-cuối-quyển"]}],"tuViMoc":[],"nhanMach":[{"ten":"Lý trưởng lão","tag":"the-thiep","quanHe":"Chồng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0070","c0071","c0072"]},{"id":"ma-vinh","name":"Mã Vinh","cn":"马荣","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ — cao cấp đệ tử Thất Huyền môn","trangThai":"song","blurb":"Mã Vinh là đệ tử đắc ý thứ năm của Lý trưởng lão thuộc Thất Huyền môn, mặc cẩm y cao cấp đệ tử và từng theo sư phụ đến Thần thủ cốc ra mắt Hàn Lập nên quen biết trước. Khi Lý trưởng lão trúng kịch độc Dã Lang bang, chính hắn khẩn cầu và dẫn Hàn Lập tới cứu, đồng thời tổ chức bảo vệ thân nhân sư phụ giữa cuộc xung đột với Dã Lang bang.","vaiTro":"Đệ tử đắc ý thứ năm của Lý trưởng lão — cao cấp đệ tử Thất Huyền môn","tinhCach":"Trọng tình thầy trò, lo lắng đến sốt ruột khi sư phụ lâm nguy; hành động nhanh nhẹn, chủ động khi cần cứu người; biết lo xa, chú trọng bảo vệ gia quyến","tabs":{"diem":[{"text":"Mặc cẩm y đặc trưng cao cấp đệ tử Thất Huyền môn","chuong":68},{"text":"Đệ tử đắc ý thứ năm (năm trong số các đệ tử đắc ý) của Lý trưởng lão","chuong":68}],"kinhLich":[{"chuong":68,"importance":"major","tieuDe":"Cầu cứu Hàn Lập cứu sư phụ","text":"Tới Thần thủ cốc khẩn cầu Hàn Lập cứu Lý trưởng lão trúng kịch độc Dã Lang bang đang hôn mê; lo lắng tột độ, tức giận các đại phu khác bó tay."},{"chuong":69,"importance":"normal","tieuDe":"Dẫn Hàn Lập vào nhà Lý trưởng lão","text":"Đứng ngoài lo lắng (nắm chặt tay), sốt ruột kéo thẳng Hàn Lập vào phòng khách sau khi Hàn Lập chào hỏi xong. Giới thiệu lần lượt các nhân vật trong phòng cho Hàn Lập."},{"chuong":70,"importance":"minor","tieuDe":"Giới thiệu thân nhân Lý trưởng lão","text":"Giới thiệu Lý thị (sư nương) và Trương Tụ Nhi (cháu ngoại Lý trưởng lão) cho Hàn Lập. Xấu hổ giải thích khi Lệ Phi Vũ vờ lạnh lùng với Hàn Lập."},{"chuong":72,"importance":"normal","tieuDe":"Lấy nước chậu — hỗ trợ bức độc","text":"Được Hàn Lập chỉ thị, nhanh chóng đi lấy chậu nước sạch để đựng độc tố rút ra từ cơ thể Lý trưởng lão."},{"chuong":79,"importance":"normal","tieuDe":"Bị tên mập tước quyền chỉ huy — sốt ruột bất lực","text":"Muốn phái người ra dò xét tình hình địch nhưng bị trung niên mập (thân tín Vương môn chủ) dùng kim sắc lệnh bài ép phải phục tùng; biến thành lá chắn sống của tên mập, 'sốt ruột như kiến bò trên chảo lửa'."},{"chuong":80,"importance":"normal","tieuDe":"Tổ chức bảo vệ gia quyến tại khu nhà đang xây","text":"Thỉnh Lệ Phi Vũ để lại hơn hai mươi thủ hạ; gom đám gia quyến không biết võ công vào khu nhà đang xây trong núi để bảo vệ tập trung khi tao loạn."},{"chuong":84,"importance":"normal","tieuDe":"Kể cho Hàn Lập nghe tình hình Lạc Nhật Phong","text":"Xuất hiện ngắn tại Lạc Nhật Phong; kể cho Hàn Lập nghe về tình hình tử khế đấu giữa Thất Huyền môn và Dã Lang bang, giúp Hàn Lập hiểu thể lệ huyết chiến."}],"tuViMoc":[],"nhanMach":[{"ten":"Lý trưởng lão","tag":"su-mon","quanHe":"Sư phụ"},{"ten":"Hàn Lập","tag":"an-nhan","quanHe":"Thầy thuốc được cầu cứu cứu sư phụ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0068","c0069","c0070","c0072","c0079","c0080","c0084"]},{"id":"ngo-pho-mon-chu","name":"Ngô phó môn chủ","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"tu-vong"}],"canhGioiCaoNhat":"Không rõ — phó môn chủ Thất Huyền môn (đệ nhị cao thủ toàn môn)","trangThai":"tu-vong","blurb":"Phó môn chủ Thất Huyền môn, cao thủ đứng thứ hai toàn môn. Dẫn đầu đoàn đàm phán tới Lạc Sa pha gặp Dã Lang bang, song đây thực chất là một bẫy phục kích. Bị nỏ liên châu quân dụng cùng đông đảo cao thủ địch vây công, chiến tử tại Lạc Sa pha.","vaiTro":"Phó môn chủ Thất Huyền môn — cao thủ thứ hai toàn môn","tinhCach":[],"tabs":{"diem":[{"text":"Giữ vị trí cao thủ thứ hai toàn Thất Huyền môn, chỉ dưới môn chủ","chuong":"@c0076"},{"text":"Dẫn đầu đoàn đàm phán Thất Huyền môn tới Lạc Sa pha gặp Dã Lang bang","chuong":"@c0076"},{"text":"Trúng bẫy phục kích, bị nỏ liên châu quân dụng và cao thủ địch vây công, tử trận tại Lạc Sa pha","chuong":"@c0076"},{"text":"Cái chết được Lệ Phi Vũ xác nhận với Hàn Lập cùng mấy trưởng lão cũng chiến tử","chuong":"@c0077"}],"kinhLich":[{"chuong":76,"importance":"major","tieuDe":"Tử trận tại Lạc Sa pha","text":"Dẫn đầu đoàn đàm phán Thất Huyền môn tới Lạc Sa pha. Dã Lang bang dùng lượng lớn nỏ liên châu quân dụng từ dưới đất phục kích, bắn loạn tiễn tề xạ. Ngô phó môn chủ bị quá nhiều cao thủ Dã Lang bang vây công, chiến tử."},{"chuong":77,"importance":"normal","tieuDe":"Xác nhận tử vong qua lời kể Lệ Phi Vũ","text":"Lệ Phi Vũ xác nhận với Hàn Lập: Ngô phó môn chủ và mấy trưởng lão đều đã chiến tử trong trận phục kích."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương môn chủ","tag":"su-mon","quanHe":"Môn chủ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0076","c0077"]},{"id":"ton-chap-phap","name":"Tôn chấp pháp","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Dã Lang bang","trangThai":"tu-vong"}],"canhGioiCaoNhat":"Không rõ — chấp pháp Dã Lang bang","trangThai":"tu-vong","blurb":"Chấp pháp của Dã Lang bang, giọng bén nhọn như gà trống gáy. Dẫn hơn mười mấy người vào Thần Thủ Cốc theo tử lệnh của phó lệnh chủ để bắt sống thần y. Bị Khúc Hồn giết chết.","vaiTro":"Chấp pháp Dã Lang bang (đã chết)","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":78,"importance":"normal","tieuDe":"Dẫn nhóm vào Thần Thủ Cốc bắt thần y — bị Khúc Hồn giết","text":"Dẫn hơn mười mấy bang chúng vào Thần Thủ Cốc theo tử lệnh phó lệnh chủ: bắt sống thần y, không được làm hại. Hàn Lập ra lệnh Khúc Hồn giết sạch trừ tên Lam y; Tôn chấp pháp cùng toàn bộ nhóm bị Khúc Hồn tiêu diệt."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0078"]},{"id":"lam-y-chap-phap","name":"Lam y chấp pháp","cn":null,"aliases":["gia hoả tham sinh uý tử"],"gioiTinh":"nam","theLuc":[{"ten":"Dã Lang bang","trangThai":"tu-vong"}],"canhGioiCaoNhat":"Không rõ — chấp pháp Dã Lang bang","trangThai":"tu-vong","blurb":"Chấp pháp mặc lam y của Dã Lang bang. Bị Khúc Hồn bắt sống theo lệnh Hàn Lập. Tham sống sợ chết, khai hết toàn bộ tin tức không cần tra khảo. Bị Lệ Phi Vũ diệt khẩu sau khi cung cấp đủ thông tin.","vaiTro":"Chấp pháp Dã Lang bang (đã chết)","tinhCach":[{"text":"Tham sống uý tử — khai hết không cần tra khảo khi bị bắt","chuong":79}],"tabs":{"diem":[],"kinhLich":[{"chuong":78,"importance":"normal","tieuDe":"Bị Khúc Hồn bắt sống","text":"Là người duy nhất trong nhóm Tôn chấp pháp mà Hàn Lập ra lệnh giữ mạng để tra khảo. Khúc Hồn bắt sống theo lệnh."},{"chuong":79,"importance":"normal","tieuDe":"Khai toàn bộ — bị diệt khẩu","text":"Tham sống sợ chết, khai hết toàn bộ tin tức về kế hoạch của Dã Lang bang và liên minh (Thiết thương hội, Đoạn thủy môn) mà không cần tra khảo. Lệ Phi Vũ lấy đủ thông tin rồi diệt khẩu."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0078","c0079"]},{"id":"dau-muc-mat-seo","name":"Đầu mục mặt sẹo (Đoạn Thủy môn)","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đoạn Thủy môn","trangThai":"khong-ro"}],"canhGioiCaoNhat":"Không rõ — đầu mục Đoạn Thủy môn (cấp ba đạo bạch tuyến)","trangThai":"khong-ro","blurb":"Đầu mục Đoạn Thủy môn có vết sẹo trên mặt, cấp cao nhất trong nhóm mười tên áo xanh chặn vây Hàn Lập và Lệ Phi Vũ. Tự nhận 'giang hồ lão luyện', quyết đoán rút lui khi nhận ra thực lực địch vượt trội.","vaiTro":"Đầu mục Đoạn Thủy môn","tinhCach":[{"text":"Lọc lõi, biết lượng sức — ngay khi thấy Lệ Phi Vũ ra tay liền ra lệnh toàn bộ rút lui tứ tán, phát tín hiệu gọi viện binh","chuong":80}],"tabs":{"diem":[{"text":"Ba đạo bạch tuyến trên ống tay áo — cấp đầu mục, cao nhất trong nhóm mười người","chuong":80},{"text":"Trên mặt có vết sẹo","chuong":80}],"kinhLich":[{"chuong":80,"importance":"normal","tieuDe":"Chặn vây nhóm Hàn Lập — bị Lệ Phi Vũ và Khúc Hồn đánh tan","text":"Chỉ huy mười tên áo xanh Đoạn Thủy môn vây nhóm Hàn Lập cách Lý trạch hơn một dặm, tuyên bố 'Thất Huyền môn đã hết rồi'. Khi Lệ Phi Vũ ra tay, lập tức nhận ra thực lực vượt trội của địch, ra lệnh toàn bộ rút chạy và phát tín hiệu gọi cao thủ tăng viện."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0080"]},{"id":"chu-nho","name":"Chu Nho","cn":null,"aliases":["Kim Quang thượng nhân","Tần Diệp Lĩnh"],"gioiTinh":"nam","theLuc":[{"ten":"Dã Lang bang","trangThai":"lam-thue"},{"ten":"Diệp gia","trangThai":"de-tu"}],"canhGioiCaoNhat":"Tu tiên sơ cấp — pháp lực thấp hơn Hàn Lập (Trường Xuân công tầng 8)","trangThai":"tu-vong","blurb":"Chu Nho là tu sĩ tu tiên sơ cấp có pháp lực thấp hơn Hàn Lập, mang biệt hiệu 'Kim Quang thượng nhân' và sở hữu bộ Kim Quang Tráo phòng ngự cùng một hộp đen điều khiển kiếm phù bằng khẩu quyết. Được Dã Lang bang thuê để tiêu diệt ba sư thúc Thất Huyền môn, hắn giết được một hán tử nhưng bị Hàn Lập dùng Khu vật thuật đoạt kiếm phù. Sau khi khai tên thật Tần Diệp Lĩnh và cầu xin tha, hắn bị Hàn Lập giết bằng Hỏa Đạn Thuật, kết thúc trong trạng thái tu-vong.","vaiTro":"Cao thủ tu tiên thuê cho Dã Lang bang — nhân vật phản diện thứ yếu","tinhCach":"Tham vàng, mang biệt hiệu vì mê vàng và sở hữu Kim Quang Tráo; ngạo nghễ khi ra trận nhưng nhanh chóng hoảng loạn khi bị áp chế; hèn nhát cầu xin tha mạng khi lâm nguy","tabs":{"diem":[{"text":"Tầm vóc nhỏ bé, vẻ ngoài ăn mặc thô tục; cười tiếng chói tai 'hắc hắc'","chuong":88},{"text":"Pháp lực thấp hơn Hàn Lập theo quan sát Thiên Nhãn Thuật — bạch quang mờ nhạt như có như không","chuong":88}],"kinhLich":[{"chuong":82,"importance":"major","tieuDe":"Được Dã Lang bang thuê","text":"Ký hợp đồng với Cổ Thiên Long: nhận 3000 lượng vàng trả trước, 2000 lượng sau khi giết ba sư thúc Thất Huyền môn."},{"chuong":88,"importance":"major","tieuDe":"Ra trận — kích hoạt Kim Quang Tráo","text":"Ngạo nghễ ra mặt đầu tiên trong trận huyết đấu. Dùng lá bùa kim quang phát ra Kim Quang Tráo bọc thân như khôi giáp, vô hiệu hóa đao của hộ pháp Thất Huyền môn; làm chấn động toàn trường. Nhận thêm thù lao 3000 lượng (tổng 8000 lượng vàng)."},{"chuong":89,"importance":"normal","tieuDe":"Bị hán tử râu ria áp chế","text":"Thách Thất Huyền môn tùy ý công kích; bị hán tử râu ria — sư thúc cao thủ từng là mãnh tướng — áp chế hoàn toàn. Kim tráo bị đấm méo liên tục, ngã xuống đất, niệm pháp quyết hoảng loạn sai. Cố lấy hộp đen ra nhưng không kịp kích hoạt."},{"chuong":90,"importance":"major","tieuDe":"Kích hoạt hộp đen — giết hán tử","text":"Ngồi xuống, đặt hộp đen lên đùi, niệm chú bắt quyết hô 'Khởi'; luồng sáng mờ bay ra, chém cụt tay phải rồi đâm xuyên ngực hán tử. Thị uy bằng cách điều luồng sáng vẽ hình mãng xà xám trên không; áp đảo tinh thần phe Thất Huyền môn. Hàn Lập nhận ra khẩu quyết giống hệt Khu vật thuật."},{"chuong":91,"importance":"normal","text":"Bị Hàn Lập dùng Khu vật thuật đoạt mất kiếm phù (luồng sáng từ hộp đen). Kinh hoàng khi một đệ tử trông bình thường của Thất Huyền môn lại có thể thu hồi vật của mình; co tay rút chân, giận mà không dám tấn công."},{"chuong":92,"importance":"normal","text":"Hiểu lầm Hàn Lập là người của gia tộc tu tiên. Sợ hãi cầu xin tha, khai tên thật: Tần Diệp Lĩnh, đệ tử Diệp gia, tới đây vì quen bang chủ Dã Lang bang chứ không có mưu đồ khai thác khoáng sản hay linh dược. Đang nhờ Hàn Lập tha mạng."},{"chuong":93,"importance":"major","tieuDe":"Bị Hàn Lập dùng Hỏa Đạn Thuật giết chết","text":"Khi Hàn Lập giả vờ trả lại kiếm phù, hắn bỏ Kim Quang Tráo để đón — đúng lúc đó Hàn Lập phóng Hỏa Đạn Thuật kết liễu. Tử trận; để lại ba vật trong tro tàn: phù lục kim quang, lệnh bài tam giác, Tần thị tộc phổ."}],"tuViMoc":[{"chuong":88,"canhGioi":"Tu tiên sơ cấp (nửa vời) — pháp lực dưới Hàn Lập tầng 8","text":"Hàn Lập dùng Thiên Nhãn Thuật quan sát thấy bạch quang mờ nhạt như có như không — xếp vào loại 'nửa vời', pháp lực thấp hơn mình."}],"nhanMach":[{"ten":"Cổ Thiên Long","tag":"dong-minh","quanHe":"Chủ thuê — được trả 8000 lượng vàng"},{"ten":"Thất Huyền môn","tag":"doi-dich","quanHe":"Đối thủ trong huyết đấu"},{"ten":"Diệp gia","tag":"su-mon","quanHe":"Gia tộc tu tiên Chu Nho tự nhận là đệ tử"}],"tuiDo":{"phapBao":[{"ten":"Lá bùa kim quang (Kim Quang Tráo)","loai":"phù chú phòng ngự","trangThai":"đang dùng","moTa":"Lá bùa màu vàng kim quang lấp lánh; đập vào thân phát ra Kim Quang Tráo — quầng sáng vàng bọc thân cứng như sắt thép. Thuộc cấp bậc cao hơn Định Thần Phù.","nguon":["c0088"]},{"ten":"Hộp gỗ đen dán bùa phong ấn","loai":"pháp khí bí ẩn","trangThai":"đang giữ","moTa":"Hộp gỗ dài màu đen, dán bùa phong ấn; chứa luồng sáng mờ điều khiển bằng khẩu quyết giống Khu vật thuật. Người ngoài gọi vật bay ra là phi kiếm nhưng nguyên tác không xác nhận thân phận thật của nó.","nguon":["c0089","c0090"]}],"danDuoc":[],"congPhap":[{"ten":"Kim cương bất hoại công","loai":"công pháp phòng ngự","trangThai":"đang luyện","moTa":"Công pháp phòng ngự tạo màn hào quang vàng bao thân. Điểm yếu: lực vật lý cực mạnh liên tục có thể làm biến hình màn hào quang.","nguon":["c0088","c0089","c0090"]}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":3,"nguon":["c0082","c0088","c0089","c0090","c0091","c0092","c0093"]},{"id":"ba-su-thuc-that-huyen-mon","name":"Ba vị sư thúc Thất Huyền môn","cn":null,"aliases":["hán tử râu ria","thư sinh","áo xám trường kiếm"],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (võ học cực cao) — hóa cảnh cao thủ","trangThai":"song","blurb":"Ba vị trưởng bối sư thúc của Vương Tuyệt Sở, gồm một thư sinh, một hán tử râu ria ngoài sáu mươi từng là mãnh tướng, và một người áo xám mang trường kiếm, đóng vai chỗ chống lưng để Thất Huyền môn dám nhận tử khế đấu. Hán tử râu ria được cử ra phá Kim Quang Tráo của Chu Nho, đơn thân áp chế đối thủ bằng thân pháp mờ ảo và tiếng gầm long ngâm hổ gầm. Khi nhận ra không thể phá vỡ kim quang, y bỏ chạy nhưng bị luồng sáng từ hộp đen Chu Nho chém cụt tay phải rồi giết chết.","vaiTro":"Trưởng bối sư thúc Thất Huyền môn, chỗ chống lưng chiến lược","tinhCach":"Kiêng kỵ trước cường địch; dũng mãnh áp chế đối thủ bằng thân thủ; biết lượng sức rút lui khi không phá được phòng ngự","tabs":{"diem":[{"text":"Ba người khác biệt rõ: thư sinh thanh mảnh; hán tử râu ria thô lỗ ngoài sáu mươi, từng là mãnh tướng; áo xám mang trường kiếm","chuong":86},{"text":"Mi tâm có thần sắc tang thương — dù là cao thủ vẫn lo lắng trước Kim Quang Tráo của Chu Nho trước khi tìm được đối sách","chuong":89}],"kinhLich":[{"chuong":87,"importance":"normal","text":"Cùng Vương Tuyệt Sở chứng kiến Hàn Lập phô thân pháp kinh người; thần sắc biến, kinh ngạc và kiêng kỵ."},{"chuong":89,"importance":"major","tieuDe":"Hán tử râu ria đối chiến Chu Nho","text":"Được Vương Tuyệt Sở cử ra phá Kim Quang Tráo của Chu Nho. Đi vòng quanh ngày càng nhanh tới mờ ảo thân ảnh, gầm vang chấn động Lạc Nhật Phong khiến Chu Nho tay chân vô lực; thân hình phình to như thiết tháp, dùng quyền cước đấm đá dồn dập làm kim tráo liên tục biến hình, đẩy Chu Nho ngã xuống đất."},{"chuong":90,"importance":"major","tieuDe":"Hán tử bị luồng sáng giết","text":"Nhận ra không thể phá vỡ kim quang, xoay người bỏ chạy. Bị luồng sáng từ hộp đen Chu Nho phóng theo: chém cụt cánh tay phải rồi đâm xuyên ngực, tử trận. Cái chết của hán tử khiến phe Thất Huyền môn rơi vào tuyệt vọng câm lặng."}],"tuViMoc":[{"chuong":89,"canhGioi":"Phàm nhân võ học — hóa cảnh cao thủ","text":"Thân pháp nhanh tới mờ ảo; tiếng gầm làm đối thủ tay chân vô lực; thuật phình to thân thể cơ bắp cuồn cuộn đủ sức đập biến hình Kim Quang Tráo — cảnh giới võ học phàm nhân đỉnh cao, không phải tu tiên."}],"nhanMach":[{"ten":"Vương Tuyệt Sở","tag":"su-mon","quanHe":"Cháu của ba sư thúc (gọi là 'sư thúc')"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":4,"nguon":["c0082","c0086","c0087","c0089","c0090"]},{"id":"ly-mon-chu-de-that","name":"Lý Môn chủ đệ thất đại","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thất Huyền môn","trangThai":"da-roi"}],"canhGioiCaoNhat":"Không rõ — Môn chủ Thất Huyền môn thế hệ thứ bảy","trangThai":"tu-vong","blurb":"Môn chủ đời thứ bảy của Thất Huyền môn, đã qua đời từ lâu. Người thiết kế toàn bộ hệ thống cơ quan bẫy Đại Hãm Tịnh bên trong Lạc Nhật Phong — công trình được lưu truyền bảo vệ tổng đàn suốt hơn hai trăm năm. Đây là nhân vật KHÁC với Lý trưởng lão đang còn sống hiện tại.","vaiTro":"Môn chủ đời thứ bảy Thất Huyền môn, người thiết kế Đại Hãm Tịnh","tinhCach":[],"tabs":{"diem":[{"text":"Người thiết kế hệ thống cơ quan bẫy Đại Hãm Tịnh trong Lạc Nhật Phong — công trình dựa trên động thạch nhũ tự nhiên chiếm hai phần ba lòng núi","chuong":83}],"kinhLich":[{"chuong":83,"importance":"normal","tieuDe":"Được nhắc tới qua công trình Đại Hãm Tịnh","text":"Tên và công trình được đề cập khi nhắc tới lịch sử tổng đàn Lạc Nhật Phong: lão thiết kế Đại Hãm Tịnh tận dụng cấu trúc động thạch nhũ tự nhiên; cơ quan bẫy truyền thừa qua nhiều thế hệ tới hiện tại."}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Huyền môn","tag":"su-mon","quanHe":"Môn phái của lão"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":5,"nguon":["c0083"]},{"id":"truong-tien-su","name":"Trương tiên sư","cn":null,"aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Dã Lang bang","trangThai":"hau-thuan"}],"canhGioiCaoNhat":"Không rõ — tu tiên giả (lai lịch chưa rõ)","trangThai":"song","blurb":"Nhân vật bí ẩn đứng sau kế hoạch tấn công Thất Huyền môn của Dã Lang bang, chỉ xuất hiện qua giọng nói và không lộ diện. Cổ Thiên Long tuyệt đối phục tùng chỉ đạo của người này. Lai lịch, mục đích thực sự và thân phận thật đều chưa được tiết lộ trong hồ sơ.","vaiTro":"Người chỉ đạo bí ẩn sau lưng Dã Lang bang","tinhCach":[],"tabs":{"diem":[{"text":"Chỉ xuất hiện qua giọng nói; Cổ Thiên Long cư xử phục tùng, không tự đưa ra quyết định lớn nào khi chưa có chỉ đạo","chuong":82}],"kinhLich":[{"chuong":82,"importance":"major","tieuDe":"Xuất hiện lần đầu qua giọng nói","text":"Giọng nói vang lên, chỉ đạo kế hoạch tấn công Thất Huyền môn; Cổ Thiên Long nghe theo tuyệt đối. Lai lịch và hình dáng thật không được lộ."}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Thiên Long","tag":"dong-minh","quanHe":"Người chịu sự chỉ đạo"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":4,"nguon":["c0082"]}]};
